INSERT INTO mstr.advisor_memo_report VALUES (84, 26943, 295, '1668826', '2025-02-17 06:29:38', 'O,Komal', 'K, Rajiv', 'test', 'done', '8214862', '2025-02-17 06:37:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3104, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (142, 20536, 326, '1551380', '2023-09-20 01:07:06', NULL, 'Jen, Yvonne ', 'Client is in the Group''s Network Infrastructure segment. We should be quoting evidence relating to Network Infrastructure segment or the client as much as possible. Similarly, in the outcome tab where you provide analysis, please quote plans relevant to entity. I would rather you quote from page 4 or other relevant pages like page 28.Page 4"In Network Infrastructure, we have now reached 150 customers for our Quillion-based chipset for fixed broadband which uses about half the power of previous generations. We have more than 100 customers for PSE-V, our advanced coherent optical solution, which uses up to 50% less power. Our latest FP5-based routing silicon, which reduces power consumption by up to 75% per bit, is now being used by more than 30 customers. And our sixth-generation Photonic Service Engine (PSE-6s) for optical networking offers customers more capacity while reducing power consumption by up to 60%."', 'Updated the evidence accordingly.', '1600990', '2023-09-20 13:56:02', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2009, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (143, 20536, 327, '1551380', '2023-09-20 01:29:09', NULL, 'Jen, Yvonne ', 'Client is in the Group''s Network Infrastructure segment. We should be quoting evidence relating to Network Infrastructure segment or the client as much as possible. Page 30"Nokia also has a marine fleet related to our subsea cables business, Alcatel Submarine Networks (ASN). ASN contributes to Nokia’s main target to reduce GHG emissions by 50% by 2030. The ASN fleet represents around 62% of our Scope 1 emissions. In 2022, the GHG emissions for our marine fleet decreased by 5% compared to 2021. ASN has a green charter in place and continued to look at five important strategic areas: the rejuvenation of its marine fleet, the use of shore power when at port, the optimization of transit routes using Artificial Intelligence (AI), the mobilization of regional based chartered vessels to reduce transits, and next-gen cable ships with the latest technology in terms of propulsion and power generation. In 2022, the main ASN Marine Fleet Manager co', 'Updated evidence accordingly.', '1600990', '2023-09-20 13:56:33', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2002, 'TRM', 'esg_navigiator', '01');
