INSERT INTO mstr.advisor_memo_report VALUES (403, 21121, 690, '1599218', '2023-12-04 18:18:47', 'Ptasinska, Dorota', 'Delaney, Peter Jared', 'Other Minor Issues - I know this is the rating currently in the policy tracker but can you amend to policies in the next 2-5y? I have separately asked to change in the tracker as well. There is quite a bit of policy expectation around the sector in HK and want to highlight the policy signal as such. Thank you', 'Okay but are there expected additional policy measures after the 2023 update? I want to flag my answer includes additional analysis/content for 2023 updates to MEES - as per: "2023 update; The minimum energy efficiency standards (MEES) regulations have changed with effect from 1 April 2023, such that the current prohibition on new lettings of sub-standard, non-domestic properties now extends to the continuation of any existing lease of a sub-standard, non-domestic property." - No additional policies was selected based on there are no further reported updates or more stringent regulations reported beyond 2023 ', '1665885', '2023-12-06 12:03:25', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (492, 21182, 805, '1551380', '2023-12-28 14:28:27', NULL, 'Harsh, Shubham', 'Accuracy of CRQ - 2022 CSR report in Chinese available for download on S&P. Even in the annual report, there is a small section on ESG issues which include information on carbon emission. ', 'The case was not in the sample, but it was sent to 2nd line since the BRAG was "Red" for the case, Now the BRAG has changed to "AMBER" after the reassessment due to new reports and information is available. Hence the case is being directly sent to RM.  ', '2008896', '2023-12-29 12:46:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
