INSERT INTO mstr.advisor_memo_report VALUES (570, 21488, 919, '1575987', '2024-01-28 15:52:15', 'Mutepfa, Tashinga', NULL, 'Please get confirmation from CA in this regard. As per Central bank regulation in India , Only funding of land is not allowed . What is the source of repayment of loan ?ADDITIONAL COMMENT: Accuracy of CRQ - please change the NZ to Operations. the LEID has been established to develop the Marigold project (currently on phase 1). Please remove the reference the LEID is only for the land as this is misleading.', 'The CA has confirmed the client''s operating status is aligned with the evidence captured in the comment box. ', '1666829', '2024-01-29 11:16:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
