INSERT INTO mstr.advisor_memo_report VALUES (634, 21454, 986, '1599218', '2024-02-09 18:14:21', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Accuracy of CRQ - please use the breakdown of revenues as highlighted in the annual report FY22-23 https://www.tatasteeleurope.com/sites/default/files/Tata%20Steel%20Europe%20Annual%20Report%202022-23.pdf (PAGE 54)', 'Actioned: updated details based on client''s annul report.', '1540001', '2024-02-14 15:43:25', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (647, 21454, 985, '1599218', '2024-02-09 16:25:19', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Accuracy of CRQ - last year this question was rated in the worst category because of carbon pricing. Please, consider the carbon pricing implications (ie, both EU and UK ETS) and add reference of them. New answer option will need to be E - policies in place and expected to remain.  USE THE ANNUAL REPORT (https://www.tatasteeleurope.com/sites/default/files/Tata%20Steel%20Europe%20Annual%20Report%202022-23.pdf) LOOK AT PAGE 15 AND 16', 'Maker comment: Actioned. Details updated from annual report', '1540001', '2024-02-19 09:55:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
