INSERT INTO mstr.advisor_memo_report VALUES (653, 21454, 990, '1599218', '2024-02-09 18:19:14', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical aspects - these measures are good, but not easy to understand. Please summarise in a simple and concise way ALSO LOOK INTO THE ANNUAL REPORT. You can mention they are working towards the improvement of the efficiency levels at their Dutch sub and looking into replacing the blast furnaces in the UK with electric ones', 'Maker comment: Same as 5.1. Section 5 completed using annual report', '1540001', '2024-02-19 10:52:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (654, 21716, 1054, '1489063', '2024-02-19 13:44:58', 'Komjati, Dalma Beatrix ', NULL, 'Can you double check this? I haven''t seen many entities where the HH PD is 100% and the transition scenarios are not - especially for a company where there are not many physical assets.Might be worth adding a comment that this is an unusual outcome', 'ok', '2006082', '2024-02-19 16:54:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3217, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (655, 21902, 1014, '1599218', '2024-02-13 10:56:33', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Analytical aspects: I do not understand why you selected "Yes - Planned change in products mix to offer lower carbon alternatives.(e.g. Portfolio rebalance or Product change / divestment)". Do they not aim to change their products (ie, they will still be producing cement). All comments in the box are no understandable at all.Please summarise in your words what the transition looks like: (i) clinker substitution, (ii) thermal energy substitution with alternative sources from fossil fuels, (iii) CCUS - easy I do not need to know more', 'Following chat on this - comments are accurate and understandable; transition towards LC3 is a change in product offering, CCUS is not included because there is no dialogue on planned investments in this area +  balance sheet accomodations don''t seem likely - commentary synthesis is updated', '1665883', '2024-02-19 18:33:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (656, 21902, 1015, '1599218', '2024-02-13 11:01:37', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'NOT A COMMENT - but this is great, clear and easy to understand. This is how I would like to see all comments in the CRQ else I (and others I guess) do not understand anything if you take simple snapshots of reports', 'Thanks!', '1665883', '2024-02-19 18:36:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (657, 21854, 1058, '1489063', '2024-02-19 17:01:34', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'I am unsure how the comments provided associate to the options selected. In my eyes none of these have been undertaken - maybe some improved operations and technology, however thereis no evidence or a greener energy mix, change in products or use of CCUS. Please adjust to remove the options not evidenced.', 'As its a roadmap question and they plan a roadmap for CCUS I have retained it, For greener energy mix I have now included targets + change in renewable energy from 2022 - 2023 CDP report as they note solar PV is part of roadmap - evidence for lower carbon products also included in Q5.6.2. I have removed the product mix comment as its a new product line (answering Q5.6.1 memo)', '1665885', '2024-02-19 23:34:56', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (660, 21853, 1060, '1493184', '2024-02-19 20:23:16', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'Analytical issues:  What is the investment into less carobn intensive actions here -- purchasing electricity is just part of the normal business. Is it reduced electricity ? or changing the consumption of fossil fuel based electricity ?', 'Aligned with other CRQ comments under same group', '1665885', '2024-02-20 17:34:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
