INSERT INTO mstr.advisor_memo_report VALUES (724, 21990, 1149, '1599218', '2024-02-28 09:47:51', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Accuracy of CRQ - why have you completed only the EV data and not the other? You have this information. I agree EV is 6% (EV+PHEV).Please also add HEV 156,397 (total sales of 4.231mn = 4.5%). The rest is ICE (=100%-6%-4.5%= 89.5%)', 'updated', '2007983', '2024-02-29 07:53:35', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3416, 'GTR3', 'esg_navigiator', '01');
