INSERT INTO mstr.advisor_memo_report VALUES (726, 21990, 1153, '1599218', '2024-02-28 10:48:46', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Accuracy of CRQ - target #3 is on intensity basis, hence you should track this on an intensity basis not absolute. Please ref to page 39 of TCFD report "The fleet average on-road well-to-wheels gCO2e/km intensity decreased from 330 to 303 between 2019 and 2021,an 8% decrease, due to fleet efficiency improvements and vehicle mix changes. "Hence: Baseline 330, Target 165, current level 303', 'Target values have been updated. Thanks for the comments. We will pay more attention to highlighted points in the future. ', '2007983', '2024-02-29 08:23:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
