INSERT INTO mstr.advisor_memo_report VALUES (767, 22343, 1212, '1599218', '2024-03-14 11:31:14', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Accuracy of CRQ - this is not a project financing. We finance Vietnam Electricity who use the funds to finance the plants, but we are not financing the plants directly - hence this is not a Project Finance transaction. Please change any reference to the transactions in the CRA Analysis as well ', 'Agreed - Changed response to "No".', '1600990', '2024-03-15 15:30:59', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (768, 22343, 1211, '1599218', '2024-03-14 11:17:30', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Accuracy of CRQ - for Capacity, please use data from page 5 (Power Sources). For Generation use data from page 9 (Power Generation Output)', 'Updated as per the Annual Report.Earlier since the client was worked as project entity we have used the project detials for the table.', '1600990', '2024-03-15 16:17:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
