INSERT INTO mstr.advisor_memo_report VALUES (780, 23084, 1216, '1493184', '2024-03-15 16:19:31', 'Leva, Aljaz', 'Tarakji, Ranim', 'Analytical issue:  PLease confirm with the RM/GCM team if the asset has insurance -- projects are likely to have insurance.', 'As per CA''s response "For this project, POSCO E&C(7th largest construction company in Korea based on construction capacity) will provide completion guarantee and historically never failed to complete any construction workplace. So construction insurance for top tier construction company in Korea is not market practice and insurance risk can be mitigated by completion guarantee of POSCO E&C." ', '2003718', '2024-03-19 07:23:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (781, 22174, 1226, '1551380', '2024-03-18 03:55:46', NULL, 'Banerjee, Monalisa', 'Accuracy of CRQ - do not agree with answer selectin. Please refer to BCA part 2 where CA has provided additional information and incorporate them.From BCA Part 2: For Gross Physical Risk, we communicated with client for below aspects. Client has acknowledgement of physical risk hazards on their business operations. Eternal Asia has six logistics bases located in Shanghai, Dalian, Changsha, Shenzhen (two), Yangshan. All of them are located in well-developed area, such as economic development zones, Logistics park or bonded port area, with minimal physical risk hazards (such as floods, storms, wildfires, heat stress, sea level rise, etc.) and good climate. There is no material impact from changing climate on business operation. All warehouses are located in areas with convenient transportation and geographic environment so that Eternal Asia can rapidly respond to customers to meet their orders. Client also has management and adaptation me', 'Changed to operations.', '1563645', '2024-03-19 07:35:40', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
