INSERT INTO mstr.advisor_memo_report VALUES (799, 22839, 1274, '1599218', '2024-03-21 19:10:12', 'Masarin, Lisa', 'Baran, Ewa', 'Accuracy of CRQ - page 30 of env report says total generation is 3113 GWh - can you please add?', 'Updated to reflect - thank you! ', '1663704', '2024-03-22 08:35:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (800, 22839, 1279, '1599218', '2024-03-21 19:30:41', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical - can you please change to 2-5y? The reason for it is that the plant is still on OCGT and they say they will design the conversion to CCGT. The issue with the policy question is that Nigeria has plans to transition their OCGTs to CCGTs by 2030, hence there is quite big policy pressure on this plant, which I think we should highlight changing this question', 'Sure, updated as suggested. ', '1663704', '2024-03-22 08:40:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (801, 22702, 1262, '2009422', '2024-03-21 09:59:44', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: please add the link of the remuneration report where pdf report could be generated, not the website. Couldn''t find it.', 'Due to the word limit, the direct link to the document could not be added. Please see below: https://www.volvogroup.com/content/dam/volvo-group/markets/master/news/2024/mar/ab-volvos-report-on-evaluation-of-renumeration-to-senior-executives.pdf', '1618369', '2024-03-22 09:53:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (802, 22702, 1243, '2009422', '2024-03-20 15:47:05', 'Masarin, Lisa', NULL, 'Accuracy of CRA: the answer is not consistent with answer to question 3.1. Nevertheless, in your commentary there is no evidence that the client assesses physical risk through supply/value chain. Please amend the answer or provide evidence.', 'The report states that climate risks have been analyzed for each of the Group''s significant locations according to climate scenarios: RCP 2.5, RCP 4.5, RCP 8.5. This, in my opinion, confirms that the Company assess the level of "physical risk" impact on its underlying assets. The answer, however, should be narrowed to "direct business operations". ', '1618369', '2024-03-22 10:04:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (803, 22702, 1244, '2009422', '2024-03-20 16:15:13', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: is the temperature alignment score 1.4 or 1.82? Please amend either your answer or your comment.', 'The below refers to the standard response (please see CRQ V3 Standard Responses file) that we use for this specific question. The company''s Temperature Alignment score is compared to the sector average TA score, hence the result is 1.82 below the sector average. ', '1618369', '2024-03-22 10:16:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3427, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (804, 22702, 1248, '2009422', '2024-03-20 16:32:21', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: where does the Scope 2  emission for 2022 come from ? Add the location based emissions as well.', 'Location based Scope 2 emissions added to the table. ', '1618369', '2024-03-22 10:18:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (805, 22702, 1249, '2009422', '2024-03-20 16:36:33', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: please add the emission intensity  by net sales, pg 174 of annual report.', 'The provided intensity emissions are Scope 1 and 2 combined, hence I am not able to add them into the case. ', '1618369', '2024-03-22 10:20:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (806, 22702, 1252, '2009422', '2024-03-20 16:48:19', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: please provide some empirical evidence here.', 'In my opinion, the report clearly confirms whether the company evaluated transition strategy using climate change scenario modelling.  The Group has conducted assessments to understand what needs to be done in order to be aligned with the Paris Agreement. This, in turn, affects its strategies and plans. ', '1618369', '2024-03-22 10:29:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3514, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (807, 22702, 1251, '2009422', '2024-03-20 16:41:53', 'Masarin, Lisa', NULL, 'Accuracy of CRQ: for the first row you have the data, please insert them, pg 174 of the annual report.', 'Done.', '1618369', '2024-03-22 10:34:02', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (808, 22380, 1272, '1191828', '2024-03-21 16:56:23', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'I wud change this to less than 2yrs as the TA is 6 and we do not have emission details. conservative approach also considering the last rating', 'Climate analyst comment: We have amended this question as a conservative approach and considering last years rating.', '1540001', '2024-03-22 11:26:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (809, 23002, 1260, '1660361', '2024-03-21 07:58:04', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Just mention that the CRA is being conducted for a Corporate. Refer to BCA - The purpose of the request is to extend a trade limit of USD27.3m to guarantee the importation of spares parts equipment and guarantee gas supply from National Hydrocarbons Corporation (SNH). ', 'As discussed, no changes required. However just updated the trade facility information.', '1600990', '2024-03-22 12:57:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
