INSERT INTO mstr.advisor_memo_report VALUES (812, 22492, 1286, '1575987', '2024-03-22 12:30:30', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Whether the company operates in a sector that would be covered directly by the PAT scheme - I dont think so  ? Please check the website of PAT scheme and let me know if you think otherwise.   Whether they export , if yes to where and if the export market has carbon pricing ? Will there be impact of Carbon pricing in Indian market on Business model/ revenue of the client ?', 'Agreed- This Client is not covered under PAT scheme.', '1286637', '2024-03-25 07:35:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (813, 22492, 1285, '1575987', '2024-03-22 12:25:40', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Does company has exports - Can we comment on export sales ? What is the percentage revenue contributed by Wind power ?', 'Sure - Added comments', '1286637', '2024-03-25 08:20:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (815, 21992, 1215, '1575987', '2024-03-15 15:48:02', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Carbon tax is already applicable on coal fired plant -  "the carbon tax has now been postponed likely until 2025" - Not clear what is postponed ?', 'Last part of the comment has been slightly changed. ', '2007983', '2024-03-25 11:39:10', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (816, 22003, 1225, '1551380', '2024-03-18 02:41:37', 'Leva, Aljaz', 'Tarakji, Ranim', 'not very  clear what policy measures are in place and how does these measures impact client', 'explanation has been added', '2003718', '2024-03-25 13:14:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (817, 22377, 1296, '1489063', '2024-03-25 13:21:08', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'They are not iron smelters and manufacturers of the metal itself - they are downstream users on in product manufacturing - hence this is an incorrect selection. Please choose "other" for the selection.', 'Climate Analyst comment: answer choice updated and comments added', '1540001', '2024-03-25 13:27:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3410, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (818, 22003, 1289, '1551380', '2024-03-25 12:08:16', 'Leva, Aljaz', 'Tarakji, Ranim', 'Other minor issues - There are some updates to targets and progress based on Annual Report and Accounts 2023 . Please update accordingly. ', 'Targets are from CDP & statement has been added from newest Annual report', '2003718', '2024-03-25 13:28:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (819, 22003, 1224, '1551380', '2024-03-18 02:39:24', 'Leva, Aljaz', 'Tarakji, Ranim', 'Please update based on Annual Report and Accounts 2023. ', 'Targets are from CDP & statement has been added from newest Annual report', '2003718', '2024-03-25 13:28:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (820, 22651, 1291, '1489063', '2024-03-25 12:38:43', 'Waclawska, Kamila', 'Leva, Aljaz', 'Are we confident that Exxon Oil Corp is not a fully global corporation with operations and oil fields in numerous locations around the globe - not just constrained to US. I would adjust this to "Global" selection, where there will be higher risk.If this portion was originally Mobil  they also had global operations before acquisition. ', 'Updated. The selection was mostly as there is limited info for the LE and as per BCA pt. 2 they stated the following: EMOC covers most of the U.S. business, and specifically the shale operations of the Group. Nonetheless, agreed with Advisory. ', '1664889', '2024-03-25 15:47:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (821, 22651, 1293, '1489063', '2024-03-25 12:41:58', 'Waclawska, Kamila', 'Leva, Aljaz', 'Again - this is very vague. Can we site any examples or investment they have made in specific mitigations. Saying that their operations are not effected, is not a clear cut strategy.', 'need to discuss this point as there are evidences of adaptation captured in comments. ', '1664889', '2024-03-25 15:58:49', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (822, 22651, 1294, '1489063', '2024-03-25 12:59:21', 'Waclawska, Kamila', 'Leva, Aljaz', 'https://investor.exxonmobil.com/sec-filings/all-sec-filings?form_type=10-Q&year=##document-4794-0000034088-23-000056-2pG22 - CAN WORK OUT oil VS. Gas SPLIT', 'OK, Group''s breakdown has now been provided. Before this was not added since we were not sure that we should apply this to the LE as well. Also, shall we consider ''Oil-equivalent production'' as well? p. 22', '1664889', '2024-03-25 16:10:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3414, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (823, 22919, 1263, '1489063', '2024-03-21 11:33:45', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Can you provide some more detail on this and why would this be relevant for a Gas Trading JV? My guess is that they don''t have any physical assets associated with the entity and so need to understand what this may be.This is also not very detailed in terms of assessing Physcial Risk - this is more acknowledgement.', 'Actioned: Justification added in comments, answer choice retained. ', '1668812', '2024-03-26 05:41:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (824, 22919, 1264, '1489063', '2024-03-21 11:36:55', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Do we have any ideal what these details are? These plans are vague without the details.', 'Actioned: No further details found for physical risk adaptation. Answer changed to no. ', '1668812', '2024-03-26 05:44:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (825, 22919, 1267, '1489063', '2024-03-21 11:42:02', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'This seems driven by reliance data - should note that this is unlikely to flow down given the gas orientated nature of business.', 'Not Relevant: As TA data is prepopulated and non-editable. ', '1668812', '2024-03-26 05:50:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3426, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (826, 22919, 1266, '1489063', '2024-03-21 11:41:11', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'It seems like the regulation is a push towards Gas...heavily. Not sure why we think there would be material impact on the companies business from these regulation (at least in a negative, risk orientated way) - if anything this should boost its profitability.I think this should be updated to show no impact in the foreseeable future.', 'Actioned: Answer choice changed', '1668812', '2024-03-26 05:50:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (827, 22919, 1265, '1489063', '2024-03-21 11:38:51', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Can you explain the rationale of this? If it is primarily a Gas trading entity, I am unsure why it would be categorized and exploration and production entity.Likely a "Downstream - Trading" selection', 'Actioned: Answer choice changed', '1668812', '2024-03-26 05:50:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (828, 22919, 1268, '1489063', '2024-03-21 11:43:09', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Not sure why the text is relevant? Maybe update to say its a 50:50 JV and hence doesn''t directly report its own emissions, and these may be absorbed by the JV groups. (That''s speculative though)', 'Actioned: Non relevant text removed. Same answer choice retained', '1668812', '2024-03-26 05:51:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (829, 22919, 1269, '1489063', '2024-03-21 11:45:54', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'We need to remember the entity we are focused on and not take every group action, if its not applicable. Given this is a gas trader, the only one that may be relevant here is the transportation efficiencies. There is no CCUS, no solar efficiencies etc.. in Gas trading. Please update to remove all those that will not be relevant to a gas trading JV.', 'Actioned: Answer choice and evidence changed to relevant answer', '1668812', '2024-03-26 06:00:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (830, 22919, 1270, '1489063', '2024-03-21 11:46:16', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Think this should be a no - they are not a producer.', 'Actioned: answer choice changed and comment updated', '1668812', '2024-03-26 06:00:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (831, 22607, 1297, '1551380', '2024-03-25 14:10:20', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Other minor issues - please mention that physical location is available on website.https://www.uhrlbd.com/uhrlregisteroffice.phpThe Westin DhakaPlot No 1, CWN (B)Road No. 45, Gulshan -2Dhaka-1212, Bangladeshhttps://www.uhrlbd.com/uhrlcorporateoffice.phpBorak Mehnur (Level-15), 51/B Kemal Ataturk Avenue,Banani, Dhaka-1213, Bangladesh', 'Actioned: the location addresses are put into comments of next section. Also mentioned that the same is not added due to technical issue. ', '1668812', '2024-03-26 06:25:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (832, 22607, 1290, '1551380', '2024-03-25 12:29:08', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Other minor issue - Financial year end is Jun. So Annual Report is for the financial year 1 July 2022 to 30 Jun 2023. Source year should put 2023.', 'Actioned: Year Changed', '1668812', '2024-03-26 06:27:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (833, 22164, 1300, '1575987', '2024-03-26 04:52:31', 'Masarin, Lisa', 'Baran, Ewa', 'How the comments are considered as Physical risk adaptation plan ?', 'Insurance reported and taken into consideration as adaptation plans to physical risks. Comments now updated. ', '1663704', '2024-03-26 07:45:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (834, 22164, 1301, '1575987', '2024-03-26 05:09:10', 'Masarin, Lisa', 'Baran, Ewa', 'Is revenue loss covered for damages due to Typhoon / Hurricanes ?', 'Yes: "consequential losses" was reported thus deemed as yes ', '1663704', '2024-03-26 07:46:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (835, 23002, 1255, '1660361', '2024-03-21 05:34:37', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'The reason for override is not entirely inaccurate, however the way it is written gives the perception that it is for Project financing. Noted on the comment for Q1.3. However, it would be clearer to mention here that the facility is for trade financing for the export of natural gas and import of spare parts for the power plant (the power plant has been fully paid up). Hence, CRA is against the Corporate (Parent in this case).  ', 'Updated.', '1600990', '2024-03-26 09:20:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (836, 23002, 1261, '1660361', '2024-03-21 08:35:13', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Company does disclose Scope 1,2,3 emissions - refer to SR 2022 pg 16.', 'As discussed, updated the group''s emissions.', '1600990', '2024-03-26 09:23:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (837, 23002, 1257, '1660361', '2024-03-21 05:54:27', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Client''s physical risk profile is driven by very high precipitation stress and high heat stress. -> This is not fully accurate as precipitation stress and heat stress are chronic risks. The description on physical risk profile should be focusing on current-day risks/acute risks.', 'Do not agree. As discussed no changes required.', '1600990', '2024-03-26 10:10:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
