INSERT INTO mstr.advisor_memo_report VALUES (840, 22377, 1295, '1489063', '2024-03-25 13:20:21', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'This seems incorrect - they are not smelting iron', 'Climate analyst comment: This field is auto populated. Unable to amend. Comments updated in 4.1.1', '1540001', '2024-03-26 12:33:59', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
