INSERT INTO mstr.advisor_memo_report VALUES (847, 22360, 1306, '1575987', '2024-03-26 06:13:48', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'How does Carbon tax on coal fired plant is linked to the entity ? Is there mandate to increase Bio fuel blending in Indonesia or fuel efficiency standards - How it will impact the company ? Why Auto related policies are not considered relevant by you ?', 'Entity sells financing for coal fired plant produced cars - production costs may rise. Biofuels and automobiles information integrated.', '1665883', '2024-03-26 19:57:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (848, 22360, 1305, '1575987', '2024-03-26 06:10:48', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'Clarify description on operations of Wuling motors and Wuling finance', 'removed factory comment', '1665883', '2024-03-26 20:02:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3405, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (849, 22360, 1308, '1575987', '2024-03-26 07:20:31', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'Can you comment on the percentage of EV sales for SAIC or Wuling and any further plans to increase sales of Alternate energy vehicles.', 'sure', '1665883', '2024-03-26 20:03:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (850, 22494, 1318, '1575987', '2024-03-26 15:24:07', 'Waclawska, Kamila', 'Baran, Ewa', 'Use ESDD report . Please only use info related to the project ( PEF transaction )Please only use the physical risk impact related to the project.  Further update : These are generic physical risk impact . Please Share ESDD report It will have relevant project level physical risk impact', 'TAQA reports were used as these mentions the Project and it was confirmed with the CA/RM. After discussed - changes were made. ', '1663704', '2024-03-27 08:41:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (851, 22494, 1319, '1575987', '2024-03-26 15:25:43', 'Waclawska, Kamila', 'Baran, Ewa', 'Not aligned to the Physical risk faced by the project . Chronic physical risk - Heat stress and water stress is not covered by adaptation plan . Review ESDD report Insurance does not include chronic Physical risk Further update : Please share the ESDD report ', 'Additional comment to include insurance now added. Answer choice was selected as medium risk to location from sea level rise was reported from last year''s Munich RE report. Floods due to the rain event/rain season were also mentioned thus we deemed this as applicable and sufficient adaptation plan. ', '1663704', '2024-03-27 08:44:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (852, 22494, 1321, '1575987', '2024-03-26 16:23:18', 'Waclawska, Kamila', 'Baran, Ewa', 'We should take only project level data - Refer to PEF guide. Further update - Not correct - Refer to the discussion. ', 'User Guide for Power lists "No change" when it comes to Q5.5.1, following the fact that the Sponsor''s reporting includes the Project it was taken into consideration. After the discussion, Q5.5.1 was changed. ', '1663704', '2024-03-27 08:49:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (853, 22635, 1324, '1489063', '2024-03-27 12:37:11', 'Masarin, Lisa', NULL, 'Can you explain what these policies are - to me there should be minimal policies in place on the airports themselves, as they are not contributing largely to the emissions created in the aviation industry, which is mainly derived from burning of jet fuel.Emissions may come about from electricity usage of the airports, however in the US I would expect the grid to be greener and hence less emissions from Scope leading to lower regulation. Please provide details, else I cannot agree to immediate policy impact.', 'As an example: Airports Climate Challenge:In April 2022, Federal Aviation Administration (FAA) and airport and environmental stakeholders in the aviation industry launched an Airports Climate Challenge to help achieve the administration’s goals of net-zero emissions of Greenhouse Gases (GHG) economy-wide by 2050.https://www.faa.gov/airports/environmental/airports_climate_challengeHowever, I do agree with your logic and happy to change the answer to Additional policy measures expected in next 5-10 years. ', '1618369', '2024-03-27 13:18:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
