INSERT INTO mstr.advisor_memo_report VALUES (857, 23426, 1323, '1551380', '2024-03-27 06:45:42', 'Komjati, Dalma Beatrix ', NULL, 'As per BCA Part 2 (see page 7), Company does more than just constructing solar power station. In addition, some information on project has been given with 3 of the top 5 projects being offshore projects (in Japan, Portugal and Australia). While I do not think offshore projects should be taken into consideration in physical risk assessment based on the fact that the construction tenor of PV power station is usually up to 2 years as per BCA Part 2 for PV power stations (longer for offshore projects requiring local approvals), it will be appropriate to mention that the company works on offshore projects. Pg 7- CNED mainly engages in the development, construction and operation of utility scale ground-based centralized PV power station. - After business restructure in 2022, CNED had around 52% revenue from EPC business, 34% from PV power station operation and the rest from others in 3Q 2023. For the main EPC business, 45% of the EPC revenue ', 'resolved', '2006082', '2024-03-28 11:27:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (858, 22427, 1312, '1575987', '2024-03-26 09:58:36', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Why not including break up in Gas or Oil ?', 'Updated under Oil.', '1600990', '2024-03-28 12:03:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (859, 22427, 1313, '1575987', '2024-03-26 09:59:27', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Include the amount of carbon tax applicable on per tonne of Co2', 'Added from policy tracker.', '1600990', '2024-03-28 12:13:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (860, 22427, 1314, '1575987', '2024-03-26 10:00:24', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Please check the PD - It should not be zero if there is a coal based power generation.', 'Updated the value as 0.0078% from PD file.', '1600990', '2024-03-28 12:15:35', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3429, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (861, 22804, 1335, '1660361', '2024-03-28 08:54:59', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Disagree with reply: As mentioned, scenarios here refer specifically to RCP, SSP, RCP/SSP scenarios (due to different greenhouse gas composition and temperature outcomes in the future).Answer should be for 1 scenario only.  Scenarios here refer to scenarios prescribed by IPCC or other bodies, e.g., RCP, RCP/SSP. While the company has not indicated clearly which RCP or RCP/SSP scenario, they have given an estimate (not multiple estimates). Hence the most appropriate answer should be for 1 scenario only.', 'agreed', '1663712', '2024-03-28 13:43:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3303, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (862, 22804, 1337, '1660361', '2024-03-28 10:33:06', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Do not agree with option selected. The company has only estimated costs but has not made a clear indication to take any measures currently or in the future to reduce physical risks. ', 'Disagree. The clients has estimated the cost of maintaining cooling infrastructure suitability and has reported is as a work in progress.', '1663712', '2024-03-28 13:44:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (863, 22804, 1345, '1660361', '2024-03-28 13:36:24', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Data centres consume very high amounts of electricity and using 100% renewable energy is impactful in meeting targets. The answer should be "Yes".', 'corrected', '1663712', '2024-03-28 13:46:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (864, 22804, 1344, '1660361', '2024-03-28 13:34:29', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Only option 2 - lower emission fuel types applicable', 'corrected', '1663712', '2024-03-28 13:46:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (865, 22427, 1316, '1575987', '2024-03-26 10:45:16', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'The core operations is electricity generation. Majority of the capacity is fossil fuel based. Capacity of solar + biofuel is minimal compared to overall gen capacity . Incremental addition target are low and will not have meaningful impact. ', 'response updated.', '1600990', '2024-03-28 13:59:26', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (866, 22804, 1339, '1660361', '2024-03-28 13:29:47', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Noted emissions estimated by S&P - unable to actual reported company emissions from CDP website as it is down for 2 weeks. Comfortable with this approach as company operates on ~100% renewable energy, no material transition risk is expcted. To review and update with actual company reported emissions in the next renewal.Disagree with reply: The CDP website is down, so it cannot be verified. However, the 140 data centres you mentioned is for the entire Group (STT GDC). The CDP report is pertaining only to Virtus Data Centres (UK arm), which is aligned to the legal entity here. Please verify once the CDP website is operational again.Understand that this is a project financing case and typically asset-level emissions are applicable However, per the BCA, SCB is financing all 11 existing data centres (including the development of 2 new ones). This is consistent with the CDP report, which includes all existing 11 data centres within the UK (do', 'Disagree. Many cases last year were done incorrectly as we did not have guidelines regarding project financing cases.As per CDP 0.1 They report for 140 data centers, we would need emissions data specify to the data centers SCB is sponsoring.', '1663712', '2024-03-28 14:02:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (867, 22804, 1340, '1660361', '2024-03-28 13:29:56', 'Mutepfa, Tashinga', 'Popielarczyk, Dagmara', 'Noted no targets as we are relying on S&P data, given that CDP website is down for 2 weeks.', 'Disagree. Many cases last year were done incorrectly as we did not have guidelines regarding project financing cases.As per CDP 0.1 They report for 140 data centers, we would need emissions data specify to the data centers SCB is sponsoring.', '1663712', '2024-03-28 14:03:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (868, 22427, 1317, '1575987', '2024-03-26 10:49:34', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'How does client is impacted in these scenarios ?', 'updated.', '1600990', '2024-03-28 14:15:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3514, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (869, 22427, 1311, '1575987', '2024-03-26 09:56:38', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'From the comments , It is not clear what will be the impact of physical risk on the business or supply chain of the company ', 'updated the extract.', '1600990', '2024-03-28 15:10:35', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (870, 22769, 1348, '1493184', '2024-03-28 14:31:24', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Analytical issues:  Seems like company is a refiner (downsream company), not an integrated player - pl. confirm and edit.', 'agree, changed.', '1663712', '2024-03-28 15:32:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (871, 22769, 1349, '1493184', '2024-03-28 14:34:50', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Analytical issues: Seems like Scope 3 emissions are increasing -- We need to show this in the CRA plus Scope 1+ also has not been continusouly declining ', 'agreed. A comment added, as the calculations refer strictly to declared targets. ', '1663712', '2024-03-28 15:37:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (872, 23440, 1342, '1575987', '2024-03-28 13:30:45', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', 'Please use Opco details here', 'Q.4.1.1 cannot be answered as it is graded out by default due to NTB light-touch approach', '2006519', '2024-04-01 07:55:24', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3420, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (873, 23440, 1343, '1575987', '2024-03-28 13:31:20', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', 'Is ETS currently not in place in Europe ? Why are we not marking as policy currently in place. ', 'Provided EU ETS as applicable and answer choice changed to policy currently in place.', '2006519', '2024-04-01 08:02:49', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
