INSERT INTO mstr.advisor_memo_report VALUES (875, 23440, 1347, '1575987', '2024-03-28 14:26:44', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', 'Tata Steel Nederland is transforming its steel production in IJmuiden to a radically differentprocess. In doing so, the use of coal will become superfluous. For example, we have theambition to achieve a CO₂ reduction of about 35 to 40% as early as 2030 - Refer to sustainability report. ', 'Provided short-term target.', '2006519', '2024-04-01 08:32:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (876, 23111, 1356, '1493184', '2024-03-28 22:40:01', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'If there are multiple vessels -- please list the emissions of the vessels in the comments.', 'As per the BCA Part2, The LE, Front Hebe owns only one ship i.e. Front Leopard, IMO no. - 9703320. Hence, we have taken the Emission of Front Leopard in consideration. ', '2008896', '2024-04-01 13:31:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3506, 'CTP3', 'esg_navigiator', '01');
