INSERT INTO mstr.advisor_memo_report VALUES (878, 23111, 1354, '1493184', '2024-03-28 22:34:46', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'Automatic based on ISIC ? Any chance for this to be overriden -- the sector is shipping for the client -- kindly mention so in the comments if its automatic', 'The ISIC code seems to be correct as the LE is operating a shipping vessel - Front Leopard (IMO - 9703320) which is a LR2 (Long Range 2) tankers are defined as those between 85,000 and 124,999 dwt, with coated cargo tanks and cubic carrying capacities of approximately 75,000 metric tons of naphtha. These tankers are utilized on medium and long-haul voyages to transport both clean and dirty oil products.Hence the company is operating in O&G Tanker - Water Transport. ', '2008896', '2024-04-01 13:52:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (879, 23425, 1361, '1191828', '2024-04-01 17:02:27', 'Leva, Aljaz', NULL, 'how can a EV battery manufacturer be classified as power client?', 'The classification has been set automatically and there is no technical possibility to change it. However, according to the user guide, the selection is correct:Storage segment involves the development and deployment of technologies and system that store electricity for later use and help minimize gird losses and ensure higher usage of renewable electricity, increasing the system’s overall efficiency. Hence, storage companies are not directly involved with the generation and transmission and distribution of electricity but support the whole value chain providing batteries and other tools to delay the electricity transmission.', '1618369', '2024-04-02 08:51:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
