INSERT INTO mstr.advisor_memo_report VALUES (892, 23410, 1370, '1551380', '2024-04-03 16:31:51', NULL, 'Gowri, V Kavya', 'Other minor issues - Please make reference to Form 10-K 2023Pg 10 - disruptions from natural or human-caused disasters (including public health crises) or extreme weather (including as a result of climate change), geopolitical events and security issues (including terrorist attacks, armed hostilities, and political conflicts, including those involving China), labor or trade disputes (including restrictive governmental actions impacting us, our customers, and our third-party sellers and suppliers in China or other foreign countries), and similar events; and- potential negative impacts of climate change, including: increased operating costs due to more frequent extreme weather events or climate-related changes, such as rising temperatures and water scarcity; increased investment requirements associated with the transition to a low-carbon economy; decreased demand for our products and services as a result of changes in customer behavior; i', 'Provided additional evidence from Form 10K.', '2006519', '2024-04-04 08:01:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (893, 23410, 1371, '1551380', '2024-04-03 16:33:17', NULL, 'Gowri, V Kavya', 'Other minor issues - Similar comment as above. Please make reference to Form 10-K 2023Pg 10 - disruptions from natural or human-caused disasters (including public health crises) or extreme weather (including as a result of climate change), geopolitical events and security issues (including terrorist attacks, armed hostilities, and political conflicts, including those involving China), labor or trade disputes (including restrictive governmental actions impacting us, our customers, and our third-party sellers and suppliers in China or other foreign countries), and similar events; and- potential negative impacts of climate change, including: increased operating costs due to more frequent extreme weather events or climate-related changes, such as rising temperatures and water scarcity; increased investment requirements associated with the transition to a low-carbon economy; decreased demand for our products and services as a result of chang', 'Provided additional evidence from Form 10K.', '2006519', '2024-04-04 08:02:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (894, 23410, 1369, '1551380', '2024-04-03 10:43:14', NULL, 'Gowri, V Kavya', 'Other minor issues - I would make reference to Amazon''s website (https://www.aboutamazon.com/news/workplace/amazon-safety) and mention about heat mitigation given that rising temperatures is one of the physical risks that the company has identified. It would make sense to change see if we should change the answer as well. Heat mitigationWe ensure our heat mitigation practices meet or exceed state requirements and federal guidance; and in many ways, go above and beyond to set more stringent standards for our sites. Nearly all of the employees in our North American fulfillment centers work in climate-controlled workplaces, and Amazon is one of only a few companies in the industry to install climate-control systems in our fulfillment centers. Our industrial fans provide cooling comfort for work areas, and we also have air-conditioned crew vans at all of our Amazon Air hubs. We’ve seen the positive impacts of an effective heat mitigation pr', 'Answer choice amended and evidence incorporated.', '2006519', '2024-04-04 08:45:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
