INSERT INTO mstr.advisor_memo_report VALUES (897, 23480, 1373, '1551380', '2024-04-04 04:21:20', 'Leva, Aljaz', 'Tarakji, Ranim', 'Other minor issues - Target 1: Unit should be tons of CO2 / 10,000 RMB or Tons of carbon dioxide equivalent / RMB 10,000 operating revenues. Also, there seems to be some discrepancies in the report in terms of base year. In page 37, it mentioned that company is "actively implementing our corporate responsibility to reduce GHG emissions and setting reasonable emission reduction targets, with a plan to reduce GHG emissions by 25% per RMB 10,000 of operating revenue by 2030 compared with that in 2019", not compared with 2020. Hence, please mention it in comments so that we can relook at it (confirm the base year) in the next CRA review.', 'Done', '2003718', '2024-04-04 09:38:17', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
