INSERT INTO mstr.advisor_memo_report VALUES (950, 22683, 1444, '1489063', '2024-04-22 12:14:35', 'Ptasinska, Dorota', 'Kumar, Ajith', 'Pg 9 of the client''s sustainability report appears to indicate a much more global set of operations, with numerous resource mines and then production bases predominately in China - would hence think to update the country choice to China (given the production angle) or Global average', 'Agreed- added', '1286637', '2024-04-23 12:34:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (951, 22683, 1445, '1489063', '2024-04-22 12:16:06', 'Ptasinska, Dorota', 'Kumar, Ajith', 'This is not an assessment - this is a vague statement. We need details of how they have assessed and evidence of some results. This will not suffice as impact analysis. Please update the answer choice if no actual assessment process.', 'Agreed', '1286637', '2024-04-23 12:37:33', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (952, 22683, 1447, '1489063', '2024-04-22 12:18:48', 'Ptasinska, Dorota', 'Kumar, Ajith', 'Does the ETS apply to all corporates or just from certain sectors? And if so, is Lithium covered under this, given it is a transition material.Follow-up: If Lithium is not covered by the ETS, then should we change this to no policy expected in 10yrs? At the moment we are saying higher risk because of policy, even though there isn''t any!', 'No only few sectors are covered by ETS and Lithium is also not covered.', '1286637', '2024-04-23 12:39:29', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (953, 22683, 1446, '1489063', '2024-04-22 12:17:42', 'Ptasinska, Dorota', 'Kumar, Ajith', 'Can we update the commentary in either this or Q4.1.1. to mention that the ISIC tagging is not 100% encompassing of the NZ sector and given this is a lithium player would fall out of scope and into "Other mining" section.', 'sure added', '1286637', '2024-04-23 12:40:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (954, 22683, 1448, '1489063', '2024-04-22 12:22:38', 'Ptasinska, Dorota', 'Kumar, Ajith', 'Can we fill this in as well please as they d provide GHG per unit of product - cna be incorporated under Scope 1', 'Noted - added', '1286637', '2024-04-23 12:46:40', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3508, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (955, 22808, 1432, '1493184', '2024-04-18 19:45:52', 'Waclawska, Kamila', 'Tarakji, Ranim', 'Analytical issues: If the group applies same policies across all assets , then how can thre be no data for the asset individually -- how do we know if it adheres to Group policies ?', 'As agreed ', '2003718', '2024-04-24 08:45:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (956, 22083, 1467, '1575987', '2024-04-24 04:36:37', 'Ramesh, S', 'Gowri, V Kavya', 'At one hand we are saving that Wavistrong is low carbon solution on other hand we are saying carbon intensity of product is very high ', 'The manufacturing process is energy intensive hence deemed to be reliant on high carbon products. The products (Wavistrong) produced are low carbon in nature and has lower GWP compared to steel or HDPE. Thus the answer choice ''high'' is selected.', '2006519', '2024-04-24 09:54:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (957, 22083, 1466, '1575987', '2024-04-24 04:34:06', 'Ramesh, S', 'Gowri, V Kavya', 'With expectation of carbon pricing in next two year - Can you please confirm why client wont be impacted ?', 'Though the carbon pricing is expected in the next two years in UAE, they have not disclosed structured categorization of sectors that will be impacted by carbon-credit trading exchange. Hence the answer choice 5-10 years is selected.', '2006519', '2024-04-24 10:20:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (958, 22083, 1465, '1575987', '2024-04-24 04:31:49', 'Ramesh, S', 'Gowri, V Kavya', 'Page 6:The combination of the in-house manufacturing process and independent suitability testing ensures that Wavistrong UPW is free from contamination and suitable for safe and sustainable use in the electrolysis process. Therefore, Wavistrong UPW offers an extremely cost-effective, low carbon solution for Ultra Pure Water service. Not clear - Can you explain this?', 'Amended the answer choice as discussed.', '2006519', '2024-04-24 10:25:48', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (959, 22083, 1464, '1575987', '2024-04-24 04:30:34', 'Ramesh, S', 'Gowri, V Kavya', 'How this will help to reduce their scope 1 & 2 emissions ?', 'The company chooses to manufacture low carbon products when they have a choice to manufacture high carbon - steel or HDPE piping system which will have a directly impact on their emission intensity. Hence the answer choice has been selected as meaningful impacts towards set targets.', '2006519', '2024-04-24 10:29:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (960, 23008, 1470, '1489063', '2024-04-24 10:15:23', 'Leva, Aljaz', 'Popielarczyk, Dagmara', 'These look like quantifiable targets? Carbon intensity has an associated figure attributed to it, so not sure why you have chosen this option.  Would change to quantifiable S1,2 3targets', 'agreed and changed', '1663712', '2024-04-24 10:30:01', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (961, 23529, 1461, '1575987', '2024-04-23 06:06:03', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Please check if client has short term targets or they have agreed for IMO revised GHG targets. ', 'No other short term target found apart from long term 2050 Net zero target. ', '1563645', '2024-04-24 12:46:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
