INSERT INTO mstr.advisor_memo_report VALUES (963, 22131, 1469, '1575987', '2024-04-24 05:34:10', NULL, 'Gowri, V Kavya', 'Should be answered on the basis of manufacturing locations of the company ', 'Climate policies were provided based on manufacturing locations (US) of the company and additionally Policies of India are included.', '2006519', '2024-04-25 06:21:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
