INSERT INTO mstr.advisor_memo_report VALUES (971, 22175, 1489, '1599218', '2024-04-25 16:58:36', 'Chourasia, Sneha', 'Jen, Yvonne ', 'Analytical - have you checked the LOA with the RM? Why have you not used the Group level 2022 Sustainable Development Report available at this link https://www.sdic.com.cn/en/socalres/A0204index_1.htm', 'Yes, LoA was checked with RM and he agreed to the proposed LoA at entity level.However, based on the discussion, changed the LoA to Group.', '1600990', '2024-04-26 16:35:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (972, 22955, 1498, '1493184', '2024-04-26 13:33:05', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'CRQ Accuracy: What about Scope 3 emissions for 2023. Its available for 2022 but not 2023 ?', 'Not Applicable: Scope 3 data for 2023 is not reported in both Sustainability Report and CDP Report. ', '1668812', '2024-04-26 19:12:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (973, 22955, 1497, '1493184', '2024-04-26 13:31:48', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Looks like an engineering company and not an O&G servie provider -- can you check with business if they have the right ISIC ?', 'Actioned: As checked in Creditmate, the ISIC is 3823 and ''Legal Entity - ISIC Description'' is "MFR&REPR OF MING, OILFIELD&GASFIELD&RLATED MACH&EQU." which is then mapped to ''Legal Entity - Industry Limit Classification'': "O&G Services Provider." The business activities match the ''Legal Entity - ISIC Description.'' The other matching ISIC with entities business is 5041 with ''Legal Entity - ISIC Description'': "EXCAVATION AND EARTH MOVING WORKS" which is then mapped to ''Legal Entity - Industry Limit Classification'': "Building Products, Construction & Engineering." Mail sent to RM/CA for confirmation on ISIC. ', '1668812', '2024-04-26 19:23:06', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
