INSERT INTO mstr.advisor_memo_report VALUES (978, 22549, 1511, '1575987', '2024-04-29 05:27:45', 'Davies, Krista', 'Delaney, Peter Jared', 'We should focus on measures applicable on RIGS ', 'Would these not be applicable?1. ONGC has adopted comprehensive measures and  advanced technology for energy and emission management.2. ONGC is focusing on the reduction of flaring by installation of gas compressors.3. ONGC has installed energy efficient LEDs across its establishments.4. Regular maintenance and technology up-gradation has improved energy efficiency.5. ONGC has SOPs in place to arrest Pipeline leakages, if anyLimited effectiveness is also reflected in Q5.6.1 answer choice', '1665885', '2024-04-29 08:20:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (979, 22549, 1509, '1575987', '2024-04-29 04:50:03', 'Davies, Krista', 'Delaney, Peter Jared', 'IMO regulations will apply on RIGS.  IMO annexure VI regulations are applicable . IMO revised GHG strategy does not specifically excludes Rigs - Please make changes accordingly. ', 'Updated', '1665885', '2024-04-29 08:21:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (980, 22959, 1484, '1599218', '2024-04-25 16:45:30', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Analytical aspects - these seem to be O&G-related targets, which are not related to the Power SectorNEW COMMENT: Analytical aspects - as per previous comment, this target is not applicable because it relates to O&G business of Aramco, not the power sector. Additionally, Aramco''s climate commitments refer specifically to  across wholly-owned operated assets (see page 10 of Annual report). This project is owned at 20% by Aramco, clearly not in scope for the NZ target. ', 'Actioned: Aramco does not have specific target related to the project; however they have an overall GHG reduction target for the whole company that is taken into account as it will cover all the sector''s that the company operates, and it is also aligned with Saudi''s decarbonization vision. Actioned New Comment: Agreed with the above rationale amended answer choice to "No targets" as project is not in scope of the stated target.  ', '1668812', '2024-04-29 09:01:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
