INSERT INTO mstr.advisor_memo_report VALUES (990, 23011, 1490, '1493184', '2024-04-26 08:54:48', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Minor issues:  Good call by the checker to make this asset intensive. However a key reason why the ratio doestn apply here is because Formosa Plastics Marine Corporation is the financing arm and treasury center for FPG’s fleet -- so in this case (I think as mentionedin the user guide), you shoudl consider the activties of the wider group/client (and not jst financing) -- please include one line stating it is a treauy centre, hence you rfere to the shipping activitiesAlso -- how are the locations deemed to be representative -- I can see checker comments but i can''t see the locations due to the error, but can you confirm which locations ahve been included. (Also are the traed routes fixed -- how do we know these ports are critical, does it say so ?) ', 'I has already been stated that despite the ratio, the Client is affected by physical risk due to the nature of the business. Munich Re was conduced for LE''s HQ. However it is not representative. - i added a comment now', '1663712', '2024-04-29 09:38:25', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
