INSERT INTO mstr.advisor_memo_report VALUES (994, 23611, 1508, '1575987', '2024-04-29 03:29:29', 'Mutepfa, Tashinga', 'Ptasinska, Dorota', 'Fuel standard in China and EV policy wont apply to cars exported to South Africa. ETS policy of china would be more relevant which can increase the input cost of manufacturing and hence dealer margins', 'Answer choice remains the same. Comment amended to: Due to its massive dependence on auto production entity located mostly in China, it may by indirectly impacted Chinese regulations. Fuel standard in China and EV policy wont apply to cars exported to South Africa, however ETS policy seems relevant and can increase the input cost of manufacturing and hence dealer margins. China EV and fuel polices removed. China ETS added.', '1611650', '2024-04-29 11:06:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (995, 22680, 1495, '1599218', '2024-04-26 11:36:41', 'Masarin, Lisa', NULL, 'the system is now fixed - can you please add the locations alongside lat and long? You should also have two locations from S&P. please use them', 'Both addresses mentioned in S&P (for the LE and the Parent) refer to the same location:No. 3009, BYD Road, Pingshan New Area Shenzhen, Guangdong 518118', '1618369', '2024-04-29 11:31:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
