INSERT INTO mstr.advisor_memo_report VALUES (999, 22531, 1441, '1493184', '2024-04-21 22:36:52', 'Davies, Krista', 'Delaney, Peter Jared', 'Minor issues:  Is there nothing on Scope 1 ? Is the target set only for purchase of electricity ? (and not based on in house emissions)', 'I''ve aligned this case with clone case that is approved (LEID: 13825455)', '1665885', '2024-04-29 19:39:29', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
