INSERT INTO mstr.advisor_memo_report VALUES (1003, 23628, 1535, '1493184', '2024-04-30 11:00:30', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Minor issues:  Kep it brif --  The linear reduction factor was set at 5.15 from 2024 and 5.43 from 2028. The Council and Parliament agreed to auction an additional 30% of the auction volume for the first year of the launch of the system, so that it runs smoothl --- These details are ont required. The idea is to highlight the policies which may cause a risk.Please also provide details on the buildings directive on Europehttps://www.rics.org/news-insights/european-parliament-adopts-epbd-to-decarbonise-europes-buildings#:~:text=After%20two%20years%20of%20negotiation,it%20climate%2Dneutral%20by%202050.Kindly update the policy circular as well', 'agreed - Due to space constraint added few lines from Building Directive in Europe policy', '1286637', '2024-04-30 12:12:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1004, 22626, 1526, '1551380', '2024-04-30 03:46:03', 'Pal, Aditya', 'Jen, Yvonne ', 'Other minor issues - company is the procurement arm and oversea selling arm of the group. Hence the trade flow is buying wood pulp from overseas and sell to related parties in China. Once the manufacturing is done in China, company will buy the finished paper products from related parties in China and sell them to buyers in HK and Macau. So you will see that key suppliers are from 3rd parties overseas (pulp) and China related parties (paper) and then key buyers are from China related parties (pulp) and 3rd parties HK+Macau (paper). The part I would like you to change or update is the part on "company''s top buyers are from China and Hong Kong". You might want to just mentioned that top buyers for paper products are from Hong Kong and Macau. ', 'Updated the comment to mention"HK & Macao" as the top buyers for paper products.', '1600990', '2024-04-30 12:18:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1005, 22626, 1524, '1551380', '2024-04-30 02:58:50', 'Pal, Aditya', 'Jen, Yvonne ', 'Other minor issues - answer selection is correct but the explanation needs to be changed. The group is one of the top 3 household paper makers in China. Main products include paper rolls, coreless rolls, facial tissues, tissue handkerchiefs, wipes, personal care products, baby diapers, cotton tissues, etc. Company is the procurement arm and oversea selling arm of the group. Hence, client''s operations which are closely tied to Group''s operations are deemed to have high reliant on fossil fuel as pulp and paper industry is an energy intensive industries.', 'Added, the explanation for very high answer selection based on the feedback above. ', '1600990', '2024-04-30 12:54:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
