INSERT INTO mstr.advisor_memo_report VALUES (1007, 22387, 1540, '1493184', '2024-04-30 16:35:16', 'Pal, Aditya', 'Jen, Yvonne ', 'Analytical issues:  While some of the points here are noted, this loan is for constructing the property -- also need to tqke into account practices during construction. As a result, planned change in product mix can be removed/ (which are the low carbon alternatives chosen ?)', 'Removed : Planned change in product mix.', '1600990', '2024-04-30 18:09:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1008, 22387, 1541, '1493184', '2024-04-30 16:37:40', 'Pal, Aditya', 'Jen, Yvonne ', 'Same as above, most of the proposed improvements are during operatiosn of the building.While this is well noted and acceptable, our loan is for the construction period. Hence the changes will not impact the majority of core operations.', 'changed the answer choice to no.', '1600990', '2024-04-30 18:12:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
