INSERT INTO mstr.advisor_memo_report VALUES (1011, 23422, 1519, '1489063', '2024-04-29 16:13:20', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'As such, S-OIL beefed up its risk response manual in preparation for typhoons and heavy rain, designed new facilities in a way that production will continue uninterrupted in spite of precipitation exceeding the highest level since observations first began, and overhauled the sewage discharge system of the Refinery in 2019. Also, S-OIL installed an additional Single Point Mooring (SPM) in 2020, a facility for unloading crude oil, to ensure a prompt response when crude oil unloading can be impeded for a long period due to a typhoon, etc. Other than the above, S-OIL set up facilities to prevent health risks for outside workers and work speed slowdowns under scorching heat in summe', 'Feedback Incorporated.', '2008896', '2024-05-01 15:22:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1012, 22626, 1545, '1551380', '2024-05-02 02:07:14', 'Pal, Aditya', 'Jen, Yvonne ', 'Other minor issues - putting comment here so that this will not be missed. For source table in Q1.1, the Source Year is the year of the reference report, not the year when the report was published. So Source Year for 2022 Environmental, Social and Governance (ESG) Report should be "2022" not 2023 and Source Year for Zhongshun Jierou Paper Co., Ltd. 2023 Annual Report should be "2023" not 2024. Please refer to User Guide. ', 'Updated the source date.', '1600990', '2024-05-02 07:26:24', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3102, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1013, 22626, 1525, '1551380', '2024-04-30 03:23:36', 'Pal, Aditya', 'Jen, Yvonne ', 'Other minor issues - I believe the ESG report used is for 2022. 2023 Annual Report and ESG report have just been published, please update CRA accordingly. AR: https://pdf.dfcfw.com/pdf/H2_AN202404241631142637_1.pdf?1713986268000.pdfESG: https://pdf.dfcfw.com/pdf/H2_AN202404241631142613_1.pdf?1713986450000.pdf', 'As discussed with Ramesh only using the latest AR.', '1600990', '2024-05-02 07:26:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
