INSERT INTO mstr.advisor_memo_report VALUES (1026, 23883, 1560, '1575987', '2024-05-12 16:39:08', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'What is the location of manufacturing facility - Carbon pricing is based on location in US. ', 'All operations are in the US', '1663712', '2024-05-13 04:09:24', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1027, 23883, 1561, '1575987', '2024-05-12 17:07:13', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'How the evidence is of improvement in efficiency ?', 'agreed. removed', '1663712', '2024-05-13 04:09:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1028, 24627, 1567, '1551380', '2024-05-13 03:32:39', 'Davies, Krista', 'Delaney, Peter Jared', 'LoA - since properties had commenced operations, we should consider the reports/information of property operator (iQ Student Accommodation) as well. So we should be using asset level disclosure + any strategy or plan available at property operator (iQ Student Accommodation) level. ', 'Hi - I already checked iQ student accomodation, they have no public reporting and all sustainability is focused on student wellbeing', '1665885', '2024-05-13 08:26:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1029, 24627, 1566, '1551380', '2024-05-13 03:04:37', 'Davies, Krista', 'Delaney, Peter Jared', 'Other minor issues - Environmental due diligence is something provided by RM/CA? What is the assessment based on MunichRe on the 2 locations?', 'NTB - Munich Re scoring not relevant', '1665885', '2024-05-13 08:27:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1030, 24627, 1569, '1551380', '2024-05-13 05:39:53', 'Davies, Krista', 'Delaney, Peter Jared', 'Other minor issues - the part on "The assets have achieved A+ efficiency rating and are considered to comply with the UK environmental regulation and hence no additional policies in 10 years has been selected", is this something which has been agreed with Harsh for CRE names?', 'No - but they have already met the energy efficiency requirements outlined below from the policy tracker regarding energy efficiency', '1665885', '2024-05-13 08:29:28', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1031, 24627, 1565, '1551380', '2024-05-13 02:54:26', 'Davies, Krista', 'Delaney, Peter Jared', 'In BCA Part 2, it has been mentioned that information undertaking include ESG reporting. What kind of ESG reporting will be available and starting when? It was also mentioned that there is intention to book loan as a Green Loan, with the Day 1 criteria and ongoing reporting requirements being assessed by the SCB Sustainable Finance (SF) team. What kind of Day 1 criteria and ongoing reporting requirements can be expected? Please check with Business Team if there are any plans or targets to be included in Day 1 criteria or reporting requirements. Please note that if these are not available, Additional Analysis or customised risk trigger will be added. ', 'The BCA (and ESRA) notes Blackstone ESG Reporting not IQ Student AccommodationOther comments included via outreach - have cc''d you in email', '1665885', '2024-05-13 08:39:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1032, 24627, 1568, '1551380', '2024-05-13 04:23:42', 'Davies, Krista', 'Delaney, Peter Jared', 'CRA summary analysis - some words and sentences need to be amended. Please check again. Do not say "LEID" please. Examples (see wordings in " ") - 1) The "LEID" has generated a GREEN BRAG "is driven low exposure" to transition risks given the assets compliance with the UK energy efficiency regulations for buildings. 2) The assets are sponsored by Black Rock but it has been deemed environmental disclosures are "too attached" from acquisitions of the assets for application of emissions and management of the assets. ', 'done', '1665885', '2024-05-13 08:57:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1033, 24627, 1564, '1551380', '2024-05-13 02:52:33', 'Davies, Krista', 'Delaney, Peter Jared', 'Only one property available - do you mean emission data is available for one property only currently? There should be 2 properties so does it mean data will be available for both properties going forward? please clarify and include in comment. ', 'have clarified with Jacqueline - will source for next CRQ', '1665885', '2024-05-13 08:57:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1034, 24626, 1574, '1493184', '2024-05-13 18:08:19', 'Pal, Aditya', 'Scariah, Renjith ', 'Minor issues:  Carclays and SMBC closed which transaction - is it relevant to this transaction ?', 'Climate Analyst comment: Comments removed', '1540001', '2024-05-14 06:53:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1035, 24626, 1575, '1493184', '2024-05-13 18:09:02', 'Pal, Aditya', 'Scariah, Renjith ', 'Minor issues:  Operations are affected by physical risk because they are asset intensive , not because they are spread across the country', 'Climate Analyst response: Comments updated', '1540001', '2024-05-14 06:54:56', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1036, 24626, 1577, '1493184', '2024-05-13 19:07:11', 'Pal, Aditya', 'Scariah, Renjith ', 'Analytical issues:  If the assets are already constructed, it is held by the asset managet as an investment, the asset in its operation stage. Others etc refer to very specific real estate actiity (not the nature of the asset)', 'Climate Analyst response: Amended the option to "operation"', '1540001', '2024-05-14 06:56:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1037, 24626, 1578, '1493184', '2024-05-13 19:08:07', 'Pal, Aditya', 'Scariah, Renjith ', 'Analytical issues: Till the remaining 50% are not complied, we cannot choose this option, policies are effective within 5 years.', 'Climate Analyst response: Amend', '1540001', '2024-05-14 06:58:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1038, 24588, 1570, '1575987', '2024-05-13 06:17:12', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Geographical segmentation data is available in page 33 of the annual report - Please use the same. ', 'The answer has been selected based on disclosures published on LE level. "LE is domiciled in HK and is holding company of the foreign subsidiaries (Indonesia, Vietnam, Malaysia, the Philippines, and Thailand)." South-Eastern Asia region represents physical risk rank for LE''s subsidiaries. Geographical segmentation data published in Annual Report show revenue on Group level. Please advice if the answer should be changed. ', '2007983', '2024-05-14 07:23:58', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1039, 24588, 1571, '1575987', '2024-05-13 06:24:15', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Why it cant be considered as adaptation plan for business operations ?', 'updated', '2007983', '2024-05-14 07:24:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1040, 24588, 1572, '1575987', '2024-05-13 06:44:09', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'China Policies needs to be considered as it contribute 60% of the revenue.  ', '60% of the Group''s revenue comes from China.LE is domiciled in HK and is holding company of the foreign subsidiaries (Indonesia, Vietnam, Malaysia, the Philippines, and Thailand). CA did not mention Chinese revenues/operations on LE level. Please advise if China Policies still should be added to the comment. ', '2007983', '2024-05-14 07:25:48', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1041, 22229, 1554, '1551380', '2024-05-10 05:28:08', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Other minor issues - please add information found in Gildan’s 2022 Climate Change Disclosure Report Pg 20 as it relates to Bangladesh which is more relevant here.Cleantech investments: We are piloting new dyeing machines that have the potential to reduce our energy, water, and chemical use. Depending on the success of this pilot, we plan to gradually introduce this equipment across our manufacturing sites. Additionally, we are investing in a new powerhouse in Bangladesh to recover exhaust gases to produce steam to the facility and reduce hot water consumption. This will reduce our natural gas consumption and increase energy efficiency.', 'Updated additional evidence.', '1563645', '2024-05-14 10:11:56', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1042, 22229, 1555, '1551380', '2024-05-10 05:32:43', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Other minor issues - Information found in Gildan’s 2022 Climate Change Disclosure Report Pg 21 is more relevant here. EXAMPLES OF OUR ACTIONS TO MITIGATE RISKSInfrastructure hardening: Investing in the resiliency of our manufacturing facil-ities to withstand extreme weather events including retrofitting and designingfor mitigation (e.g., barriers, sealed motors, raised electronics, etc.)Increase optionality: Working with logistic partners to develop alternativeroutes in the case of extreme weather events; identifying alternative optionsto shift production to other facilities when neededProactive assessments: Performing flood risk assessments at our strategicmanufacturing locations to understand our risk exposure and develop floodmitigation strategiesRigorous planning: Maintaining robust business continuity plans and emer-gency response plans at all facilities, including vendor resiliency plans', 'Updated additional evidence as suggested.', '1563645', '2024-05-14 10:12:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1043, 24626, 1576, '1493184', '2024-05-13 18:10:05', 'Pal, Aditya', 'Scariah, Renjith ', 'Analytical issues: This is now weighted average -- please change to domicile if we''ve directly used UK as the country (Using domicle is ok in this case as there are 330 assets across the country)', 'Climate analyst response: Domicile country is not UK hence no changes as discussed.', '1540001', '2024-05-14 11:36:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1044, 22499, 1579, '1551380', '2024-05-15 01:10:09', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Accuracy of CRQ - Energy Consumption captured instead of emission. Please correct data. ', 'Agreed - Amended Accordingly ', '1286637', '2024-05-15 07:31:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1045, 22499, 1580, '1551380', '2024-05-15 01:45:54', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Accuracy of CRQ - Please review the numbers - (1) Use emission instead of energy consumption and (2) Target level calculation for Target 1 is wrong (target level for target 1 cannot be higher than target 2).', 'Agreed- Amended accordingly.', '1286637', '2024-05-15 07:33:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1046, 24526, 1587, '1551380', '2024-05-16 06:54:02', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Other minor issues Target 1 - Reduce absolute Scope 1 and Scope 2 GHG emissions 28 percent over a 2019 baseline - Should baseline year be 2019 instead?', 'Climate Analyst comment: yes..typo error. Amended.', '1540001', '2024-05-16 10:56:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1047, 24526, 1585, '1551380', '2024-05-16 06:19:08', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Other minor issues - doesn''t agree with answer. Manufacturing of steel and plastic containers, and paper products are energy intensive. So answer cannot be low. It can only be Medium at best. Please also amend analysis accordingly.', 'Climate Analyst comment: Agreed. Amended', '1540001', '2024-05-16 11:02:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1048, 24576, 1583, '1599218', '2024-05-15 14:54:25', 'Masarin, Lisa', 'Tarakji, Ranim', 'Analytical: If there were not other comments, I would not have added this but, can you please link each decarbonisation activity to the answers you have provided? For example:- Implementation of CCUS: "Hyundai Rotem is promoting the development of CCUS (Carbon Capture, Utilization, Storage) technology to enter the stage of "blue hydrogen" that collects carbon emitted during the reforming process."- Change in supply chain: "Hyundai Rotem purchased a total of 15.19 billion KRW worth of green products, and it plans to expand the purchase of green products in the future. Furthermore, the company aims to improve policies, such as providing additional points for suppliers certified with environmental-friendly and green technologies."', 'Implemented as agreed with Antonio', '2003718', '2024-05-16 11:12:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1049, 24526, 1588, '1551380', '2024-05-16 07:10:39', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'CRA summary analysis - while I do not strongly oppose to the answer selection here, I would want to highlight the following in analysis.Sustainability report page 26 Transition Risk - Carbon pricing regulations, such as cap-and-trade systems and carbon taxes, are impacting Greif in some markets (Europe and North America) and may emerge in other regions. In addition, please review sentence in Climate Risk Grading (BRAG) Analysis "The company’s disclosure of climate relGreif, Inc. engages in the production and sale of industrial packaging products and services worldwide." ', 'Climate Analyst comment: Comments added. Typo error in BRAG analysis. Amended.', '1540001', '2024-05-16 11:13:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1050, 24526, 1586, '1551380', '2024-05-16 06:31:17', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Other minor issues - please explain the answer selection. (e.g. Based on disclosure in annual report, insurance has been purchased but might not provide full coverage. Hence, no coverage selected.)As per Annual Report Page 14 - "We also purchase environmental liability policies where legally required and may elect to purchase coverage in othercircumstances in order to transfer all or a portion of environmental liability risk through insurance. However, there can be no assurance that anyenvironmental liability claim would be adequately covered by our applicable insurance policies or would not be excluded from coverage based on the termsand conditions of the policy. We do not purchase crop insurance for our timberland holdings, and a forest fire or other event could damage a materialamount of timber."', 'Climate Analyst response: Comments added.', '1540001', '2024-05-16 11:20:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1051, 22669, 1593, '1489063', '2024-05-17 14:00:13', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'WE might need to call out that tin is not Aluminium and potential sector tagging issues - however the general risk assessment level will likely be similar to risk scoring is accurate.', 'Done', '2003718', '2024-05-20 09:03:02', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3413, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1052, 22669, 1594, '1489063', '2024-05-17 14:00:56', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Can you do the conversion to get to a %Update - I meant can you do a conversion of all the raw materials into a kWH unit so that we can compare all the different sources. This is not giving the right message currently. You will have to research energy density conversions - e.g. 1 tonnes of coal burned = X kWH of energy. You should be able to google these', 'Done', '2003718', '2024-05-20 09:03:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3423, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1053, 22145, 1596, '1551380', '2024-05-20 05:42:46', 'Masarin, Lisa', 'Tarakji, Ranim', 'Other minor issues - 2023 summary report available. See https://sustainability.indoramaventures.com/storage/content/sustainability-report/en/executive-summary-2023/doc.pdf. ', 'Added', '2003718', '2024-05-20 09:14:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1054, 22300, 1591, '1489063', '2024-05-17 13:48:05', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'Can we please investigate why the PD scores are so low please - this seems like it should be a high risk client and so don''t think Green is an appropriate rating. Can we identify which financials and emissions data has been used?', 'Even tho carbon price dramatically increased after 2030,  which is reflected in total cost, revenues are also increasing. EBITDA slightly decreased over years same as FCF. However total debt stays the same over the years . Taking into account, there are  small movements in EBITDA,  the threshold is not crossed. ', '1632774', '2024-05-20 10:15:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3430, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1055, 22300, 1589, '1489063', '2024-05-17 13:47:59', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'Can we please investigate why the PD scores are so low please - this seems like it should be a high risk client and so don''t think Green is an appropriate rating. Can we identify which financials and emissions data has been used?', 'Even tho carbon price significantly  increased after 2025,  which is reflected in total cost, revenues are also increasing. EBITDA slightly decreased over years same as FCF. However total debt stays the same over the years . Taking into account, there are  small movements in EBITDA,  the threshold is not crossed. ', '1632774', '2024-05-20 10:16:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3428, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1056, 22300, 1590, '1489063', '2024-05-17 13:48:02', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'Can we please investigate why the PD scores are so low please - this seems like it should be a high risk client and so don''t think Green is an appropriate rating. Can we identify which financials and emissions data has been used?', 'Even tho carbon price significantly  increased after 2025,  which is reflected in total cost, revenues are also increasing. EBITDA slightly decreased over years same as FCF. However total debt stays the same over the years . Taking into account, there are  small movements in EBITDA,  the threshold is not crossed. ', '1632774', '2024-05-20 10:16:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3429, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1057, 22145, 1600, '1551380', '2024-05-20 05:57:39', 'Masarin, Lisa', 'Tarakji, Ranim', 'Other minor issues - information found in CDP should be captured. Also, company actually has a total of 141 operating locations. So while the captured locations are representative, not all locations (can be found on websites) have been captured. I wouldn''t demand all the locations to be added but I will need the commentary to be changed. "As of 31 December 2022, we had 141 operating sites in 35 countries to serve our customers in various applications and end markets.""We are acquiring carbon credits in selected countries which are part of our operations in Advanced Economies countries (Europe and North America). These countries currently constitute 70% of IVL’s global production."', 'Done', '2003718', '2024-05-20 10:19:10', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1058, 22145, 1602, '1551380', '2024-05-20 06:21:01', 'Masarin, Lisa', 'Tarakji, Ranim', 'CRA summary analysis - Generally this is quite a good CRA with minor issues. The key issue is to ensure what is being mentioned in CRA are aligned with company''s reporting and that we point out the important risks being identified in company''s report as well as through our CRQ. This will then help RM/CA to assess the potential financial impacts. Some amendments needed in CRA summary analysis below:Physical Risks Analysis 1) "The parent recognizes that its operations are subject to flood or water shortage risks which can have an impact... " LoA is at entity level so should not mention "parent" here. 2) Information found in CDP like "141 operating sites in 35 countries" and "Advanced Economies countries (Europe and North America) constitute 70% of IVL’s global production" needs to go into assessment and analysis. There are some discrepancies between the reports though so I am not going to demand a change in answer selection in section 2. ', 'Done', '2003718', '2024-05-20 10:28:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1059, 22145, 1601, '1551380', '2024-05-20 06:12:02', 'Masarin, Lisa', 'Tarakji, Ranim', 'CRA summary analysis - please capture below in analysis. CDP C2.3a Our sites subject to ETS in 2022 constitute 11.26% of IVL’s total scope 1 carbon emissions, and we expect that number to grow to 40.1% by 2030. The number of sites under ETS is expected to grow from 7 sites in 2020 to 29 sites in 2030. We also expect that 8.8% of IVL’s total scope 1 emissions to be above the emissions cap, incurring a cost of up to USD 120 m in 2030 according to internal projections based on BNEF, Refinitiv and other analyst carbon price projections.', 'Done', '2003718', '2024-05-20 10:44:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1060, 22145, 1597, '1551380', '2024-05-20 05:45:23', 'Masarin, Lisa', 'Tarakji, Ranim', 'Other minor issues - 2023 numbers available. See https://sustainability.indoramaventures.com/storage/content/sustainability-report/en/executive-summary-2023/doc.pdfORhttps://sustainability.indoramaventures.com/en/environmental/ghg-management', 'Done', '2003718', '2024-05-20 10:53:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
