INSERT INTO mstr.advisor_memo_report VALUES (1063, 23437, 1592, '1489063', '2024-05-17 13:56:33', 'Leva, Aljaz', 'Tarakji, Ranim', 'I don''t see evidence of why this is hence a high emitter or reliant on fossil fuels. Can you please understand what their energy mix is in production and what are their future intended mixes, as well as current emissions levels compared to peers', 'Done', '2003718', '2024-05-20 12:56:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1064, 24587, 1604, '2009422', '2024-05-22 12:16:13', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Accuracy of CRQ: the clients has already submitted the CDP report for the last two years where a score is also generated.Please amend the answer.', 'this is the default question for NTB and the answer cannot be changed (it is greyed out)', '2001097', '2024-05-22 14:05:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3102, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1065, 24587, 1605, '2009422', '2024-05-22 12:56:16', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Accuracy of CRQ: the answer to this question contradicts the answer to Q5.4. As long as the direct/indirect emissions are disclosed the company identifies transition risk.', 'this is the default question for NTB and the answer cannot be changed (it is greyed out)', '2001097', '2024-05-22 14:05:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1066, 22575, 1617, '1599218', '2024-05-22 17:13:29', 'Pal, Aditya', 'Delaney, Peter Jared', 'throughout the questionnaire you mention you used the 2022 CDP questionnaire (based on 2021 figures) rather than the 2023 (based on 2022 figures). I do not understand why the 2022 is better even though it is rated worse - please use the 2023', '2022 is only used for certain questions -if you compare the response from the 2022 and 2023 reports, the 2022 information is more applicable from a content perspective', '1665885', '2024-05-22 18:28:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3102, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1067, 22575, 1616, '1599218', '2024-05-22 17:11:14', 'Pal, Aditya', 'Delaney, Peter Jared', 'Accuracy - can you please also check if financial impact from chronic is available in CDP? If not, please quote information from page 19 of ESG Report', 'Done but CDP 2022 is still more accurate - nothing included in CDP 2023', '1665885', '2024-05-22 18:33:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3303, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1068, 22575, 1612, '1599218', '2024-05-22 17:03:08', 'Pal, Aditya', 'Delaney, Peter Jared', 'Accuracy of CRQ - can you please remove this data and use the data available in the ESG Rep? Page 59 - please only use 2022 as the previous years are on equity basis meanwhile they will report control basis going forwad', 'done - scope 3 emissions also now available', '1665885', '2024-05-22 18:35:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1069, 22575, 1613, '1599218', '2024-05-22 17:06:02', 'Pal, Aditya', 'Delaney, Peter Jared', 'Analytical - this is clearly because of the rebaseline of the emissions. A 500% increase in emission is senseless given they have restated the scope of accounting.They say that, following the rebaseline, the total reduction between baseline and 2025 is 235k tCO2, which means the 2020 figure is 2,350,000 tCO2 (=235k/0.1). Once you add this baseline, you will still see an increase but much more in line with the current figures. Please also update the current figure based on the comment in the Q5.4', 'done - comment was made before, targets have been updated', '1665885', '2024-05-22 18:41:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1070, 22575, 1615, '1599218', '2024-05-22 17:09:59', 'Pal, Aditya', 'Delaney, Peter Jared', 'Analytical - please mention the financial impact figures available at page 19 for the transition scenario and also what financials they will impact', 'done', '1665885', '2024-05-22 18:44:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3514, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1071, 22575, 1614, '1599218', '2024-05-22 17:07:35', 'Pal, Aditya', 'Delaney, Peter Jared', 'Analytical - please use your own words to explain why this is meaningful - no copy past from reports for this', 'done', '1665885', '2024-05-22 18:48:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1072, 24584, 1608, '2009422', '2024-05-22 14:10:55', 'Gurunathan, Akshay Ram', 'Joardar, Abhisek ', 'Accuracy of CRQ: please either change the answer or comment.', 'Actioned: Answer Choice Aligned with comment', '1668812', '2024-05-23 05:04:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1073, 24584, 1610, '2009422', '2024-05-22 14:26:52', 'Gurunathan, Akshay Ram', 'Joardar, Abhisek ', 'Accuracy of CRQ: 45% reduction in 2030, not in 2050.What are these policies in the next 5-10 year? CABM is effective in 2026, and is currently in a transformation phase.I had a deep dive into European policies i.e EU ETS,  CABM and other related directives such as Biodiversity etc and overall these policies have a significant and material impact on companies operating in sustainability energy sector as well in medium term, influencing  their financial performance , operations and strategic direction as they navigate the evolving regulatory landscape.', 'Actioned: Year changed to 2030. The policies and its impact on the company is detailed, also the reasoning for choosing the current answer added in comments. Answer choice changed as directed to 2-5 years ', '1668812', '2024-05-23 05:13:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1074, 22742, 1618, '1599218', '2024-05-22 17:22:53', 'Masarin, Lisa', 'Baran, Ewa', 'Accuracy - 2020 is not the baseline year - 2020 is the year when the target was announced. the baseline year is 2018 - this is available both in CDP and Sust reportAccuracy - Please also change the response on time horizon - they are both ST and LT', '#1 - indeed it is 2018, for other 2 targets it is 2020. Corrected', '1663704', '2024-05-23 08:02:59', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1075, 22742, 1620, '1599218', '2024-05-22 17:31:11', 'Masarin, Lisa', 'Baran, Ewa', 'Accuracy - can you please use the data available at page 35 of Sust report?Please also mention that the Tennessee plant was acquired in 2021 and no emission information were available and we take the assumption it will decarbonise in line with the domestic ops ', 'Comment added, as we did reference to the targets reported in CDP, CDP values were entered (now updated as per comments), please let us know if you wish to change it.', '1663704', '2024-05-23 08:14:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1076, 22742, 1621, '1599218', '2024-05-22 17:32:23', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical - please be more specific. Call out why this measures are deemed meaningful and how they will help cut emissions. What will the Client ultimately reach?', 'Updated ', '1663704', '2024-05-23 08:19:02', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1077, 22305, 1623, '1551380', '2024-05-23 14:12:51', 'Pal, Aditya', 'Davies, Krista', 'Accuracy of CRQ Targets do not look correct - I cannot find any 40% reduction target in report. Based on extracts below, there should be 4 targets.Extract from Sustainability report:- Achieve carbon neutrality by FY2050 through the value chain - Reduce CO2 emissions 50% by FY2030 (compared to FY2010)- Achieve carbon neutrality by FY2030 at business sites (factories and offices)Extract from Website (https://www.hitachi.com/environment/vision/low_carbon.html):In working toward realizing a decarbonized society, Hitachi has set the goal of realizing carbon neutrality by fiscal 2030 at all business sites (factories and offices) as part of its long-term environmental targets called Hitachi Environmental Innovation 2050.Our roadmap to achieving this goal sets targets of reducing CO2 emissions by 50%, compared to the base year, by fiscal 2024 and 80% by fiscal 2027 toward realizing carbon neutrality by fiscal 2030.5 Targets:1) Scope 1 & 2 - red', '40% reduction target is per CDP Report C4.1a.  However given the targets reported in the SR are more ambitious the target table has been updated to reflect these. ', '2005295', '2024-05-24 12:05:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1078, 22305, 1624, '1551380', '2024-05-23 14:40:43', 'Pal, Aditya', 'Davies, Krista', 'Accuracy of CRQ - Please update progress based on amended targets. If unsure, please reach out to Shuk Fan.', 'Updated per 5,5', '2005295', '2024-05-24 14:39:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1079, 24663, 1636, '1575987', '2024-05-24 10:26:13', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Consider less than 70%  based on the type of EST . Further even for duel fuel vessel AER is not less than 60% compared to non dual fuel vessel ', 'Agreed', '1665885', '2024-05-24 15:23:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
