INSERT INTO mstr.advisor_memo_report VALUES (1110, 22583, 1671, '1191828', '2024-05-30 10:05:42', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Why arent we using BW offshoring reports ? https://www.bwoffshore.com/sustainability/environmental-impact/pls check last year''s CRA ', 'Offshore reporting is already used', '1665885', '2024-05-30 13:43:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1111, 22583, 1675, '1191828', '2024-05-30 10:12:38', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Please re do this based on BW offshoring report. Also check the last CRA and ascertain how a 50% score is coming down to 20%', 'Already using BW Offshore: "GHG emissions from BW Offshore''s operational assets are the liability of our Clients and therefore BW Offshore is in short-term not directly subject to the risk of emerging carbon regulation or other pricing instruments, such as new carbon trading markets or fiscal measures. However, BW Offshore is responsible for monitoring, accounting and reporting the GHG emissions from our operating assets to our Clients. The emergence of new GHG emissions monitoring and accounting requirements will require more capital investment to facilitate monitoring requirements and greater operational costs to maintain the monitoring and reporting systems."', '1665885', '2024-05-30 13:45:12', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1112, 22583, 1672, '1191828', '2024-05-30 10:07:30', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Referring to MARPOL Annex VI, Regulation 19, Applications 2.1 and 2.2, the IMO DCS is not applicable to ships not propelled by mechanical means as well as to platforms, including FPSOs and FSUs and drilling rigs, regardless of their propulsion. Hence this LEID is exempt from IMO regulations on emission reduction', 'BRAG now GREEN', '1665885', '2024-05-30 13:49:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
