INSERT INTO mstr.advisor_memo_report VALUES (1115, 22415, 1678, '1191828', '2024-05-30 13:47:51', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'what kind of BRAG commentary is this ? the client i rated REd and the commentary says client is green. can someone redo the entire piece please.', 'Climate Analyst Comment: The case was rated as Green initially, however post resubmitting the case BRAG changed to red ( after amendingQ4.1.1. based on checker feedback) which was missed from our end. Comments updated to reflect the correct rating.', '1540001', '2024-05-30 14:21:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1116, 22858, 1677, '1489063', '2024-05-30 12:14:59', 'Radhakrishnan, Gowtham ', 'Chourasia, Sneha', 'Are these carbon policies going to be relevant or material for an online booking site for travel - feels like this might be an overestimation of risk.', 'Agreed, I have changed the time period to 5 to 10 years now. ', '2001416', '2024-05-31 08:30:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1117, 22668, 1651, '1551380', '2024-05-28 03:23:53', 'Ptasinska, Dorota', 'Jen, Yvonne ', '(additional qns) this should be 5-10 years as per your offline discussion with Antonio. Please amend.Other minor issues - Could you please also mention that company sells mainly to large companies in US and hence, can be subjected to policy measures implemented in the US on imported goods? Also update analysis in outcome tab please. ', 'Agreed and updated.', '1600990', '2024-05-31 13:46:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1118, 22961, 1679, '1489063', '2024-05-30 14:54:10', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Do they assess a level of risk associated - this seems like an acknowledgement of risk rather than an assessment of where the most critical risks come from - e.g. have they done their own scenario analysis or noted that certain risks are more pertinent than others?', 'Actioned: The company has not performed scenario analysis and no such risk analysis is done. As advised the level of impact is not clear. Answer choice aligned ', '1668812', '2024-05-31 14:11:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1119, 22733, 1676, '1489063', '2024-05-30 12:10:13', 'Waclawska, Kamila', 'Wasylczuk, Nataliya', 'Do we have any emissions analysis on what is the fuel type mix of the buildings / clinic to understand where energy comes from. It is too broad to say all hospitals are highly reliant, because it is very asset specific.', 'Unfortunately not. Group does not provide this type of information. Additionally, to this question, the following comment has been added:Sustainability report, page 15:2.6x energy use of hospitals compared with other commercial buildings; 1 hospital bed = 4 single-family homes in annual energy use', '1607754', '2024-05-31 14:59:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
