INSERT INTO mstr.advisor_memo_report VALUES (1121, 22325, 1693, '1551380', '2024-05-31 17:05:52', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'CRA summary analysis - the BRAG Analysis section will start flowing into BCA directly and hence, please ensure analysis is appropriate and capture key points.First sentence - I echo Checker''s comment that it is not appropriate to say "rated GREEN (unchanged YOY) on account of limited information available with respect to its climate risk position". It sounded like limited information available is something positive and result in client being rated Green. Please amend. ', 'Noted and amended accordingly', '1668331', '2024-06-03 06:49:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1122, 22741, 1660, '1575987', '2024-05-29 12:35:33', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Consider - policy in 5-10 years . Please say Malaysia is exploring carbon tax. Implementation of Carbon tax would impact the portfolio company and can cause additional credit cost ', 'Done', '2003718', '2024-06-03 09:32:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
