INSERT INTO mstr.advisor_memo_report VALUES (1124, 22741, 1661, '1575987', '2024-05-29 13:16:52', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'How does it will have meaningful impact - If the major emissions are scope -3 emissions? Where water is used in digital lending - Use only the measure relevant to the LE', 'Water commentary has been removed, other impacts are meaning full, additional commentary has been provided. ', '2003718', '2024-06-03 09:45:19', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
