INSERT INTO mstr.advisor_memo_report VALUES (1139, 24718, 1713, '1575987', '2024-06-07 05:59:13', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Why we accessing physical risk with respect to shipyard. It is the shipyard risk to deliver the vessel and not the SPV risk if the vessels are delivered or not  ', 'The ship would currently be at the shipyard, so if there was an event at the shipyard that destroyed the vessel under construction then it would delay delivery and impact the terms of the charter and consequently the charter payments linked to the SPV and therefore materially impact the SPV - you also okayed this in the last CRA with the same structure and same shipyard', '1665885', '2024-06-09 17:53:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
