INSERT INTO mstr.advisor_memo_report VALUES (1145, 24722, 1715, '1489063', '2024-06-07 10:22:08', 'Masarin, Lisa', 'Tarakji, Ranim', 'https://www.cdp.net/en/formatted_responses/responses?campaign_id=83630982&discloser_id=1030907&locale=en&organization_name=Diageo+Plc&organization_number=4702&program=Investor&project_year=2023&redirect=https%3A%2F%2Fcdp.credit360.com%2Fsurveys%2F2023%2Fjwbhd7d6%2F258105&survey_id=82591262CDP report submitted - they received an A in 2023', 'This question is blocked for NTB. Thus, we couldn''t select the appropriate choice.', '2003718', '2024-06-10 07:01:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3102, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1146, 24722, 1716, '1489063', '2024-06-07 10:26:11', 'Masarin, Lisa', 'Tarakji, Ranim', 'This is not the appropriate way to answer the question - with blanket assumption for the industry. Pg35 of the company sustainability report shows the split between renewable and non-renewable energy sources.66% reliant on non-renewable.  This is the evidence we should rely on.', 'Group data has been added.', '2003718', '2024-06-10 07:10:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1147, 22045, 1729, '1551380', '2024-06-10 02:54:56', 'Ptasinska, Dorota', 'Brodzicka, Elzbieta', 'Useful information found in Annual Report should be used. Pg 68LCPL has also made great strides in lowering the impact on the environment by reducing greenhouse and acid gases through various modiﬁcation and process optimization which includes installing a co-generation plant, shutting down one steam boiler, diesel generators, and an incinerator and installing a project for recovering metals. Pg 69LCPL operational strategy, post power generation, has reduced thousands of tons of carbon, NO2 and SO2, resulting in a substantial reduction in greenhouse gases. LCPL invested US$ 4 million for a capital project which helped shutdown a unit that used furnace oil as fuel. Additionally, LCPL spent US$ 50 million in the co-generation power project, resulting in the shutdown of diesel generators and one boiler.', 'added', '2007983', '2024-06-10 07:55:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1148, 22045, 1730, '1551380', '2024-06-10 03:13:48', 'Ptasinska, Dorota', 'Brodzicka, Elzbieta', 'Other minor issues - We did not consider Parent''s targets last year. Why are we considering them this year?To also review analysis and only include information that are more relevant to entity if available. ', 'N/A In previous year assessment CDP for Parent company was not available (Q1.5 - "No" and Q5.4 - selected as "no targets"). Scope 1&2 target mentioned only in Q1.2. We don''t know the reason (maybe it''s a mistake or different interpretation).However, in this year CRQ Parent''s targets are deemed relevant for LE since both entities operate in the same sector and targets are quantitative. ', '2007983', '2024-06-10 08:21:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1149, 22045, 1732, '1551380', '2024-06-10 03:15:04', 'Ptasinska, Dorota', 'Brodzicka, Elzbieta', 'Other minor issues - the emission data is for domestic site? Please specify in comment. Also, please mentioned that as per LE''s annual Report, the company reports its processes liquid and gaseous emissions to local authorities. However, there is no further information on emission data and what is being reported. pg 69LCPL report its processes liquid and gaseous emissions to local authorities at SEPA deﬁned frequency. Since commissioning of the plant in 1998, we continue to comply with all regulatory requirements related to the environment. ', 'updated', '2007983', '2024-06-10 08:59:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
