INSERT INTO mstr.advisor_memo_report VALUES (1168, 22972, 1735, '1599218', '2024-06-10 15:04:02', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Accuracy of CRQ - if the Client''s TA is 6C and the sector is 3.70C, why did you say "below sector average"? Please change to "above sector average"', 'Actioned: Manual error, answer choice  now aligned. ', '1668812', '2024-06-13 13:02:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3427, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1169, 22972, 1700, '1599218', '2024-06-06 08:41:59', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Accuracy of CRQ - this is wrong. The figure disclosed is not 69.04 MW but 69,040 MW (you have been misled by the unit of measure). Additionally, this is not the total amount capacity owned but also includes capacity from power station supplying the grid from other operator. Please have a look at question "C-EU8.2d" of CDP and you will find all the stats you need - I have verified these and are also very similar to what is written in the reports.for avoidance of confusion I am adding here what needs to be displayed - let me know if you need further guidance	MW	MWhCoal – hard	 18,924 	 115,242,930 Oil	 6,026 	 7,812,410 Gas	 16,292 	 40,882,920 Sustainable biomass	 1 	 599,330 Geothermal	 579 	 4,138,190 Hydropower	 3,597 	 13,175,000 Solar	 29 	 9,094,300 ', 'Actioned: The error was due to misunderstanding of Indonesian numerical system, where decimal is represented by   a comma  (,) whereas the unit is separated by point (.) correct evidence from CDP has been put into comment.', '1668812', '2024-06-13 13:34:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1170, 22972, 1747, '1599218', '2024-06-11 16:53:35', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'please change to "6. No, but we intend to use carbon pricing in the next two years"', 'Actioned: Answer choice updated and aligned with comments', '1668812', '2024-06-13 13:41:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3515, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1171, 22763, 1753, '1493184', '2024-06-13 15:34:22', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Minor issues:  not clear if project has already achieved gold certification or it has been applied -- Are you referring to a different proeject which CA has linked to.If company is only planning ot submit the application for leed CERTIFICATION, how do we know it is expected to be gold ?', 'The CA has confirmed "the Group has obtained LEED certifications for quite a few of its portfolio projects in the commercial office asset space. For this project as well,". LEED Gold certification has not been added as there is no confirmation if the asset is included, but LEED-Leadership in Energy and Environmental Design has been added as the shared address applies to asset.Thus, this LEED certifications has been obtained by project as well and added.', '2003718', '2024-06-14 06:30:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3419, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1172, 24667, 1758, '1489063', '2024-06-14 12:43:00', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'file:///C:/Users/1489063/Downloads/Sobha%20Limited_AR_2023-03-31_English.pdfAnnual report is available for the group - has this not been used?', 'Agreed - added', '1286637', '2024-06-14 14:23:01', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1173, 24667, 1759, '1489063', '2024-06-14 12:49:19', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Their emissions levels are tiny and this is a furniture manufacturer. This is very small in comparison to global emitters like O&G and energy providers and not going to be a driving factor in global emission level. Would recommend this is changed this to Low given emissions are <18,000 tonnes a year.', 'Agreed- Added', '1286637', '2024-06-14 14:27:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1174, 24667, 1760, '1489063', '2024-06-14 12:50:49', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'I do not understand the logic of the selection - there is no current policy and no intended one that would affect a furniture manufacturer. I would select "no policy in next 10 years" for this selection', 'Ok - noted', '1286637', '2024-06-14 14:31:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1175, 24667, 1761, '1489063', '2024-06-14 12:51:20', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'They do publish emissions values - file:///C:/Users/1489063/Downloads/Sobha%20Limited_AR_2023-03-31_English.pdf Pg76', 'Agreed - added', '1286637', '2024-06-14 14:37:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1176, 22780, 1749, '1493184', '2024-06-13 15:10:13', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Analytical issues: Its not clear what is being mentioend here -- arent we talking about funding the 112 asssets, why are we referring to the overall company then ? answer to be tailored to the transaction', 'Agreed and modified ', '1668331', '2024-06-14 14:43:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1177, 22780, 1750, '1493184', '2024-06-13 15:12:31', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Analytical issues:  If we are funding separate assets, we shoudl be having some form of insurace, have you checked from business/''confirmed from BCA?', 'Obtained Insurance document from PAM and included the same', '1668331', '2024-06-14 14:44:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1178, 22780, 1751, '1493184', '2024-06-13 15:14:14', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Analytical issues: This is incorrect -- please refer tothe user guide on details of value chain which is based on the lifecyle of the asset --- if its owned for investment purposes, it is operations stage of the building  -- pleae coordinate with Tashinga to ensure consistency in responses across CRE CRA''s', 'Agreed and modified', '1668331', '2024-06-14 14:44:33', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1179, 24667, 1762, '1489063', '2024-06-14 12:52:19', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'SOBHA practices energy conservation by installing solar panels for lighting common areas and solar water heaters in all its projects. Some of the highlights in its energy saving measures are:• The SOBHA Glazing and Metal Works factory provided with 225kW and the SOBHA Interior factory provided with 750kW roof top solar power plants as an alternate source of energy.• At the SOBHA Corporate Office, 90 per cent of the power is wheeled from the solar power plant.• Around 2.36 million units of solar power were used across SOBHA’s facilities which resulted in saving the carbon footprint by 2,000 tons.• Use of heat pumps and solar water heaters instead of geysers to reduce power consumption', 'Agreed - added', '1286637', '2024-06-14 14:45:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1180, 22780, 1752, '1493184', '2024-06-13 15:20:02', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Analytical issues:  Not clear how the response pertains to the current transaction. If there are no targets set, how can there be a meaningful impact towards meeting them ? ', 'Agreed and amended', '1668331', '2024-06-14 15:09:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1181, 24726, 1766, '1489063', '2024-06-17 14:41:30', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Can you help explain why this entity would have any additional policy pressure expected on it when it is exclusively operating as an infrastructure / operator of renewable only energy. It is unlikely that any ETS or Carbon scheme will apply to the entity given its zero reliance on fossil fuels. Although construction process will require emissions outputs, most governments would subsidise or grant the ability to produce renewable energy generation assets and not lead to additional costs for the client - hence recommend changing to "No Additional Policy"', 'Climate Analyst comment: As discussed, the current answer choice will be more accurate, hence retaining the same.', '1540001', '2024-06-18 13:40:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1182, 24744, 1771, '1489063', '2024-06-20 08:46:18', 'Leva, Aljaz', 'Tarakji, Ranim', 'Wouldn''t the physical risk, as you rightly say above, be on the supply chain and production of soy beans that they sell on. Therefore I think we would need to either identify the countries / locations where the beans are originated, or chose a global proxy if data is unavailable.Egypt doesn''t seem like the most appropriate physical risk in this case. ', 'updated', '2007983', '2024-06-21 06:33:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1183, 24744, 1772, '1489063', '2024-06-20 08:55:34', 'Leva, Aljaz', 'Tarakji, Ranim', 'Any information in BCA / from CA about where the Soybeans are originated from in more detail / geography split? Apologies - my creditmate isn''t working.', 'There is no BCA for the client available. Financial Statements SoyVen Holding B.V. provided by CA contains only confirmation that "soybeans are originated worldwide". ', '2007983', '2024-06-21 06:37:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1184, 24744, 1773, '1489063', '2024-06-20 08:58:11', 'Leva, Aljaz', 'Tarakji, Ranim', 'I think we would focus more on Scope 1 and 2 emissions as we are looking at the credit risk of the client itself. Therefore looking at what they might be specifically charged for from carbon taxes and fines. It is very unlikely that government and carbon schemes would penalise a client for their Scope 3 emission.Hence would recommend updating to Low', 'updated', '2007983', '2024-06-21 06:47:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1185, 24737, 1775, '1489063', '2024-06-20 14:23:24', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Can tag this as Scope 1 , 2 and 3 emissions targets, give that scope 1 and 2 are negligible. Should benefit client for setting Scope 3 ambitions and seems like they would set 1 & 2 if applicable.', 'Actioned: Answer option changed', '1668812', '2024-06-24 04:56:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1186, 24285, 1779, '1575987', '2024-06-23 18:43:23', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', '"In order to continue to meet customer requirements, Goertek has increased capital investment in energy-saving and emission-reduction projects, such as waste heat recovery, reclaimed water reuse, and construction of high-energy-efficiency power equipment rooms; it purchases green electricity through DPPA and builds self-built distributed photovoltaic power station operations and maintenance. Etc., the annual capital investment is expected to be between 2 million and 5 million yuan." - How this is related to physical risk ?', 'updated', '2001097', '2024-06-24 07:18:40', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1187, 24292, 1782, '1575987', '2024-06-25 04:10:54', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'I think the answer choice is not accurate given most of the supplies is sourced outside of China ', 'As we''ve been told that we should consider all elements no matter how small they are, this is why such answer has been selected', '2001097', '2024-06-25 08:42:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1188, 24724, 1780, '1493184', '2024-06-24 12:21:46', 'Ptasinska, Dorota', 'Tarakji, Ranim', 'Analytical issues: Is it contruction or operations, what is mentioned in comments does not match with the option selected. I thin they are only property developers which construct and then sell -- they dont own properties during operation stage', 'Operation was chosen as the company develops and owns hospitality properties, which include hotels, resorts, spas, and service apartments. Based on the BCA part 2, CRE Loan is to develop the Project “Prestige Golfshire” which is residential project located at Nandi Hills in Bangalore. Answer choice has been updated to Construction.', '2003718', '2024-06-25 09:46:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1189, 24724, 1781, '1493184', '2024-06-24 12:22:50', 'Ptasinska, Dorota', 'Tarakji, Ranim', 'Not sure about this answer, i cannot see any core movement to "Greener Buildings" there is a lot of strive but no real change! and remember for CRE that;s what matters, for 80% solar power i agree but the rest is just aspirations not backed by a roadmap? I do not see one =- What do you think?', 'Feedback has been implemented. The company mitigates greenhouse gas emissions by utilizing solar power for approximately 80% of its electricity needs and incorporating sustainable practices in design, technology, and safety systems.  90%Of Office pipeline - LEED Gold, LEED Platinum and WELL Certified. Q5.61 accordingly amended.', '2003718', '2024-06-25 09:49:19', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1190, 24716, 1776, '1575987', '2024-06-20 14:34:26', 'Mutepfa, Tashinga', 'Brodzicka, Elzbieta', 'Please do munich re assessment for project location . Check if Physical risk RT is applicable based on the munich re assessment ', 'This is a NTB', '1665885', '2024-06-25 10:12:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1191, 23884, 1556, '1575987', '2024-05-10 05:53:18', 'Mutepfa, Tashinga', 'Delaney, Peter Jared', '"Centrica PLC is a Holdco - We are using the information available at the Opco level. Please note - legal entity has been selected as Level of Applicability due to structure of BCA showing that lending occurs to Centrica and not a subsidiary" - Group or Legal entity - Please clearly mention based on above. ', 'done', '1665885', '2024-06-25 17:29:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1192, 24739, 1765, '1489063', '2024-06-17 14:24:52', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Are we confident that these measure will apply to the entity, given it is a trader and isn''t operationally producing high levels of emissions. e.g. It is unlikely to have more than 25kt emissions to hit SG threshold - so can we detailed assess the impact and make sure we aren''t overstating risk.Follow-up - but its a trading company - why would they have additional policy on them for CCUS or H2 exploration. They simply buy the end product and sell, and don''t need to invest the capex themselves, like a producer', 'Amended and removed the unwanted sections as suggested.', '1563645', '2024-06-26 07:45:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1193, 23556, 1786, '1489063', '2024-06-25 15:48:19', 'Gurunathan, Akshay Ram', 'Waclawska, Kamila', 'I am unsure why we are assuming the carbon taxes are not material to Exxon at this time? Can you please explain the logic behind this assumption. I would think they are heavily affected and uncertainty of additional policy pressure to lead to more likely near term impacts.', 'corrected as per your on behalf of the original Maker suggestion. Thank you ', '1632774', '2024-06-26 10:18:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1194, 23846, 1785, '1489063', '2024-06-25 15:41:46', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'I would argue that the performance of the treasury arm is dependent on that of the group operations, as treasury arm has no direct business model themselves. Therefore we should in this case be looking at climate credit risk of parent company, who is an integrated steel producer in Australia.As a result, should change option to "Steel Manufacturing"', 'updated as requested on behalf the original Maker. Discussed also with Checker. Thank you Elliott', '1632774', '2024-06-27 07:43:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3410, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1195, 23835, 1798, '1660361', '2024-06-27 10:27:32', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Please add in the emissions intensity targets - understand the company has combined Scope I and II ', 'Done', '2003718', '2024-06-27 10:41:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1196, 23578, 1802, '1489063', '2024-06-27 16:09:00', 'Mutepfa, Tashinga', 'Ziemlinska, Aleksandra ', 'Do we have an idea of where production occurs? Where are the tobacco leaves sourced from, as this would give a greater indication of risk vs. the revenue generation. Believe the raw produce will be in more tropical counties and hence maybe higher physcial risk.', 'The answer was changed due to above feedback.', '2018956', '2024-06-28 08:05:33', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1197, 23578, 1801, '1489063', '2024-06-27 16:07:35', 'Mutepfa, Tashinga', 'Ziemlinska, Aleksandra ', 'Do you have a comparison of Tobacco manufacturing in comparison to traditional agri food manufacturing in terms of emission, as well as compare to an O&G company.VH seems excessive for a product that doesn''t rely directly on fossil fuels - it can pivot away to renewable means of manufacturing. Additionally main agri emissions come from livestock farming and so think this would be significantly lower.Believe a Medium or High rating is more appropriate.', 'Answer was changed from "Very High" to "High" with justification. ', '2018956', '2024-06-28 08:06:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1199, 24546, 1788, '1660361', '2024-06-26 09:41:00', 'Radhakrishnan, Gowtham ', 'Sunil Dahale, Shreyash', 'Inventory should not be included in the numerator when calculating asset intensive ratio', 'Amended.', '2020154', '2024-06-28 09:07:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1200, 24546, 1789, '1660361', '2024-06-26 09:47:26', 'Radhakrishnan, Gowtham ', 'Sunil Dahale, Shreyash', 'Electricity generation capacity of 33,771 MW -> this statement is not accurate (it is referring to oil fired installed capacity). Please also include the renewable energy installed capacity of 3.5MW from Solar/Wind in the table below (used for own consumption/operations)', 'Table did not allow decimal, so inputted 3 instead of 3.5 MW. Amended the electricity generation capacity of oil-fired and natural gas power plants.', '2020154', '2024-06-28 09:12:59', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1201, 24546, 1790, '1660361', '2024-06-26 10:00:43', 'Radhakrishnan, Gowtham ', 'Sunil Dahale, Shreyash', 'Please also input the emissions intensity that was provided on SR 2023 pg 36', 'Included.', '2020154', '2024-06-28 09:14:35', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3508, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1202, 24546, 1791, '1660361', '2024-06-26 10:06:27', 'Radhakrishnan, Gowtham ', 'Sunil Dahale, Shreyash', 'Please correct the target reduction number here - instead of 0.40 it should be 0.29 (from 0.69 to 0.4)', 'Amended.', '2020154', '2024-06-28 09:16:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1203, 24342, 1808, '1660361', '2024-06-28 06:24:57', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Please exclude inventory from asset intensity calculation - it should include only net fixed assets / revenue.', 'Amended as suggested.', '1563645', '2024-06-28 09:32:42', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1204, 24342, 1809, '1660361', '2024-06-28 06:51:21', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Comments do not correspond with selection - noted that client has assess risks across "entire supply chain", not just own business operations. Please adjust answer selection', 'Answer selection amended as both own operation and supply chain', '1563645', '2024-06-28 09:33:50', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1205, 24342, 1810, '1660361', '2024-06-28 07:45:19', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', '"Component Suppliers" is the rightful choice here since client deals only in the design, building and construction. For "Transmission", with reference to user guide - The Transmission segment refers to company transporting electricity from power generation sources to distribution networks and, ultimately, to end-users. Transmission lines carry high voltage electricity down to transmission substations, which then reduce electricity voltage so that it can be inputted into distribution lines. Most times, transmission and distribution activities are performed by the same companies, hence it is expected that in most times the “Transmission & Distribution” is directly selected. For selection of transmission and/or distribution only, should be supported by strong evidence that the company operates in that segment only. ', 'Answer choice changed to "Component Suppliers" ', '1563645', '2024-06-28 09:34:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3404, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1206, 24342, 1811, '1660361', '2024-06-28 09:25:57', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Answer choice does not correspond to writeup. The company has made investments into a hydropower plant and (pg. 47) Installation of solar panels at manufacturing plant in Bentong, Pahang, 2. Change to energy modern and efficient equipment/heating system, 3. Carbon Accounting for RTB Group.Answer choices 2 and 3 (and 7) would be more appropriate.', 'Answer choices amended as suggested.', '1563645', '2024-06-28 09:48:26', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1207, 24478, 1800, '1489063', '2024-06-27 16:03:40', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Do we have a sense of where the company sources its tradeable products from? If there are mainly sourced from China then we should pick that instead of SG, despite it being situated there.', 'Agree, their entire sourcing is from the Parent company which is in China and hence amended accordingly', '1668331', '2024-06-28 09:54:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1208, 24730, 1796, '2009422', '2024-06-26 12:39:02', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Accuracy of CRQ: More evidence please on choosing 2 year policy answer to ensure adequate and effective policy evidence. As discussed please provide more rationale about EU ETS 2, its relevance and its interface with light manufacturing industry. Nevertheless please provide comments on CBAM.', 'Added rationale for 2-5 yrs answer choice selection and more comments on CBAM.', '1600990', '2024-06-28 15:55:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1209, 24730, 1795, '2009422', '2024-06-26 12:10:23', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Accuracy of CRQ: It''s clear that most of energy consumption is coming from Scope 3...however more clarification and evidence on relying on coal needs to be provided? Or preferably on renewable energy?', 'Updated a comment to show why answer choice "high" is relevant.', '1600990', '2024-06-28 15:56:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1210, 24730, 1797, '2009422', '2024-06-27 07:57:48', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Accuracy of CRQ: please mention here also the figures from sustainability report fact book e.g pg 9 and 65 respectively.https://www.lg.com/content/dam/lge/global/sustainability/pdf/2022-2023_LGE_SR_FACT_BOOK(EN).pdfPlease refer to Parent''s report and provide an breakdown analysis on entity level.Please reflect your analysis for both questions 5.4 and 5.5.Ok, if there''s no info about LE in the parent''s SR.', 'We have used CDP values in Q5.4 as the emissions reported in CDP Report is more apt for the business segment that client is into. The Sustainability Report Factbook includes the LG Group and its subsidiaries overall GHG emission.As discussed with QA no changes required in Q5.5', '1600990', '2024-06-28 16:13:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1211, 23963, 1804, '1575987', '2024-06-28 06:02:32', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Please see if we can elaborate on impact assessment . ', 'Added one example on how these assessments are carried out.', '1286637', '2024-06-29 11:30:58', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1212, 23963, 1806, '1575987', '2024-06-28 06:13:35', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Please check the reliance to high carbon products should be low  ', 'They operate a manufacturing plant in Rudrapur, which specializes in the production of Personal Computers, Laptops, and Servers, leading to the selection of the "High" option. Please check and let us know if you have any other view.', '1286637', '2024-06-29 11:37:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1213, 23963, 1807, '1575987', '2024-06-28 06:15:14', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Is the carbon tax applicable  or proposed on the Industry in which client operates ? Please note majority of emissions of the company are in form of scope -3 emissions ', 'Agreed - Carbon Tax is not applicable hence changed the answer choice to 5-10 years.', '1286637', '2024-06-29 11:39:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1214, 24041, 1812, '1660361', '2024-06-28 10:21:51', 'Radhakrishnan, Gowtham ', 'Pai, Vallabhi Vishwas', 'For 2023, the Scope 2 emissions (market and location) are filled in incorrectly - to be swapped.', 'Agreed. The values are updated correctly. ', '2019328', '2024-07-01 06:05:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1215, 24126, 1787, '1551380', '2024-06-26 01:12:54', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'Analytical aspectsLow <=20% was selected in previous CRA. Please justify the change in answer in this assessment. ', 'Justification provided', '1668331', '2024-07-02 06:38:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1216, 24126, 1815, '1551380', '2024-06-30 15:18:28', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'This is for BRAG Analysis in Outcome tab. I think we should add the COMMENTARY YEAR 2023 in Engie''s 2024 Integrated Report in the Analysis as it shows that the company is looking at reviewing and adjusting its 2025 and 2030 targets."2023 was an unusual year, given the low load factors seen in France and across Europe more generally. The actual emissions from electricity production and gas sales were well below our forecasts. An in-depth study will be carried out in 2024 to determine the role of cyclical factorsin these developments and, conversely, the role of more structural and therefore recurring changes. Potential adjustments to the 2025 and 2030 targets will be reviewed as part of the next update of the Group’s climate strategy, to be presented at the 2025 Shareholders’ Meeting."', 'Added in the BRAG analysis', '1668331', '2024-07-02 06:38:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1217, 24126, 1813, '1551380', '2024-06-30 15:01:33', 'Gurunathan, Akshay Ram', 'Radhakrishnan, Gowtham ', 'As per BCA Part 2, Engie entities in Singapore represent the energy services business line in the Asia Pacific region. The Engie entities offer suites of business solutions “as a service” in energy efficiency and sustainability for clients in commercial buildings, industries, and cities. I believe the Engie entities in Singapore is under the Energy Solution segment so we should be looking at the strategy for the segment. If you refer to page 29 of 2024 Integrated Report, it gives the strategy of the segment which says "the Group helps its customers to reduce their costs and energy consumption, as well as their CO2 emissions. It uses long-term contracts and has a panel of diversified and complementary offerings.It helps to accelerate the energy transition of its customers, and prioritizes the development of decentralized energy networks (urban heating and cooling networks, building of utilities on thecustomer’s site, decentralized solar ', 'Added', '1668331', '2024-07-02 06:45:28', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
