INSERT INTO mstr.advisor_memo_report VALUES (1219, 24151, 1819, '1489063', '2024-07-02 15:08:56', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'In AF-KLM Document:- advancing towards our goal of Net Zero emissions by 2050 -GHG emissions intensity in metric  tons of CO2  equivalents per revenue ton-kilometer (gCO2eq/RTK)(2) : 30% reduction compared to 2019 ', 'Feedback Incorporated ', '2008896', '2024-07-03 11:09:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
