INSERT INTO mstr.advisor_memo_report VALUES (1226, 24453, 1830, '1575987', '2024-07-04 05:10:51', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'In US - you have to point out state in which plant is located - Most of the US states have only policy measures applicable on power plants - Please elaborate on how carbon pricing on power plants will impact the company What is the break up of revenue as per geography ?  ', 'Agreed - Power plant located in Milpitas CA California currently this state is not under RGGI regulations, Trust this clarifies. Revenue break up added in Q2.13. Unable to add any further details in Q4.2 due to space constraint.', '1286637', '2024-07-04 07:14:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
