INSERT INTO mstr.advisor_memo_report VALUES (1230, 24724, 1839, '1493405', '2024-07-05 06:47:29', 'Ptasinska, Dorota', 'Tarakji, Ranim', 'Are we able to analyse the increase in emissions and can we cover that in the BRAG Summary?', 'Feedback has been implemented. Scope 1 & 2 GHGs in 2022-2023 have been manually added and increased. Analyses added to Q5.4 and to BRAG.', '2003718', '2024-07-05 08:30:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3506, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1231, 24724, 1840, '1493405', '2024-07-05 06:48:44', 'Ptasinska, Dorota', 'Tarakji, Ranim', 'I would change this answer to No - Hard to establish for all the points mentioned above if we can see capital allocated?Since emissions are still increasing, its hard to know what investment has been made. It seems to be subjective, hence woudl be better to mention No till we see the results quantitatively', 'Company''s ongoing efforts involve integrating energy consciousness and the latest technologies into our operations and projects to create remarkable and sustainable designs. We achieve this by using effective designs, appropriate materials, and energy efficient equipment, significantly reducing overall energy consumption and CO2 emissions. In 2023, 53 Mwh Solar Rooftop Capacity and 140 tCO2e carbon emissions Reduced. All considered, it is hard to establish the capital allocated, but the company does investment R&D towards the change. Updated to No', '2003718', '2024-07-05 10:29:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1232, 24724, 1838, '1493405', '2024-07-05 06:44:32', 'Ptasinska, Dorota', 'Tarakji, Ranim', 'Incorrect Option - Given this is a Corporate Loan, should this answer be yes or no?Althugh the information provided below is useful and can be included in the comments box -- choose the option as No, as that is ony when the financing is directly for the asset/buildings. ', 'Yes, because they have certification for the asset that the facility is for and they are also certifying 90% Of Office pipeline - LEED Gold, LEED Platinum and WELL Certified, and the Level of Applicability is at legal entity so it is relevant  to the client over all business and the asset which are financing. Updated to No ', '2003718', '2024-07-05 10:33:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3419, 'GTR3', 'esg_navigiator', '01');
