INSERT INTO mstr.advisor_memo_report VALUES (1237, 24490, 1837, '1575987', '2024-07-04 12:01:31', 'Davies, Krista', 'Roy, Devika Rose', 'There are several reasons for the decrease inabsolute emissions, including:• Emissions decreased due to lower sold capacity (MW) in central and distributed power generation• Lifetime for power generation was adjusted (27 years in fiscal year 2023vs. 28 years in fiscal year 2022)• Operating hours for specific gas turbine frames used in central powergeneration decreased due to increasing penetration of renewableenergy sourceNot clear how it is linked the question asked.  Please review entire comment ', 'Okay', '2001769', '2024-07-08 08:15:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1238, 24632, 1843, '1575987', '2024-07-08 07:16:11', 'Masarin, Lisa', 'Baran, Ewa', 'Please check if future home standards are applicable on commercial real estate - i.e. hotels ?What is the Energy efficiency rating of the hotels ?', 'updated with appropriate comment: excluding hotels.energy efficiency - portfolio of 17 assets in regional cities across the UK - the energy efficiency rating was not shared', '1663704', '2024-07-08 11:56:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1239, 23836, 1841, '1599218', '2024-07-05 15:16:56', 'Ptasinska, Dorota', 'Ziemlinska, Aleksandra ', 'target #1-2 are fine, well donetarget #3 - in the description, add this is for FLAGtarget #4 - are you sure about it? it is the same target as #3 but without scope 1 - cannot find any reference of it in the sustainability report. I WOULD DELETEtarget #5 - there are several issues with this: (i) it is on intensity basis (not absolute), and (ii) as per CDP narrative the target does no longer hold given they have set target #1. I WOULD DELETEtarget #6 - make Scope 1&2&3target #7 is fine - in the description add this is for FLAGby doing this we will have 5 targets - 4 refers to those at page 6 of Sust Report, and 1 is for a general NZ target', 'I updated accordingly.', '2018956', '2024-07-08 13:08:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1240, 24008, 1848, '1493184', '2024-07-08 13:14:31', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Please reword the answer -- 1. Dont copy paste the entire para -- just write whats relevant2. The last sentence is not clear.Due to the conservative approach and the updated policy.Policy measures are updated., and they are in place and expected to continue, while In the last year''s CRA they were expected in the next 2-5 years.Sample answer:Briefly explain the choice of answer, change from last time and why:Policy measures are updated to represent that they are currently in place as the building code applies to all buildings or building complexes that have a connected load of 100 kW or greater or a contract demand of 120 kVA or greater and are intended to be used for commercial purposes.', 'Feedback has been implemented1- Relevant supporting comment is included.2- Comparison between this year and last year is provided. ', '2003718', '2024-07-08 14:24:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1241, 24008, 1849, '1493184', '2024-07-08 13:56:49', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Minor issues: Answer to be asset specific not company spceific --- change for Q5.4.5.5', 'Feedback has been implemented for the specific asset ', '2003718', '2024-07-08 14:28:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1242, 23813, 1845, '1551380', '2024-07-08 08:31:29', 'Mutepfa, Tashinga', 'Ziemlinska, Aleksandra ', 'ESRA makes reference to website -  https://stories.flipkart.com/sustainability/https://stories.flipkart.com/flipkart-renewable-energy-commitment-100/https://stories.flipkart.com/downloads/sustainability/Did we check if these will be more relevant/appropriate?', 'Sourced added to the 1.1 and used in Section 5', '2018956', '2024-07-09 06:40:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1243, 23836, 1842, '1599218', '2024-07-05 15:18:02', 'Ptasinska, Dorota', 'Ziemlinska, Aleksandra ', 'Accuracy - please use the latest information available in the report (page 3) https://www.sdguthrie.com/wp-content/uploads/2024/06/Performance-Data-FY2023_7June2024.pdfplease be careful the way you add the data. target #1-2 are for Scope 1&2 Energy and industrial processes - use the emissions for this category onlyfor the targets for FLAG, use the FLAG emissions only', 'updated', '2018956', '2024-07-09 07:26:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1244, 24008, 1846, '1493184', '2024-07-08 13:10:09', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Analytical issues:  This doesn''t count as acknowledgement --- you can mention thi sentence but clarify that there is no explicit acknowledgement of physical risks', 'Answer has been updated to "No"', '2003718', '2024-07-09 08:01:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1245, 24008, 1847, '1493184', '2024-07-08 13:11:33', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Analytical issues:  Have you checked the BC-- its unlikely we have a project finance with no insurance ', 'No information available about physical risk insurance', '2003718', '2024-07-09 08:02:17', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1246, 23680, 1852, '1489063', '2024-07-08 14:02:41', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'Can you lay out what types of materials the client trades and what allocation of their business is associated with them. My guess is these are construction focused materials - e.g. Cement.  Can you then also rank the materials in terms of allocation and associated carbon emissions, so we can understand why this is very high. Without the details, i would argue that this is just a trader and not a manufacturer or user of the products, hence direct emissions and not attributable to them. Additionally, they have option to pivot to green-sourced materials and so believe their reliance should be "high" or "medium" as opposed to very high, where little business model change is available.', 'The comment was addressed in the response to the question. However, due to the lack of disclosures at LE level, a conservative approach was taken, and the selected answer was changed from "very high" to "high".', '1642635', '2024-07-09 09:55:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1247, 23680, 1853, '1489063', '2024-07-08 14:03:12', 'Ptasinska, Dorota', 'Waclawska, Kamila', 'Do these regulations apply to traders of the materials or just the CRE company itself?Follow-up: Do we think that the indirect impact is material though? This does not seem like a high materiality case because it is very speculative that the impact will directly flow through. It is using assumptions that produces will pass-on the costs and demand will change. Whilst possible, these are theories and not concrete material impact. I would change this to "No Additional Policy Pressure" until actual regulations will directly impact the client.', 'The regulations concern the CRE companies, but the LE - as a trader of construction materials - can be indirectly impacted by the transition to building "green buildings" and the ETS expansion into the building materials industry. The answer stayed the same, but we added an explanation for that.Follow up q- answer updated  to: Although the above regulations concern the CRE companies, this does not seem like a high materiality risk for the LE which is a trader of construction materials. We don''t want to be very speculative that the impact will directly flow through hence the answer choice "no policies expected in the next 10 years', '1642635', '2024-07-09 09:59:10', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
