INSERT INTO mstr.advisor_memo_report VALUES (1270, 23729, 1868, '1551380', '2024-07-11 08:48:54', 'Masarin, Lisa', 'Waclawska, Kamila', 'Analytical aspects - "Construction" will be more appropriate here. The company manufactures elevators and does not operate or manage the building. The building itself is more that just the elevators so we cannot choose "Operations". It is also good to have a view on whether the company is a key emitter within the value chain before selecting the option. "Operations" is the activity generating the most emission for CRE. Would you say elevator manufacturing is the activity generating the most emission for CRE? If not, then you should not consider any ''red'' option at all. ', 'updated as requested', '1632774', '2024-07-19 06:34:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1271, 23729, 1869, '1551380', '2024-07-11 09:42:50', 'Masarin, Lisa', 'Waclawska, Kamila', 'Analytical aspects - the table here is for information on the underlying building/asset that is being financed. The certification here is for the factory that is used to manufacture the elevators and for the office building used by the company. The information is not relevant here. Please leave the table blank and mention that company is a manufacturer of elevators and question is not relevant as there is no underlying building/asset that is being financed. ', 'updated as requested. Thank you ', '1632774', '2024-07-19 06:37:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3419, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1272, 24436, 1898, '1660361', '2024-07-19 09:13:26', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Do note that we need direct evidence to substantiate the answer choice. The initiatives listed on the Group website are too high level, therefore this answer option should not be selected "Yes - Planned change in production operations: Lower emission fuel types (e.g. Greening of energy mix)".', 'Climate analyst comment: The option removed.', '1540001', '2024-07-19 10:20:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1273, 24436, 1899, '1660361', '2024-07-19 09:19:54', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'This answer choice should be selected instead - "No - They will have an impact, but it will not help significantly towards meeting targets, effecting only a small number of core operations". The initiatives implemented, substantiated by only 179kg/flight saved in carbon emissions, have minimal impact on overall emissions generated through core flight operations. An example of an initiative that would significantly reduce emissions would be to substitute conventional jet fuel with aviation biofuel.', 'Climate Analyst comment: Amended. ', '1540001', '2024-07-19 10:21:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1274, 24436, 1897, '1660361', '2024-07-19 08:58:02', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Writeup does not correspond to comments - own assets should be selected instead of supply chain.', 'Climate Analyst comment: Updated', '1540001', '2024-07-19 10:41:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1307, 23729, 1934, '1551380', '2024-07-22 01:31:32', 'Masarin, Lisa', 'Waclawska, Kamila', 'CRA summary analysis - BRAG has changed from Amber to Green given change in answer option. Please update analysis.', 'updated', '1632774', '2024-07-22 06:35:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1308, 24748, 1937, '1551380', '2024-07-22 05:31:09', 'Masarin, Lisa', 'Kumar, Ajith', 'Please use information in Group Mandate instead. As per GM - Exposure to cyclical industries, particularly automotive - "Freudenberg''s largest end customer industry remains the automotive sector, where it specializes in sealing, filtration and vibration control technologies. The reliance on the automotive sector to approximately 39% as at year end 2022. Freudenberg remains however relatively diversified across non-auto segments and the group maintains a strategy to diversify away from auto segment, whilst continuing to invest in innovative/higher growth products in the auto segment."- Raw materials: "A large portion of the cost base is linked to raw materials (e.g. oil, steel and natural rubber)"', 'Agreed - Added', '1286637', '2024-07-22 06:59:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1309, 24748, 1938, '1551380', '2024-07-22 05:38:10', 'Masarin, Lisa', 'Kumar, Ajith', 'CRA summary analysis - I am not quite sure what the sentence "The GTR is positively influenced by the company''s strong performance in Product Development (PD), which is supported by industry averages and our belief that the company is currently affected by more climate policies" means. Could you please rephrase?', 'agreed - amended', '1286637', '2024-07-22 07:08:04', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1310, 24787, 1896, '1551380', '2024-07-19 07:05:34', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'LOA - Why do we not consider the Siemens Limited''s report?https://assets.new.siemens.com/siemens/assets/api/uuid:83be7e9a-3c89-4c2d-91fa-d0f698571cf5/Siemens-AR-2023-2.pdfGiven that SEIL will be demerge from Siemens Limited and will be listed, we can also put this in the comment so the next time the case is being work on, it reminds the maker to review the LoA.There are also some key information on the demerger. https://assets.new.siemens.com/siemens/assets/api/uuid:ee6bca2c-a4ff-4f6b-86a9-c4b47e3eacd8/Siemens-Limited-Analyst-Call-Presentation-Q2-FY24.pdf', 'Updated accordingly.', '1563645', '2024-07-22 08:13:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1311, 24787, 1935, '1551380', '2024-07-22 02:21:11', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Other minor issues - I know this is a NTB BCA and we are not required to capture the locations. However, it has been mentioned in BCA Part 2 that Energy business related plants are located in Salcete, Goa and Vadodara, Gujarat. So instead of saying " it is not possible to assign any particular plant/office to Energy business i.e. that information is not available, and given Siemens Limited is a listed company, it does not share any data to anyone apart from information already in public domain", please include that sentence "it has been mentioned in BCA Part 2 that Energy business related plants are located in Salcete, Goa and Vadodara, Gujarat". https://www.siemens.com/in/en/company/about/business-locations.html#PlantLocationsSalceteEnergy AutomationL-6, Verna Industrial Estate,Verna, SalceteGoa -403722ManejaEnergy Oil & GasR. S. No. 144,Opp. Makarpura Railway Station,Maneja,Vadodara - 390013', 'Updated accordingly.', '1563645', '2024-07-22 08:14:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1312, 24790, 1943, '1575987', '2024-07-22 09:48:01', 'Masarin, Lisa', 'Tarakji, Ranim', 'If Inland ships or Coastal ships - China sovereign Heat map is to be used ', 'As the company is holding 30+ ships with capacity of 40,000 tons. As this is total tonnage, they are considered as Inland ships and China sovereign Heat map is used', '2003718', '2024-07-24 07:01:29', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1313, 24790, 1944, '1575987', '2024-07-22 11:52:45', 'Masarin, Lisa', 'Tarakji, Ranim', 'Can we check what is the revenue percentage from trading and transportation ?', 'LE is contributing circa 20% of SPSI’s total revenue (SPSI is the Group). The shared revenues in BCA part 2 are for the Group. As this section is done at Legal Entity level, Group''s information has not been added. Business Team didn''t shared any information about LE''s revenues.', '2003718', '2024-07-24 07:17:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1314, 24790, 1945, '1575987', '2024-07-22 11:55:40', 'Masarin, Lisa', 'Tarakji, Ranim', 'Could we please check if the IMO regulations on GHG emissions would be applicable on Inland vessels ?', 'IMO 2023 covers ships of 5,000 gross tonnage and above. As LE''s ships are combined tonnage is 40,000 and they are all inland vessels. IMO doesn''t apply on LE''s vessels. ', '2003718', '2024-07-24 08:00:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1315, 24686, 1953, '1575987', '2024-07-26 05:37:33', 'Scariah, Renjith ', 'Kumar, Ajith', 'Please add results of Munich Re assessment. ', 'Munich RE results were already added in Q2.12 and Q2.1.1 says only Operating locations are representative or not. Please let me know if you have different opinion , thanks', '1286637', '2024-07-26 08:51:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1316, 24686, 1955, '1575987', '2024-07-26 07:03:34', 'Scariah, Renjith ', 'Kumar, Ajith', 'How efficiency of equipment and supply chain related answer choices are justified ?', 'Agreed - added below details"Reduce Scope 1 & 2 GHG emissions by increasing energy efficiency and through the adoption of new technology"', '1286637', '2024-07-26 08:55:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1317, 24686, 1957, '1575987', '2024-07-26 07:14:14', 'Scariah, Renjith ', 'Kumar, Ajith', 'Pls add comments related to LE ', 'Agreed - LE level details are not available - Answer choice was also changed.', '1286637', '2024-07-26 08:56:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1318, 24686, 1954, '1575987', '2024-07-26 05:55:21', 'Scariah, Renjith ', 'Kumar, Ajith', 'How terminal and storage facility will have Scope 1 & 2 emissions ? Can we discuss this ?', 'agreed - removed this answer choice', '1286637', '2024-07-26 09:08:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1319, 24686, 1956, '1575987', '2024-07-26 07:13:41', 'Scariah, Renjith ', 'Kumar, Ajith', 'Please rethink what a Terminal and Storage facility could do to reduce emissions (Scope 1 & 2) - Change source of Energy - Covered by Solar panels , reducing energy consumption For scope 3 - Type of product sold. ', 'agreed - added below answer choiceDuring the year under review, our rooftop solar installations across our facilities realised more than 361 tCO2e of emissions avoidance (FY2022: 224 tCO2e)', '1286637', '2024-07-26 09:09:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1320, 24810, 1946, '1599218', '2024-07-24 16:37:14', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Accuracy of CRQ - why did you say Generation is 5,000,000 MWh? in 2022 it is 3,938,339.3 MWh', 'Climate Analyst comment: Amended ', '1540001', '2024-07-26 09:37:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1321, 24810, 1947, '1599218', '2024-07-24 16:48:37', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'can you please see if you refresh this, whether MunichRE scores will appear? THANKS A LOT!', 'Climate Analyst comment: Scores refreshed and details updated. ', '1540001', '2024-07-26 09:48:43', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1322, 24562, 1959, '1191828', '2024-07-29 09:40:55', 'Pal, Aditya', 'Roy, Devika Rose', 'Given the broad geographic spread of Banpu''s operations, please include a couple of bullet points on policy measures expected in some of Banpu''s other key operating locations (e.g. - Australia, Indonesia, US, Thailand etc). You can use revenue contribution as a proxy to identify the Top 3-4 operating locations. ', 'ok', '2001769', '2024-07-29 13:11:56', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1323, 24562, 1960, '1191828', '2024-07-29 09:46:33', 'Pal, Aditya', 'Roy, Devika Rose', 'Company''s 2025 reduction targets are based on a future ''BAU'' forecast rather than a reduction from 2019 actuals. For e.g., its 2025 emissions intensity target for the mining business is actually higher than 2019 and 2023 actuals (refer graph on page 57 of company sustainability report). Given this, the company''s targets cannot be considered as credible. Emissions intensity target for Power business may be included as they atleast still show a reduction from 2019 actuals. ', 'Hi, incorporated your comment on not considering the mining target credible.We have not included the power business target as we do not include targets that have been achieved in the table below. This approach was double checked with other Analysts', '2001769', '2024-07-29 15:10:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1324, 24562, 1949, '1599218', '2024-07-25 08:25:59', 'Pal, Aditya', 'Roy, Devika Rose', 'Please include commentary on company''s ''Greener and Smarter'' strategy where the company aims to increase the portfolio of cleaner energy and energy technology businesses to 50% by 2025. ', 'ok', '2001769', '2024-07-29 15:21:06', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1325, 24562, 1951, '1599218', '2024-07-25 08:28:24', 'Pal, Aditya', 'Roy, Devika Rose', 'General comment for the whole section: please, just summarize your comments without copy/paste - it is just so hard to read through - if you want to really use the client''s narrative, at least adjust the text to adapt it to the commentary box', 'I''ve added commentary but changed alignment to make the text easier to read', '2001769', '2024-07-29 15:44:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1326, 24562, 1958, '1191828', '2024-07-29 09:38:58', 'Pal, Aditya', 'Roy, Devika Rose', 'Update comment to say that “14.71% of the company’s key assets are prone to flood risk events”. The assets prone to flood risk include some mining properties and not just wind farms and floating solar facilities.', 'Comment has been updated. ', '2001769', '2024-07-29 15:50:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3203, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1327, 24822, 1961, '1660361', '2024-07-30 03:42:35', 'Leva, Aljaz', 'Kumar, Ajith', 'May I know why are we redoing the CRA for this client? Noted last approval in June and client is rated Green.', 'This was the Ad-hoc case - requested by client hence initiated Ad-hoc query, Trust this clarifies.', '1286637', '2024-07-30 07:06:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1328, 24822, 1962, '1660361', '2024-07-30 03:45:15', 'Leva, Aljaz', 'Kumar, Ajith', 'Please specify how were these locations selected - no indication from the company website that there are plants (website only shows LPG distributors and gas pipeline operators). ', 'These locations are available in the BCA part 2 and CA also provided the same locations while Ad-hoc request. Trust this clarifies.', '1286637', '2024-07-30 07:07:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1329, 24217, 1964, '1660361', '2024-07-30 05:35:30', 'Davies, Krista', 'Delaney, Peter Jared', 'Incorrect answer selected - While I understand the linkage you have mentioned, from the way it is being written here, the measure is again targeting vessel efficiency, not specifically to lower probability or impact of asset damage or business disruption. Therefore, "no measures" would be more appropriate here.', 'Updated - but generally across shipping cases we would accept this', '1665885', '2024-07-30 08:23:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1330, 24217, 1963, '1660361', '2024-07-30 05:23:06', 'Davies, Krista', 'Delaney, Peter Jared', 'Incorrect answer selected - the impact of weather conditions as mentioned here is specifically for the purpose of simulating vessel efficiency which in turn affects its carbon footprint (transition risk related). Physical risk refers to the impact to assets through damages or disruption. Therefore, answer should be "does not acknowledge".', 'Updated', '1665885', '2024-07-30 08:24:19', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1331, 24899, 1966, '1575987', '2024-07-31 05:36:57', 'Pal, Aditya', 'Delaney, Peter Jared', 'Please confirm the type and tenure of charter', 'Please see confirmation in email chain with RM', '1665885', '2024-07-31 08:18:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1332, 24899, 1967, '1575987', '2024-07-31 06:11:52', 'Pal, Aditya', 'Delaney, Peter Jared', 'S&P liquidity is generally limited. ?', '?? - this is from the clarksons report', '1665885', '2024-07-31 08:18:55', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1333, 24899, 1968, '1575987', '2024-07-31 07:53:45', 'Pal, Aditya', 'Delaney, Peter Jared', '"The vessel insurances to be maintained and follow SF CUP unless CUP breach approval is obtained: H&M, War, P&I, MII. " - Whether breach approval is taken ? What is the plan?', 'Please see confirmation from RM', '1665885', '2024-07-31 09:14:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1334, 23598, 1969, '1660361', '2024-07-31 08:32:54', 'Pal, Aditya', 'Roy, Devika Rose', 'Missing input - please also fill in the emissions intensity found also on pg 97 of the annual report.Follow-up comment - noted and agreed', 'As only total emission intensity is available, Ive added it in the comment box above', '2001769', '2024-07-31 10:03:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3508, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1336, 23598, 1971, '1660361', '2024-07-31 08:45:55', 'Pal, Aditya', 'Roy, Devika Rose', 'Incorrect answer choice - Investments have been made by the company to make the enhancements as written, even though these may not be materially affect the emissions produced or emissions intensity.Follow-up comment - understood your rationale. However, while the client did not declare the amounts spend, it has listed tangible actions taken which indicate investment made. Moreover, the client has already been penalised on Q5.6.1. Therefore, if we select "yes" in Q5.6.2, the message would be "the client has made investments, but these do not have a material impact (non-core changes only)". I believe this is a more appropriate message as opposed to saying the client has not done anything at all. ', '-Thank you for the feedback. However, as you have pointed out, these measures will not cause significant emission reduction. We believe selecting any other option would be rewarding the client when there is no other evidence on capital investment or R&D available.-Response amended as per Advisor feeedback', '2001769', '2024-07-31 10:19:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1337, 23657, 1972, '1660361', '2024-07-31 09:12:22', 'Pal, Aditya', 'Gowri, V Kavya', 'Please input the emission intensity figures into the table instead of just putting in the comments - since it is combined scope 1 and 2 emission intensity values, suggest you input under scope 2, since scope 2 emissions are much more significant for the company. Also, please reflect within the comments that the emissions intensity is combined (scope 1 and 2) - already done so no change.Page 44:Scope 1 and 2 emission intensity values (CO2e kg/sqft)Baseline year (2019) - 0.74422021 - 0.71232022 - 0.94322023 - 0.4948', 'Actioned - Provided the emission intensity values in table similar to the comments.', '2006519', '2024-08-01 05:46:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1338, 24831, 1978, '1551380', '2024-08-05 05:47:22', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Other minor issues - Please mention that ESG report has mentioned the company actively responds to the national "double carbon" but no quantitative targets can be found. ', 'Updated accordingly.', '1563645', '2024-08-05 07:18:10', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1339, 24831, 1976, '1551380', '2024-08-05 03:37:18', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Instead of saying "As company''s most asset locations are located in China", please change to "As company''s key manufacturing sites are located in China".', 'Updated accordingly.', '1563645', '2024-08-05 07:18:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1340, 24831, 1975, '1551380', '2024-08-05 03:33:17', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Why do we list the Q12023 report when we have Q12024 report? https://www.lomonbillions.global/financial-information/', 'Updated accordingly.', '1563645', '2024-08-05 07:18:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1341, 24653, 1977, '1575987', '2024-08-05 05:43:23', 'Pal, Aditya', 'Pai, Vallabhi Vishwas', 'Delta calculation from Estimated attained EEXI is not correct. It should be linked with Poseidon trajectory AER  . Check whether any EST is installed on the vessel. The Mentioned measures except ECO engines & NO2 catalytic converter are not efficiency measure.', 'Comments are corrected as per feedback. Any EST are not installed in the vessel. Hence, not considered in the CRQ and assessment.', '2019328', '2024-08-05 09:07:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1342, 24045, 1986, '1551380', '2024-08-06 03:30:15', 'Pal, Aditya', 'Gowri, V Kavya', 'Other minor issues - is the unit specified anywhere? If not, do we need to put the full number (i.e. 1890000 instead of 1.89)? ', 'The unit is specified in comments in Q5.4', '2006519', '2024-08-06 06:49:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1343, 24045, 1985, '1551380', '2024-08-06 03:17:21', 'Pal, Aditya', 'Gowri, V Kavya', 'Other minor issues - wordings found in annual report would be more straightforward and relevant.Annual Report 2023 page 62"We promote the responsible use of natural resources, both complying with international and national legislation as well as respecting biodiversity. Our principles on biodiversity are set forth in a corporate policy and a separate position paper on this issue. In this, we express our commitment to the objectives of the United Nations Convention on Biological Diversity, which includes the fair and equitable sharing of the benefits arising from the use of genetic resources. We also have a supplementary corporate policy in placethat is designed to ensure compliance with international and national legislation on access to genetic resources and the fair and equitable sharing of the benefits arising from the use of genetic resources. Through monetary and nonmonetary contributions to the establishment of new gene banks that', 'Actioned.', '2006519', '2024-08-06 06:49:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3104, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1344, 24045, 1987, '1551380', '2024-08-06 04:04:50', 'Pal, Aditya', 'Gowri, V Kavya', 'Refer to page 134, the scope 3 emissions that were used for target calculation is "indirect emissions from our upstream and downstream value chain to attain the SBT", not the full amount. So all baseline level needs to be updated. Instead of 13.75 for target 1, it should be 12.58 (3.76+8.82) and instead of 9.99 for target 3 and 5, it should be 8.82. Target level and current level need to be changed as well. If unclear, please reach out to Shuk Fan. Progress is different from actual reduction so the statements in comments need to be rephrased. To review outcome tab as well where progress has been mentioned. For example, the statements "With regards to this RT, Bayer AG''s scope 1, 2 and 3 emissions have reduced by 12.69% and moving towards their net zero target. With regards to Interim target, the company''s scope 1, 2 and 3 emissions have reduced by >50% and moving towards achieving their target. With regards to medium-term target, the co', 'Actioned', '2006519', '2024-08-06 07:13:29', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1345, 23584, 1979, '1551380', '2024-08-05 05:57:03', 'Radhakrishnan, Gowtham ', 'Pai, Vallabhi Vishwas', 'Analytical aspects - Referring to page 2 and 3 of BCA, Company (LPB) is the intermediate holding Co. of all major functions and also the internal trading arm. Assessment should include key operating companies (trading and manufacturing). Please also reflect this in the LoA commentary. Other minor issues - Source year should be 2023.', 'Changes updated as per feedback. ', '2019328', '2024-08-06 14:44:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1346, 24700, 1993, '1551380', '2024-08-07 05:00:25', 'Pal, Aditya', 'Gowri, V Kavya', 'Other minor issues - Please add in statement below from report which relates to Singapore. Pg 52 - Our sites in Gibbons and Maitland (Canada) and Singapore are subject to the relevant national CO2 taxes. Overall, about 78 percent of GHG emissions were subject to carbon pricing systems in 2023.', 'Actioned.', '2006519', '2024-08-07 07:06:01', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1347, 24700, 1996, '1551380', '2024-08-07 06:26:05', 'Pal, Aditya', 'Gowri, V Kavya', 'Target 5 - Please review unit. Should it be intensity instead of absolute emission? Should it be Metric tons CO2e per megawatt hour (MWh)?Target 4 - Carbon Neutral commitment covers Scope 3? Referring to page 49, company specified that it is for Scope 1 & 2. ', 'Target 5 - Typo errorTarget 4 - Amended', '2006519', '2024-08-07 07:06:56', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1348, 24700, 1994, '1551380', '2024-08-07 05:02:21', 'Pal, Aditya', 'Gowri, V Kavya', 'Please add below statement as well which relates to Singapore. Pg 49 - we are investing in the construction of a new facility in Singapore for carbon-neutral production of alkoxides.', 'Actioned', '2006519', '2024-08-07 07:24:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1349, 23584, 1980, '1551380', '2024-08-05 07:48:35', 'Radhakrishnan, Gowtham ', 'Pai, Vallabhi Vishwas', 'Analytical aspects - Company is the intermediate holding Co. of all major functions and Internal trading arm. Assessment should include key operating companies (trading and manufacturing). Please review the statement "entity operates in procurement and intermediate trade of paper products which are not currently under the ambit of China’s carbon policy".', 'Changes updated as per feedback. ', '2019328', '2024-08-07 07:48:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1350, 23584, 1982, '1551380', '2024-08-05 07:54:08', 'Radhakrishnan, Gowtham ', 'Pai, Vallabhi Vishwas', 'https://www.leo.com.hk/contact.htmlPlease capture all relevant addresses of subsidiaries (see BCA page 3 for shareholding chart).Leo Paper Products Ltd.Leo Paper Bags Manufacturing (1982) Ltd.Leo Design & Packaging Solution Ltd.Heshan Astros Printing Ltd.Leo United Paper Products Ltd.', 'Changes made as per feedback', '2019328', '2024-08-07 07:49:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1351, 23982, 1995, '1660361', '2024-08-07 06:23:21', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Incorrect answer choice - Comments point to plans made only for direct business operations (no supply chain).', 'Disagree - Its a correct answer choice - Below example is related to supply chain as well, let me know if you have other opinion."Sea Level Raise : Establish an environmental monitoring team to continuously monitor and report the sea water levels.When selecting new sites for expansion, avoid choosing a coastal or low-lying area."', '1286637', '2024-08-07 08:29:06', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1352, 23982, 1998, '1660361', '2024-08-07 06:37:29', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'May I know where the 2021 numbers were retrieved from? Was unable to locate anywhere in the CSR report 2023', '2021 emission was taken from previous year report and I have added the reference as well, trust this clarifies.', '1286637', '2024-08-07 08:38:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3506, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1353, 23982, 1999, '1660361', '2024-08-07 06:46:30', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Incorrect answer choice - Comments do not justify the following answer choice: "Planned change in supply chain to lower carbon emissions"', 'agreed - removed this answer choice', '1286637', '2024-08-07 08:40:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
