INSERT INTO mstr.advisor_memo_report VALUES (1358, 24304, 1989, '1551380', '2024-08-06 06:56:48', 'Radhakrishnan, Gowtham ', 'Gurunathan, Akshay Ram', '"Yes - Entity direct operations can be affected by Physical Risk" would be more appropriate here in my opinion especially when company identifies Acute physical risk due to heatwaves as "significant risks".', 'Agreed - Amended', '1665924', '2024-08-07 10:31:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1359, 24304, 1991, '1551380', '2024-08-06 07:49:47', 'Radhakrishnan, Gowtham ', 'Gurunathan, Akshay Ram', '2023 ESG report is available for download but report is in Korean. Based on emission numbers provided, there is an increase in scope 1 & 2 emissions in 2023 to 15,921tCO2e (2022: 14,525tCO2e) which exceed the threshold of 15,000 tCO2e for target management system. Hence, I would argue for "Additional policy measures expected in next 2 - 5 years" or even "Additional policy measures expected in next 2 years".', 'Agreed - Amended', '1665924', '2024-08-07 10:35:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1362, 24780, 1973, '1599218', '2024-07-31 18:14:10', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical - this is the financing arm of the Group and likely very much asset light. Please reflect that risk are through the value chain and mention that an increase in extreme weather events is likely to generate financial losses owing to the potential impact on leased vehicles, and related borrowers'' challenges in meeting their financial obligation. Reflect this in the CRA Analysis as well', 'Climate Analyst comment: Actioned.', '1540001', '2024-08-09 11:48:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1363, 24386, 2014, '1551380', '2024-08-12 03:54:41', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Accuracy of CRQ - Please amend comments - wrong sector.Current Comments - The company is within the media industry limit classification and its project temperature alignment score is 0.76 degree above the sector average. (3.46)', 'Climate Analyst comment:  Actioned. Human error due to  copy pasting standard comment.  Amended.', '1540001', '2024-08-12 09:43:03', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3427, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1364, 24386, 2016, '1551380', '2024-08-12 04:03:15', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Other minor issues - Hyosung TNC became the first company in the world to commercialize and mass-produce regen Bio-Based Spandex, which is made by processing natural raw materials extracted from corn.In the reporting year, Hyosung TNC achieved a successful commercialization of the plant-based environmentally friendly ''regen Bio-Based Spandex.'' As a result of promoting the regen''s eco-friendliness in the market, sales of our eco-friendly yarn have nearly doubled every year since 2017, with sales of KRW 54,864 million in the reporting year. - Are we able to derive the % of revenue from sale of ''regen Bio-Based Spandex''? If it is more than 30% , we can adjust it to High <=70%. ', 'Climate Analyst comment: Revenue breakup for the client is not available. Hence marking it as very high on a conservative approach. However comment updated as per above.', '1540001', '2024-08-12 10:16:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1365, 24386, 2013, '1551380', '2024-08-12 03:35:27', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Other minor issues - Answer selection needs to be changed.Please add "Yes - Planned change in products mix to offer lower carbon alternatives.(e.g. Portfolio rebalance or Product change / divestment)''. The evidence is in pg 8 SR 2022 "In response to the growing demand for eco-friendly materials, Hyosung TNC has developed and marketed regen Bio-Based Spandex and regen Spandex, which are made from by-products. These two products have undergone independent 3rd-party Life Cycle Assessments (LCA) and have been verified for their ability to mitigate carbon emissions."For "Yes - Planned change in production operations: Lower emission fuel types (e.g. Greening of energy mix)", the evidence is in pg 24 SR2022 "Hyosung TNC utilizes and consumes biogas by supplying the biogas generated from anaerobic digestion at the wastewater treatment plant to the boiler in order to increase the use of renewable energy within the plant. The company plans to use', 'Climate Analyst Comment: Actioned.', '1540001', '2024-08-12 10:33:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1366, 24780, 2005, '1599218', '2024-08-07 11:04:34', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Accuracy of CRQ - target #2 and #3 also include Scope 3 emissions. There is a note at page 81 stating that the target comprises also upstream (fuel production) and downstream (emissions from driving) emissions.Accuracy of CRQ - all targets are not on absolute basis, but physical intensity. Still at page 81, there is another note stating that the unit is gCO2e/Km', 'Climate Analyst comment: Actioned. Additionally updated targets from CDP.', '1540001', '2024-08-12 14:26:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1367, 24780, 2006, '1599218', '2024-08-07 11:08:15', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical - please call out exactly for each selection option, why you have selected that option - refer to the bottom of this note for examples of what I mean.Additionally, you should also select "Portfolio rebalance" - use the format below and specifically call out how many more EVs they are targeting to produce.if you choose "lower emission fuel types", please say "Toyota is aiming for lower emission fuel types by doing XYZ"if you choose "Other changes", please add another sentence saying "Toyota is aiming for other changes and are doing XYZ"', 'Climate Analyst comment: Actioned', '1540001', '2024-08-12 14:40:25', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1368, 24757, 2007, '1493184', '2024-08-08 12:25:11', 'Mutepfa, Tashinga', 'Harsh, Shubham', 'Accuracy: In LOA section, what is credit rating assessment ?? CRA is climate risk assessment', 'Feedback incorporated, Auto correct changed the CRA abbreviation. ', '2008896', '2024-08-13 12:43:06', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1369, 24757, 2008, '1493184', '2024-08-08 12:57:54', 'Mutepfa, Tashinga', 'Harsh, Shubham', 'Analytical issues:  Relevant location details are to be included', 'Q2.1 has been Grayed out, we cannot add the location details in the NTB CRA. ', '2008896', '2024-08-13 12:44:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1370, 24839, 2017, '1599218', '2024-08-12 16:34:13', 'Joardar, Abhisek ', 'Gowri, V Kavya', 'Accuracy of CRQ - C11.1 of CDP Report, the Client states that is covered by both the EU and Mexico ETS. Please also read through the subsequent questions where they provide detailed information on which plants are being covered by the scheme, how many certificates they receive for free and how many they purchase - please report all this info in the CRQ', 'Actioned - answer choice updated and evidence is provided from CDP report.', '2006519', '2024-08-14 07:24:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1371, 24884, 2025, '1493184', '2024-08-17 17:06:32', 'Joardar, Abhisek ', 'Harsh, Shubham', '.', 'NOT RELEVANT: Adding locations in NTB light touch approach is greyed out ', '2008896', '2024-08-18 18:22:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1372, 24884, 2026, '1493184', '2024-08-17 17:13:21', 'Joardar, Abhisek ', 'Harsh, Shubham', 'Analytical issues:  PLease reer to user guide -- value chain is based on building''s lifecycle. Should be operational stage', 'ACTIONED: Agreed ', '2008896', '2024-08-18 18:22:57', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1373, 24884, 2027, '1493184', '2024-08-17 17:14:07', 'Joardar, Abhisek ', 'Harsh, Shubham', 'Minior issues:  Do we know what the EPC rating is for the assets ?', 'NOT RELEVANT: Yes we have the EPC certificate for all the Assets under consideration. Analysis provided in Q5.6 and evidence added in the comment. Due to character limitation the ratings have been added in Q5.6.', '2008896', '2024-08-18 18:25:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1374, 24230, 2033, '1575987', '2024-08-23 06:49:42', 'Joardar, Abhisek ', 'Sunil Dahale, Shreyash', 'Does ECBC applies to Industrial buildings ? if the building is already constructed - How ECBC code will apply ?', 'Amended. As Medha owns mostly industrial buildings, which do not face policy measures in the short-to-medium term, changed answer choice accordingly.', '2020154', '2024-08-26 05:43:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1375, 25799, 2036, '1551380', '2024-08-26 08:32:50', 'Masarin, Lisa', 'Ziemlinska, Aleksandra ', 'Other minor issues - Please add in comment that the mitigation is to address Chronic physical risk arising from Changing precipitation patterns and types. Same for analysis in Outcome tab. The flow should be that the client has assessed all possible physical hazards that can impact company''s operations and it has been determined that Changing precipitation patterns is the most material as water is a resource that is vital for OMV as it is used for multiple processes in OMV’s direct operations, e.g., drilling, steam generation, and cooling, among other processes.', 'Comment added', '2018956', '2024-08-26 11:47:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1376, 25799, 2035, '1551380', '2024-08-26 07:11:40', 'Masarin, Lisa', 'Ziemlinska, Aleksandra ', 'Accuracy of CRQ -  "Integrated / Diversified" should be chosen, Entity is an international oil, gas, and chemicals company with operations extending from hydrocarbon exploration and productionthrough to trading and marketing of mineral oil products, chemical products, and natural gas. As per user guide - Integrated/Diversified companies are multinational corporations engaged in all aspects of the oil and gas value chain and, through their own activities, oversee all operations spanning from E&P down to refinery and processing and trading and distribution.', 'The answer is changed.', '2018956', '2024-08-26 11:48:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1377, 25799, 2037, '1551380', '2024-08-26 08:40:10', 'Masarin, Lisa', 'Ziemlinska, Aleksandra ', 'Refer to email please. Take note of unit and make sure they are correct for each target. ', 'corrected', '2018956', '2024-08-26 12:26:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1378, 24448, 2029, '1660361', '2024-08-22 08:20:36', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Small point - can you please add the 2020 and 2019 figures please for Scope 1 and 2 (found under pg 64 of the sustainability report).Also emissions intensity is captured on the same page in the chart on the bottom left. Can you feed those info into the comments box - noted no information on Scope was available. ', 'Updated as suggested.', '1563645', '2024-08-27 06:43:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1379, 24448, 2030, '1660361', '2024-08-22 08:32:55', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Error with the target level for Scope 3 - it is working out to 40% instead of 50%. Please amend (Target level of 22147200 to be amended) ', 'Amended accordingly.', '1563645', '2024-08-27 06:43:47', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1380, 24448, 2031, '1660361', '2024-08-22 08:41:49', 'Radhakrishnan, Gowtham ', 'Banerjee, Monalisa', 'Additional answer option to be selected (Planned change in product mix) - shift in production to focus on higher iron ore content product thereby reducing scope 3 emissions.Climate Change Report 2023 Pg 20 (already covered in your comments)In terms of our scope 3 emissions, we will be maximising our premiumproduct offering – suitable for lower carbon, direct reduction processesof iron in steelmaking – thereby reducing steelmakers'' processemissions and thus our own scope 3 emissions. Using high iron orecontent product in blast furnace steelmaking can realise a 2.5%reduction in carbon emissions for every 1% increase in iron ore grade.We are also working to facilitate the move to a circular economy byengaging in ferrous recycling initiatives.', 'Updated accordingly.', '1563645', '2024-08-27 06:51:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1381, 24424, 2043, '1410763', '2024-08-27 06:53:10', 'Ciszewski, Michal', 'Kapica, Joanna', 'Please amend this to ''Yes''. The client is a Financial Arm of an Automotive company. As such, this will be covered in the Automotive Value Chain. ', 'Noted and addressed: the answer was changed as per the feedback.', '1642635', '2024-08-28 07:21:07', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1382, 24911, 2046, '1575987', '2024-08-28 09:15:05', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'The level of details does not elicit a Yes answer. ', 'agreed - amended the answer choice', '1286637', '2024-08-29 08:30:49', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1383, 24911, 2049, '1575987', '2024-08-28 10:57:12', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Please say how the company Could be impacted given it is engaged in execution of construction contracts. ', 'agreed - added', '1286637', '2024-08-29 08:35:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1384, 24181, 2050, '1191828', '2024-08-28 16:10:02', 'Komjati, Dalma Beatrix ', 'Harsh, Shubham', 'Understand that the policy measures are marked current due to EU ETS....however that is applicable from Jan 2026 only. Also exports to EU is less than 25%. Hence this answer choice seems penalizing to me', 'ACTIONED. The answer choice is changed.', '2008896', '2024-08-29 14:44:35', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1385, 24395, 2053, '1551380', '2024-08-29 05:19:53', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Source URL for Source 4 and 5 are the same. Please check.', 'Climate Analyst comment: Link updated', '1540001', '2024-08-30 08:46:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1386, 24395, 2054, '1551380', '2024-08-30 03:04:41', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Please add that as a telecommunications and technology services provider, key assets of the company are network infrastructure including cell towers and central offices. ', 'Climate Analyst comment: Comment updated', '1540001', '2024-08-30 08:47:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1387, 24395, 2055, '1551380', '2024-08-30 03:45:56', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Please review answer. I don''t think there is any policy measures that are currently in place. All discussion on policy risks are referring to the future and impacts on business are assessed to be Medium-low and for medium- and long-term.', 'Climate Analyst comment: Amended to reflect the national commitment. Policy measures expected in next 5 - 10 years.', '1540001', '2024-08-30 08:59:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1388, 23615, 2048, '1660361', '2024-08-28 10:03:40', 'Komjati, Dalma Beatrix ', 'Tarakji, Ranim', 'According to the Climate Policy Tracker, additional policy measures are expected in next 2-5 years instead.', 'Implemented', '2003718', '2024-08-30 09:12:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1389, 23615, 2047, '1660361', '2024-08-28 09:26:05', 'Komjati, Dalma Beatrix ', 'Tarakji, Ranim', 'Please check whether emissions data is available within Capital IQ, if so please populate manually into the table below (as per the 2023 CRQ).Also, small change - please correct the target reduction to 100% instead of tCO2e for its Scope 1,2 and 3 2040 target.', 'Emission data is not available.Target reduction has been corrected. ', '2003718', '2024-08-30 09:27:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1390, 24130, 2040, '1551380', '2024-08-27 02:22:46', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Risk impact (3.1) and measures (Q3.2) should aligned. So include the risk impacts mentioned in page 37 in comments.Risk Impact1) Results in product delivery delays or supply chain disruptions, leading to a decrease in revenue:The production stability of raw materials is affected by extreme climate. In particular, copper plates and copper strips are widely used as electrical conductor materials in various industries. If suppliers are unable to provide goods in a timely manner, products may not be shipped in accordance with customer demand, which may result in delayed delivery of products or even a disruption in the industry supply chain, leading to a decrease in operating revenue.2) Extreme climate change increases transportation costs:The occurrence of extreme weather will increase the risk of transportation interruptions. Transportation companies may reduce flight services as a result, and the Company will need to find alternative tran', 'Agreed. Included the risk impacts.', '1600990', '2024-08-30 12:29:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1391, 24130, 2039, '1551380', '2024-08-27 01:51:24', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'If you read BCA Part 2, WII is the treasury center serving the subsidiaries (copper & wire operating entities in China) currently under intermediate parent Walsin Lihwa Holdings (‘WLH’). ', 'Agreed. Updated the other half of the nature of business.', '1600990', '2024-08-30 12:33:58', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3410, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1392, 24130, 2028, '1551380', '2024-08-21 07:26:23', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Please relook at the tracker for Taiwan policy as well as the Material Risk Event log. The statement " There is no policy measures in Taiwan for Metals & Mining Sector" is incorrect. Also, if you read BCA Part 2, WII is the treasury center serving the subsidiaries (copper & wire operating entities in China) currently under intermediate parent Walsin Lihwa Holdings (‘WLH’). So the focus should be on China plus any key export markets of copper & wire products manufactured in China. Again, looking at BCA part 2 (business snapshot), key markets for copper & wire are Taiwan, HK, China, Southeast Asia. ', 'Agreed. Updated the Taiwan policy and policies of HK, China and other countries in South East Asia that can impact the business of WII.', '1600990', '2024-08-30 13:06:06', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1393, 24130, 2041, '1551380', '2024-08-27 03:21:26', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Q4.2, Q5.5 and Q5.6 are linked and they drive the risk trigger logic as well. We cannot answer Q4.2 and Q5.5 as a collective at Group level and yet answer Q5.6 at entity level. ', 'Agreed - Updated the answer choices.', '1600990', '2024-08-30 15:06:12', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1394, 24130, 2042, '1551380', '2024-08-27 03:21:41', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Q4.2, Q5.5 and Q5.6 are linked and they drive the risk trigger logic as well. We cannot answer Q4.2 and Q5.5 as a collective at Group level and yet answer Q5.6 at entity level. ', 'Agreed and updated the answer choice.', '1600990', '2024-08-30 15:06:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1395, 25954, 2059, '1489063', '2024-09-03 13:20:08', 'Pal, Aditya', 'Roy, Devika Rose', 'Given that the full set of production of assets is conducted off the west coast of Norway, I would adjust this assessment to take the Norway Sov Heatmap Ranking instead. Key risk is lower production of O&G rather than of customers demand in this case, so think Norway is good proxy for offshore close to the country. Would include this analysis in rationale.', 'ok, amended', '2001769', '2024-09-03 16:56:49', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1396, 25954, 2060, '1489063', '2024-09-03 13:32:00', 'Pal, Aditya', 'Roy, Devika Rose', 'Please adjust the LNG / Gas split. You have grouped the 35% gas into LNG here.Oil represented 59% of the production  in 2023, with gas and NGL making up 35% and 6%, respectively.', 'Amended', '2001769', '2024-09-03 17:02:10', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3414, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1397, 25954, 2061, '1489063', '2024-09-03 13:37:45', 'Pal, Aditya', 'Roy, Devika Rose', 'Can you add the non-quantitative targets for scope 2 ?Scope 2:Ensure that 100% of our purchased electricity from our operated assets comes from renewable sources, neutralising our scope 2 emissions. ', 'Added', '2001769', '2024-09-03 17:02:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1398, 25954, 2062, '1489063', '2024-09-03 13:41:59', 'Pal, Aditya', 'Roy, Devika Rose', 'I would argue that their isn''t much evidence for planned change in production. Focus is on ship vessel / transport efficiencies which i would say are through the Supply Chain improvements instead, hence would remove production operations.Assume Greening Mix & Portfolio Rebalance is increase focus on Gas?', 'Yes - focus on gas', '2001769', '2024-09-03 17:19:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1399, 24397, 2066, '1489063', '2024-09-03 15:29:43', 'Joardar, Abhisek ', 'Banerjee, Monalisa', 'https://www.abulkhairgroup.com/business-portfolio/LONG STEELAbul Khair Steel Melting Ltd’s rolling mill was commissioned in 2009 which introduced advanced TMT technology of steel making in Bangladesh market. As a backward linkage EAF (Electric Arc Furnace) facility was added in 2015 for making 100% refined steel billet which are used to produce world class TMT bar. The integrated long steel making plant comprises of country’s first Electric Arc Furnace refining facility and the single largest fully automated rolling mill with annual capacity of 1.4 million ton. Abul Khair Steel currently produces 100% EAF refined steel billets and AKS TMT 500W & 550W construction steel bar in Bangladesh', 'Updated accordingly.', '1563645', '2024-09-04 08:23:11', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3420, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1400, 24757, 2009, '1493184', '2024-08-08 13:00:20', 'Mutepfa, Tashinga', 'Harsh, Shubham', 'Analytical issues:  I''m not able to access the BCA- what is the purpose of the loan and the entity -- Holding companies can also take up loans to construct the building, so value chain is not just dependant on t whether the company is a holding company or operating company, it also depends on what the financing is for and the stage in the lifecycle of the building', 'Actioned: The answer choice has been changed to ''Construction'', The facility has been provided to redevelop the Chifley Tower North podium into a 56,646 sqm Premium Grade Office building. ', '2008896', '2024-09-05 02:54:09', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3409, 'GTR3', 'esg_navigiator', '01');
