INSERT INTO mstr.advisor_memo_report VALUES (1418, 25731, 2093, '1575987', '2024-09-12 04:26:44', 'Pal, Aditya', 'Kumar, Ajith', '"Focusing on energy and water resource management, we are improving our energy utilization rate and reducing carbon dioxide emissions through technological modifications to equipment and other measures.˙On the production side, we have purchased energy-efficient power equipment and actively encourage the reuse of excess energy and residual pressure to reduce energy consumption in our production systems. Simultaneously, we continue to conduct energy-saving reviews to reduce energy consumption in the production system throughmanagement measures." - How these are related to Physical risk ?', 'agreed - Amended the answer choice', '1286637', '2024-09-13 13:57:20', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1419, 25993, 2108, '1575987', '2024-09-16 09:08:01', 'Leva, Aljaz', 'Popielarczyk, Dagmara', 'Revenue disruption seems not to be covered ', 'amended to option B', '1663712', '2024-09-17 04:43:14', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
