INSERT INTO mstr.advisor_memo_report VALUES (1423, 25731, 2094, '1575987', '2024-09-12 05:39:08', 'Pal, Aditya', 'Kumar, Ajith', 'if manufacturing plants are located in other countries apart from china - Whether there regulations would not be relevant ? Please comment in this regard', 'Agreed - Amended', '1286637', '2024-09-17 06:52:17', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
