INSERT INTO mstr.advisor_memo_report VALUES (1425, 24188, 2085, '1410763', '2024-09-10 13:31:54', 'Gurunathan, Akshay Ram', 'Desai, Apurva Milind', 'The client has operations across Australia, NZ, Indonesia, Singapore, Vietnam,  China and India. Despite being headquartered in SG, it has bigger operations in Australia than in SG purely based on # of assets in each country (data listed in section 2). Please use the expected sovereign policy measures in Australia''s Real Estate sector to respond to this question. You can briefly comment on policy measures expected in other key operating locations - China, India and SG.', 'Agreed and amended. ', '2020019', '2024-09-17 09:07:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
