INSERT INTO mstr.advisor_memo_report VALUES (1433, 24879, 2105, '1575987', '2024-09-16 04:24:21', 'Pal, Aditya', 'Roy, Devika Rose', 'Why not option 5 - CCUS ? What evidence suggest improved efficiency of equipment  ?', 'amended', '2001769', '2024-09-23 10:27:59', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1434, 24879, 2103, '1575987', '2024-09-16 04:02:52', 'Pal, Aditya', 'Roy, Devika Rose', 'Can we check unit of the emissions   ? the emissions for an O&G company seems to be quite low ', 'Amended as the report on pg 89 - million tonnes of carbon eq', '2001769', '2024-09-23 11:59:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1435, 24879, 2104, '1575987', '2024-09-16 04:05:21', 'Pal, Aditya', 'Roy, Devika Rose', 'If Client has emission intensity targets - Do they don''t report intensity based data ?', 'They report Scope 1 & 2 emissions data together and not separately. This has been captured in the comment box for Q5.4', '2001769', '2024-09-23 12:04:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1436, 24879, 2101, '1575987', '2024-09-16 03:55:24', 'Pal, Aditya', 'Roy, Devika Rose', 'Does the client have refining operation ?', 'No refining operations. Amended to E&P', '2001769', '2024-09-23 12:07:22', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3403, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1437, 24879, 2102, '1575987', '2024-09-16 03:58:10', 'Pal, Aditya', 'Roy, Devika Rose', 'Is the emissions are above 1 lac tonnnes ? Should we not consider the carbon policy in Alaska and PNG ?How coal related policies are relevant here ?', 'Santos Ltd and its facilities are included in the safeguard mechanism. Source: https://cer.gov.au/markets/reports-and-data/safeguard-facility-reported-emissions-dataAdded policy in Alaska & PNG and removed coal related evidence', '2001769', '2024-09-23 12:28:17', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1438, 26008, 2123, '1551380', '2024-09-24 07:17:58', 'Pal, Aditya', 'Tarakji, Ranim', 'CSR report has been quoted in section 5 but not listed as source. ', 'Done.', '2003718', '2024-09-24 07:42:53', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1439, 26008, 2125, '1551380', '2024-09-24 07:38:42', 'Pal, Aditya', 'Tarakji, Ranim', 'Please review the statement "While 60% of the electricity comes from renewable sources, reducing the overall carbon footprint, the remaining 60% is sourced from non-renewable energy, contributing significantly to indirect emissions." - Should it be 40% from renewable sources and hence the answer selection of High <=70%?Please amend analysis as well. ', 'The typo has been corrected. 60% of the electricity comes from renewable sources, while the remaining 40% is sourced from non-renewable energy. High is selected duo to scope 3 emissions,  taking into consideration that the 40% of the electricity sourced from non-renewable energy contributes significantly to indirect emissions.', '2003718', '2024-09-24 07:53:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1440, 26008, 2124, '1551380', '2024-09-24 07:19:07', 'Pal, Aditya', 'Tarakji, Ranim', 'Please remove the statement "Please note Company''s GHGs have increased since the base year 2020. We were unable to find out from public disclosures what has caused the increase, assuming methodology change but recommend to confirm with client."  from comment and analysis. Revenue has increased by 57% from 2020 to 2023 so it is not surprising to see increase in emissions. ', 'Done.', '2003718', '2024-09-24 07:56:26', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
