INSERT INTO mstr.advisor_memo_report VALUES (1445, 24774, 2010, '1493184', '2024-08-08 13:02:00', 'Mutepfa, Tashinga', 'Harsh, Shubham', 'Analytical issues:  have you checked reports at ADIA (they will have info related to their CRE investment business?)', 'We have reviewed ADIA''s website (https://www.adia.ae/en/pr/2022/real-estate.html), but did not find any climate-related reports or information available on the site or in the public domain. However, we received the ''Environmental Due Diligence Report'' and ''Energy Certificate'' from the Business team, which were utilized for the climate risk assessment. Hence the LOA has been selected as the ''Legal Entity''.', '2008896', '2024-09-25 09:24:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
