INSERT INTO mstr.advisor_memo_report VALUES (1455, 25140, 2143, '1551380', '2024-10-03 02:34:29', 'Scariah, Renjith ', 'Banerjee, Monalisa', 'In BCA Part 2, the following has been provided. "However we understand from the discussion with the client that all the assets of the company are adequately insured to cover any risk arising out of fire, earthquake, flood etc. Thus, we do not foresee any  major financial implication for the company on account of Physical Risk. The insurance availed by the company adequately covers any potential physical risks. Thus, we do not see any financial risk emanating from the physical risk."', 'Updated the same accordingly.', '1563645', '2024-10-03 09:49:41', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1456, 25140, 2144, '1551380', '2024-10-03 02:38:04', 'Scariah, Renjith ', 'Banerjee, Monalisa', 'The hazard scores are not showing - how did the statement "revealing varied risk levels across site, including high Heat and Precipitation stress highlighting the vulnerability of III’s operations" come about?', 'Previous comment was updated as per the MunichRE assessment reflected in the system. Now updated comment based on updated MunichRe result. There are some ongoing issues in MunichRe automatic assessment.', '1563645', '2024-10-03 09:53:30', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
