INSERT INTO mstr.advisor_memo_report VALUES (1459, 24711, 2119, '1575987', '2024-09-24 04:05:06', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Business model is not clear - Is it a rolling mill or does it have EAF , Induction or blast furnace ?  Is the plant manufacturing steel from Scrap or DRI ?', 'ADDITIONAL INFORMATION. Since the BCA Part 2 is now available in CreditMate, additional information related to the client''s business model has been added to the comment. The response choice is not changed. ', '2007983', '2024-10-04 07:42:31', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3410, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1460, 24711, 2118, '1575987', '2024-09-24 04:03:26', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'Insurance does not cover Chronic Physical risk and hence cannot be considered as complete awareness of Physical risk . Further, Insurance needs to be taken due to policies of banks for securing assets and does not necessarily mean - Company is fully aware of physical risk ', 'Not relevant as confirmed by Elliott Rouse.', '2007983', '2024-10-04 07:44:12', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
