INSERT INTO mstr.advisor_memo_report VALUES (1474, 25372, 2148, '1489063', '2024-10-04 13:40:57', 'Gurunathan, Akshay Ram', 'Desai, Apurva Milind', 'Can you provide some evidence for this that the transport network is reliant on fossil fuels and to what degree? Does this transport and logistics arm make up a substantial portion of the business revenue / operations? ', 'Available disclosures do not have information about the energy mix of SBT. As we do not have any evidence for measures in place to decarbonize their supply chain, the answer choice has been selected as a conservative approach. The % share of revenue has now been added to the comments.', '2020019', '2024-10-08 13:37:18', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
