INSERT INTO mstr.advisor_memo_report VALUES (1476, 25211, 2171, '1575987', '2024-10-08 16:43:40', 'Scariah, Renjith ', 'Banerjee, Monalisa', 'Please confirm if Alibaba''s report includes departmental store business - If not Alibaba''s report cannot be used. ', 'Climate analyst comment: Yes, They do. hence we considered their reports. Note- This is not a material feedback as it''s just a query from 2nd line.', '1563645', '2024-10-09 07:15:23', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
