INSERT INTO mstr.advisor_memo_report VALUES (1483, 24532, 2174, '1551380', '2024-10-09 15:28:03', 'Komjati, Dalma Beatrix ', 'Pai, Vallabhi Vishwas', 'similar feedback as Jeju LNG - Korean ETS price currently USD 6 , In korea Shipping is also covered in ETS. Can we also align the inputs where appropriate for 13686582 & 13686583 (JEJU LNG1 S.A. & JEJU LNG2 S.A.) as well given same LoA?', 'Agreed. Changes implemented as per feedback.  Changes made in Q4.2- ''updated with current carbon price and sector coverage''  and Q5.6.1- answer choice updated to ''Yes-meaningful impact'' ', '2019328', '2024-10-10 06:11:39', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
