INSERT INTO mstr.advisor_memo_report VALUES (1487, 25806, 2181, '1575987', '2024-10-10 06:19:13', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Please explain  for the 1st line - 2030 targets - Scope 1, 2 and 3 targets are different ', 'Updated, detailed explanation of scope 3 targets has been added including categories, percentage.. etc. ', '2003718', '2024-10-10 08:09:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1488, 25897, 2186, '1489063', '2024-10-10 13:48:21', 'Mutepfa, Tashinga', 'Kapica, Joanna', 'Do we know how they book this revenue, as it may not correspond to the area of their operations and so I don''t think is a great proxy for Physical Risk in this case. I think a Asia-Pacific regional average view would be more appropriate of a Global Average if not, as revenue is not guaranteed to align to asset locations. ', 'Noted. We don''t have the details of how the revenue is booked and we don''t have the Asia-Pacific regional average provided separately. Hence, we decided to go with the Asia average (86).', '1642635', '2024-10-10 14:36:13', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1489, 25982, 2151, '1575987', '2024-10-04 13:51:59', 'Ptasinska, Dorota', 'Jen, Yvonne ', 'How EU-ETS is applicable here ? PAT scheme details and applicability are available on its website.  Introduction of carbon markets in India and legislative process initiation should be highlighted as key risk  ', 'Agreed. Updated the comment section.', '1600990', '2024-10-10 18:10:26', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1490, 25982, 2152, '1575987', '2024-10-04 13:58:07', 'Ptasinska, Dorota', 'Jen, Yvonne ', 'Not sure how are they tracking the target achievement - Please recheck ', 'Agreed. Added why the emissions at entity level is important.', '1600990', '2024-10-10 18:11:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1491, 25344, 2185, '1489063', '2024-10-10 13:13:47', 'Masarin, Lisa', 'Baran, Ewa', 'I think we can add that is specialises in industrial flue gas desulfurization, denitrification and dedusting. Industrial flue typically refers to power generation activities with a focus on coal.Hence, whilst the activities are trying to reduce the emissions levels of the power plants, the client is highly reliant on high emissions activities for their business model and cash flow generation for financing repayments.', 'Thank you additional comments included! ', '1663704', '2024-10-11 07:39:05', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1492, 25389, 2140, '1599218', '2024-10-01 15:12:56', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical -  can you please gather these numbers from the list at page 138 of the sust report? You have aggregated all thermal capacity under coal, but that number also includes gas. Generation leave it blank as the breakdown is not fully available', 'now updated', '1663704', '2024-10-11 11:08:46', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1493, 25389, 2141, '1599218', '2024-10-01 15:27:33', 'Masarin, Lisa', 'Baran, Ewa', 'I would drop the this target - our system cannot monitor a "cap" -Can you please check the 2025 target available in here - https://www.banpu.com/investor-relations/publications/climate-change-report/Response: The parent''s climate change report includes short-term emissions intensity reductions targets for its Power Business (page 19). This should largely apply to BPP and can be updated here. ', 'Please note that the report is for Parent / Group not Banpu Power; no selected with additional comments for target #1.', '1663704', '2024-10-11 11:13:27', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1494, 25389, 2182, '1599218', '2024-10-10 12:47:18', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical - please what does this comment mean? Do they use scenario analysis? What scenario do they look at? What is the financial impact under the scenarios?', 'now updated', '1663704', '2024-10-11 11:26:26', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3514, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1495, 25389, 2142, '1599218', '2024-10-01 15:32:20', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical - when you speak about the energy breakdown in 2025 (i) compute the % of capacity from renewable expected in 2025 and (ii) compare to the % of renewable capacity in 2023. If this will increase, then overall reliance on thermal power is actually decreasing and you can mark this question as "they will be useful" - do you see the kind of reasoning I am looking for?', '% calculated and comments updated ', '1663704', '2024-10-11 12:16:16', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1496, 25389, 2188, '1599218', '2024-10-10 14:00:50', 'Masarin, Lisa', 'Baran, Ewa', 'please stop copy paste - speak plain English a tell about the investment pipeline (800 MWefrom renewable pipeline). All I need to see here is:"Banpu is allocating Capital Expenditure towards projects that will support its decarbonisation pathway. They have set up a no coal expansion policy as a result of which reliance on coal is not expected to increase moving forward, although any coal-related investment will be focused on enhancing operational efficiency of existing plants, which will further support its emission intensity profile. At the same time, Banpu has a project pipeline to increase total capacity to 5300MW by 2025 (of which ~800MW made up of renewable energy), from ~3500 MW at YE23 (of which only ~290MW from renewable power). The additional investment in thermal power is expected to come from more efficient CCGT power plants, which, as per CDP Disclosure, accounted for over 60% of the Client''s total Capital Expenditure plan."', 'comments updated ', '1663704', '2024-10-11 12:16:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1497, 24531, 2179, '1493184', '2024-10-09 21:11:30', 'Komjati, Dalma Beatrix ', 'Pai, Vallabhi Vishwas', 'Analytical:  Is the ISIC incorrect ? It shoudl be shipping', 'Yes. The ISIC is correct. Jeju vessels are LNG Carriers, hence ISIC classification as 4020- Gas Mfr & distribution is correct. ', '2019328', '2024-10-14 09:35:02', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1498, 24534, 2163, '1575987', '2024-10-07 11:37:37', 'Komjati, Dalma Beatrix ', 'Pai, Vallabhi Vishwas', 'Please limit comments limited to the vessel only ', 'Noted. Comments updated as per feedback ', '2019328', '2024-10-14 09:35:37', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1499, 24534, 2164, '1575987', '2024-10-07 11:41:19', 'Komjati, Dalma Beatrix ', 'Pai, Vallabhi Vishwas', 'Reason for positive delta ?', 'As responded by the CA, LNG bunkering tanker like the client- Jeju vessels are bunkering are considered out of scope for Poseidon.As bunkering tankers, a large portion of the fuel burnt on the vessels goes into loading / discharging cargo and keeping the cargo cold (LNG has a boiling point -162°C). Therefore, the amount of fuel burnt is high relative to amount of distance travelled. Based on the same rationale, for this year’s 2023/24 PP reporting, DNV has also agreed that these vessels are ‘out-of-scope’.', '2019328', '2024-10-14 09:36:52', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1500, 21931, 2183, '1489063', '2024-10-10 12:56:41', 'Pal, Aditya', 'Roy, Devika Rose', 'Client is a leaser of equipment, which is a non-high emission activity. Whilst the group is involved in port operations, the client itself would not have operations associated with emissions. The client would not be responsible for the emissions of leased equipment either and so overall low reliance on emissions. Please change to Low or provide evidence against this.', 'We believe the client is responsible for the leased equipment as this falls in their Scope 3. Amended to low because these emissions would be negligible. Source: https://dart.deloitte.com/USDART/home/publications/deloitte/additional-deloitte-guidance/greenhouse-gas-protocol-reporting-considerations/chapter-7-accounting-for-ghg-emissions/7-2-scope-3-emissions-from', '2001769', '2024-10-14 10:34:54', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1501, 21931, 2184, '1489063', '2024-10-10 12:58:27', 'Pal, Aditya', 'Roy, Devika Rose', 'Again - do not think this regulation would apply to leasing equipment company. It is possible that the Group is affected by the regulation and so some Parent Company effects - but unlikely for entity to be directly effected. Can keep at same rating due to parent affect, but please include some narrative in the text and analysis to point out these factors.', 'Okay. Adding context', '2001769', '2024-10-14 10:47:15', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1502, 25478, 2195, '1575987', '2024-10-14 16:54:11', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'Please elaborate reason for marking answer choice as No', 'As per the ESG Report, page 5, REPORTING BOUNDARY, the information provided in the report covers our 3 major buildings in Hong Kong, namely Pioneer Place (“PP”), Club Lusitano Building (“CL”) and 68 Yee Wo Street Building (“68 YWS”) which together account for 90% (2023: 90%) of the Group’s total rental and property management service income. Hence the provided information is not applicable to the asset under question. ', '2008896', '2024-10-16 09:04:51', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
