INSERT INTO mstr.advisor_memo_report VALUES (1505, 25349, 2197, '1551380', '2024-10-16 04:34:46', 'Gurunathan, Akshay Ram', 'Desai, Apurva Milind', 'Please review BRAG analysis - see below extract. Don''t think it is correct as no RT is proposed in this CRA but there were RTs proposed in previous CRA. It was mentioned that - There were no previous risk triggers. The present physical RT is, “To follow up on (1) the potential impact of physical risks and (2) company''s plan to reduce, manage or adapt to physical risks in the context of both direct business operations and the company''s value/supply chain.” ', 'Agreed and amended. ', '2020019', '2024-10-17 09:16:19', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1506, 25632, 2209, '1493184', '2024-10-18 16:56:38', 'Joardar, Abhisek ', 'Pai, Vallabhi Vishwas', 'Accuracy: There are no Scope 3 targets entered', 'The Group''s targets currently do not address scope 3. The answer choice selected was incorrect, which has been amended to sector coverage-"scope 1 and 2 targets" Referring sustainability report 2023 pg 70-Scope 3 Target Setting- The company is on track to set targets for reduction in the 2025–2026 timeframe. ', '2019328', '2024-10-19 16:10:36', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
