INSERT INTO mstr.advisor_memo_report VALUES (1508, 24716, 2202, '1575987', '2024-10-16 08:41:23', 'Mutepfa, Tashinga', 'Brodzicka, Elzbieta', 'Please check are all these applicable to LE ?', 'It has been checked and all initiatives apply to the LE. ', '2007983', '2024-10-21 07:14:44', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1509, 25598, 2173, '1551380', '2024-10-09 02:55:41', 'Joardar, Abhisek ', 'Sunil Dahale, Shreyash', 'Please review answer selection and comment.Answer Selection: Additional policy measures expected in next 2 - 5 yearsComments: Consequently, it is not anticipated that no additional policy measures will be introduced in the next 2 to 5 years that would impact these industries.The answer selection should be changed to "No additional policy measures expected in next 10 years" as there isn''t any emerging regulation risk as disclosed in CDP. Their emissions are minimal as well as a global firm operating in more than 65 countries. Pg 82 of 2023 ESG Report"In our climate‑related risk assessments, we have considered current regulations, emerging regulations, legal, market, technological, and reputational risks, as well as acute and chronic physical risks. Based on input from McKinsey’s internal functions, sustainability practice experts, and others, we have not identified inherent climate‑related risks with the potential to have a substantive f', 'Amended accordingly.', '2020154', '2024-10-21 07:24:21', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1514, 22668, 2213, '2015466', '2024-10-22 09:37:44', 'Ptasinska, Dorota', 'Jen, Yvonne ', 'These does not seem to be physical risk adaptation. Examples of adaptation measures: -Flood defence walls-Strom drains-Dry warehouse', 'Agreed and updated as No.', '1600990', '2024-10-22 09:45:45', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
