INSERT INTO mstr.advisor_memo_report VALUES (1702, 26601, 2443, '1493184', '2025-01-03 23:53:26', 'Joardar, Abhisek ', 'Pai, Vallabhi Vishwas', 'Scope 3 emissions in 2023 seem incorrect ', 'The total scope 3 emission in 2023 seems to be correct, which is 2014 tonnes CO2e.Category 3.6- 578 tCO2eCategory 3.7- 1436 tCO2e578+1436= 2014 tCO2eBut, the stark difference in reported emissions is due to change in methodology. The 2022 Cat 3.7 (employee commuting) emission was determined by- "Estimated average emission of the whole MHB employee population based on the projection from the available number of employee commuting data." whereas in 2023 it was determined by "The emission data derived from the responses collected in an employee commuting survey"', '2019328', '2025-01-06 05:28:58', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (1703, 26601, 2444, '1493184', '2025-01-03 23:55:17', 'Joardar, Abhisek ', 'Pai, Vallabhi Vishwas', 'Progress for Scop1, Scope 2 emissions is still needed to be shown, in the text please compare how Scope 1and Scope 2 emissions are changing based on revnue intensity (ie Scope1/revenue)', 'the progress for revenue intensity is tracked as per the set target for only scope 1 & 2. Additionally, yoY progress is individually tracked for scope 1 & 2.', '2019328', '2025-01-06 06:08:34', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
