INSERT INTO mstr.advisor_memo_report VALUES (1807, 26315, 2590, '1410763', '2025-02-20 15:23:43', 'Leva, Aljaz', 'Brodzicka, Elzbieta', 'The financial impact does not cover the EV entity of the group. The 5 plants mentioned in Q 3.1.1 do not include the EV plant in Chakan and therefore the $ of the financial impact mentioned is probably being grossly overstated. Option 3 would be a better response in the absence of any financial impact estimates to MEAL. ', 'amended', '2007983', '2025-02-21 07:47:38', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3303, 'PRA3', 'esg_navigiator', '01');
