INSERT INTO mstr.advisor_memo_report VALUES (1810, 26875, 2566, '1489063', '2025-02-18 17:58:39', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Where did you acquire this data from - as per their latest Earning report Q3 24, they had 199 kboe/d of liquids and roughly (577-199) = 378 kboe/d of gas production which is more like a 34%/ 66% split', 'It was posted in S&P last year and taken as an estimation. Updated with data you shared. This will not have any material impact on BRAG. ', '1663712', '2025-02-24 09:49:32', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3414, 'GTR3', 'esg_navigiator', '01');
