INSERT INTO mstr.advisor_memo_report VALUES (1812, 27267, 2565, '1489063', '2025-02-18 16:06:27', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Can you check what the Shell Group PDs are and whether they are higher or lower than these sector averages. WE have Shell Plc data available and these should apply to this entity, so we could directionally say if this should be different.', 'As per email communication - we cannot override the PD data but we are well aware that most cases from the group base on Shell PLC data for PD values. This is a technical issue that is to be solved. Commentary added as per Elliot''s advise. ', '1663712', '2025-02-24 10:07:08', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3428, 'GTR3', 'esg_navigiator', '01');
