INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18278, 63, '1493184', '2023-07-27 18:12:47', 'Waclawska, Kamila', NULL, 'For CRE, as a practice, request to also mention the energy source breakdown of the power grid in the country if possible, while justifying high risk.  Or eg: Hong Kong electricity predominantly comes from coal. (Quote the source when you mention the power grid breakdown). For major markets, ths should be publicly available.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
