INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18703, 61, '1551380', '2023-07-27 10:00:15', 'Masarin, Lisa', 'Baran, Ewa', 'Don''t agree with answer choice. Based on BCA Part 2, the company is engaged in design, manufacturing and sales of jewellery under Chow Tai Fook brand and provides wholesale business of gold and jewellery to CTK self-operated POS and franchisees. Shouldn''t the most appropriate industry be Clothing and Clothing Accessories Stores or Jewelry and silverware manufacturing which are both having low reliant on carbon emission?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18707, 14, '1599218', '2023-07-17 16:38:42', 'Ptasinska, Dorota', 'Baran, Ewa', 'Q5.1 - can you please amend and state that, considering its business model aimed at developing low carbon plants, the Client does consider transition risks. Can you please also add that such Entity is a way for the Parent Company to diversify from its domestic coal-fired cogeneration plants', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2001, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18737, 12, '1489063', '2023-07-17 14:59:36', 'Ptasinska, Dorota', NULL, 'Do they have any details on the types of alternative fuels used for clinker production / an idea on the ideal clinker ratio used? Are there any details on how much these projects will cost and over what timeframe will they begin implmentation?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2009, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18737, 13, '1489063', '2023-07-17 15:00:49', 'Ptasinska, Dorota', NULL, 'Do they mention any details about the security of these additional alternative fuel mixes. Most of these come from the by-product of other high emitting processes like coal fired power plants and so security of materials may reduce in the future.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2015, 'TRM', 'esg_navigiator', '01');
