INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18878, 217, '1575987', '2023-08-31 05:20:24', NULL, 'Banerjee, Monalisa', '" To improve accountability, we also set mid-term targets to reduce and avoid emissions across our value chain by 2025." - Can you quantify short term targets ? if not - No should be selected for short term targets.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2040, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18878, 218, '1575987', '2023-08-31 06:04:53', NULL, 'Banerjee, Monalisa', 'Please include mitigation for acute physical risk.  How using data from world resource institute mitigate physical risk in the supply chain ?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2079, 'PRA', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 18970, 114, '1489063', '2023-08-04 12:33:38', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'This doesn''t sound like they have made plans to change production / product base at all, and will still be wholly focused on LNG rather that altering the mix of storage and transportation. Would recommend this be altered to a "No" - the below is more of a product change and ccan be used if you feel appropriate for a Yes• Biomethane/Biogas/Bio-LNG: In 2022, we have ventured into the Biomethane and Renewable Gases Guarantees of Origin trading and supply business. This is aligned with our strategic expansion plan to develop new gas markets and diversify our product portfolio. We are seeking similar opportunities to secure biogas supplies in Southeast Asia. Our team in Spain has secured the International Sustainability and Carbon Certification (ISCC) to trade and supply biomethane in Europe.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2009, 'TRM', 'esg_navigiator', '01');
