INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19420, 30, '1575987', '2023-07-20 15:48:29', 'Masarin, Lisa', NULL, 'Please mention : "The implementation of Indonesia’s carbon tax is expected in 2023 after facing delays. The carbon tax was introduced into Indonesia’s tax law at the end of 2021. Indonesia’s carbon tax is set around 2 USD/tCO2 and will initially focus on coal-fired power plants. The government plans to gradually increase the tax and expand the coverage to other sectors. "', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2084, 'GTR', 'esg_navigiator', '01');
