INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19784, 656, '1551380', '2023-11-27 09:16:54', 'Komjati, Dalma Beatrix ', NULL, 'Per email discussion, the entity is a listed company and reports (in Chinese) are available online as well as S&P emission data. Please review CRA. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19794, 85, '1599218', '2023-08-02 14:48:06', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'emissions reported are in million metric tons - table''s unit of measure is metric tonnes. this makes the emissions not comparable with those of other clients', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2090, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19912, 107, '1575987', '2023-08-04 07:28:23', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', 'LOA :  Please add that the legal entity is a Hold co.  Climate related info is not available at LE level. The opco''s are in Cement manufacturing. The ultimate Parent Ultratech limited is also engaged in Cement manufacturing, hence considered for LOA.  ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19912, 110, '1575987', '2023-08-04 09:25:06', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', 'Include comments from CDP Q 2.2 a - Acute climate risk and chronic climate risk - Pls. say - The financial impact of physical risks is estimated to be less than 1% of EBITDA.  ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2077, 'PRA', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19912, 111, '1575987', '2023-08-04 09:26:49', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', '" We have not witnessed any impact of heat waves on its facilities. Nevertheless, it ensures that its employees are protected during peak summer days. It is committed to the WASH Pledge, ensuring adequate availability of safe drinking water to workers. Warehouses are also secured with early morning and late evening operational hours." - Are these comments required ?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2080, 'PRA', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19912, 112, '1575987', '2023-08-04 09:36:34', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', '"The company has been assessed as very high emitting given it''s reliance on high emitting" - Please review . Cement manufacturing involves heating of limestone in kilns in which coal is used as a fuel . The manufacturing process thus releases large amount of Co2 ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19912, 113, '1575987', '2023-08-04 10:13:31', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', '"The aluminum sector, reliant on natural gas for the generation of electricity for manufacturing needs, has set emission intensity targets that cover the complete range of industrial processes: power production, smelting, and casting. The use of state-of-the art gas turbine technology, improved maintenance of plants and equipment, and operational efficiency are yielding emission savings for the sector. - " - How this is relevant to the cement sector ?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2082, 'GTR', 'esg_navigiator', '01');
