INSERT INTO mstr.advisor_memo_report VALUES (NULL, 19941, 363, '1551380', '2023-09-24 13:28:33', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Please mention that a total of 451 locations are available on website (https://www.basf.com/global/en/who-we-are/organization/locations.html). I will be adding additional analysis to ask CA to provide key operation locations in BCA. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2048, 'GPR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20087, 257, '1493184', '2023-09-04 23:08:38', NULL, 'Joardar, Abhisek ', 'I can see some investment activities to reduce carbon intensity of operations but there is no map to change production mix - This is only if you see core business diversifying into other activities. Perneco is still an upstream O&G player only. Please change the response and the comments to No', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2009, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20087, 258, '1493184', '2023-09-04 23:10:02', NULL, 'Joardar, Abhisek ', 'The answer is not clear, what is the consumer preference that is being talked about, and what is the change made by Perenco ?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2032, 'TRM', 'esg_navigiator', '01');
