INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20155, 319, '1551380', '2023-09-18 13:15:53', 'Pal, Aditya', NULL, 'As per company''s website, production base, automatic Logistics Center and R&D center are located in Comix industrial park. Address as per website is "Comix Industrial Park, No.18, Jinxiu Middle Road, Pingshan District, Shenzhen, Guangdong, China".', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2047, 'GPR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20274, 329, '1489063', '2023-09-20 16:05:08', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'The text below doesn''t constitute an actual Net zero commitment in my mind - sounds more like they agree with the global standard that NZ is appropriate. I think this should be change to Short term only commitments for the thermal substitution rate - which isn''t an emissions reduction target either. You also say No Net Zero target in Q1.7, so think this should be consistentThink the answer is painting a better picture than reality and so need to mention some of this in Analysis and commentary,', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2040, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20274, 330, '1489063', '2023-09-20 16:14:09', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'This should be changed to very high. The company is entirely reliant on the operating entity which is involved in the manufacture of cement. This is one of our Net Zero sectors and Dangote is the largest exposure in the portfolio. They are involved in the clinker and calcination of cement, which requires heating and burning of fossil fuels to high temperatures to "cook" the cement product for offtake. This is a very high emitting process. Please change.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
