INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20408, 296, '1599218', '2023-09-13 10:57:41', NULL, 'Kumar, Ajith', 'This is not an investment for decarbonisation (ie, increase share of renewables). If you read through the CDP report it states that it is aimed at developing partnerships through JVs to improve its tech capabilities (and bring an example of a partnership related to AI, IoT, etc). Please focus on what investments it is doing to increase renewables (and nuclear)! look at page 7 (capital investments) of the 2022 annual report (https://www.clpgroup.com/content/dam/clp-group/channels/investor/document/3-3-financial-reports/2022/e_2022Annual%20Report.pdf.coredownload.pdf)', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2015, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20408, 297, '1599218', '2023-09-13 10:58:18', NULL, 'Kumar, Ajith', 'please also remove this one, and reflect the CAPEX as per link shared in Q5.7 (renewables should be ~10%)', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2031, 'TRM', 'esg_navigiator', '01');
