INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20424, 157, '1575987', '2023-08-17 06:33:44', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'As per the emission table provided in Q 5.3 - Emissions scope 1 + Scope 2 seems to > 25 KT . Are we sure Carbon pricing is not applicable to the entity ? ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2082, 'GTR', 'esg_navigiator', '01');
