INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20426, 153, '1489063', '2023-08-16 07:59:16', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Can mention that the client''s business model is online travel ticketing and hence they have very little need for operating assets or asset-heavy processes. As a result, we are more comfortable with physical risks of entity, however any locations of data centers or other information technology sites should be considered in future assessments.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2047, 'GPR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20427, 149, '1551380', '2023-08-15 08:05:02', 'Komjati, Dalma Beatrix ', NULL, 'Please mention here as well as in LoA justification that company is a joint venture between Anhui Provincial Port and Shipping Group and car manufacturers Chery and JAC. Shareholding: Anhui Provincial Port and Shipping Group (44.44%), Chery Automobile (44.44%) and JAC Motors (11.11%). Also mention that company will be an operator of LNG dual fuel powered ro-ro vessels which support the transportation of automobile vehicles. As for the Answer selection, I will adjust it to High <70% with justification that LNG is deemed as a cleaner fuel as compared to diesel and fuel oil. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
