INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20460, 187, '1489063', '2023-08-23 14:21:51', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'The company is a marketing and distribution company for Palm Oil essentially. Palm oil is not the highest carbon emitting product, especially from direct production, as it is the growth of palm trees. There is a land use impact, however this is small. Additionally, this entity is not producing the palm oil, as it is taking the refined product from another company and trading it, so very little carbon impact. I would adjust this to be a "Low" or maximum "Medium" reliance on fossil fuels.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
