INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20470, 166, '1551380', '2023-08-21 01:40:07', 'Mutepfa, Tashinga', NULL, 'For justification of aligning to Group, please add that "Company''s CAT1 limit of USD50Mn is used for the group’s general corporate needs as well as refinancing needs (e.g. intra-group lending to support the group’s subsidiaries)" and that "the Group operates in five business segments – (1) Engineering and Construction); (2) Survey, Design and Consulting Services; (3) Equipment and Component Manufacturing; (4) Property Development, and (5) Logistics/Trading/Others. The Group’s main focus is on the construction of infrastructure, such as railways, roads, urban rails, and civil works, house building etc."', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
