INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20474, 203, '1575987', '2023-08-28 04:25:28', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Q 1.1.  Marked as Yes - Comments are for a No answer.  - Please amend the comments - " During the development, construction and operation of renewable energy solutions, our company makes environmental, social, and corporate governance (ESG) decisions that additionally impact or depend on the sustainability agenda, both in Europe and globally".', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20474, 204, '1575987', '2023-08-28 04:46:53', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'How additional policies will impact a EPC contractor engaged in renewable energy segment. Additional policy measures for transitioning  will be an opportunity for it to grow the business. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2084, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20474, 205, '1575987', '2023-08-28 05:06:28', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Why the answer is No then ? You can also use CSR report of Q Energy France which is a subsidiary of the legal entity and engaged in same line of business ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2002, 'TRM', 'esg_navigiator', '01');
