INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20492, 249, '1599218', '2023-09-04 12:35:47', 'Ramesh, S', 'Harsh, Shubham', 'Please amend to Medium - this final answer will depend on the fuel used for distillery purposes for which I have added a customized RT.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20497, 263, '1551380', '2023-09-06 04:32:13', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Please use inputs in CDP C1.2a instead.Additionally, climate change risks are explicitly included in Hilton’s annual Enterprise Risk Management assessment processes. We define climate change risks as “Shifts inglobal or regional climate patterns, leading to an increase in the severity/frequency of extreme weather events, rising sea levels, and sustained higher temperatures, all ofwhich may result in risk to current operations and future development in at-risk markets.”', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20497, 271, '1551380', '2023-09-07 02:39:21', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'How was High<=70% selected? No justification has been provided in comments. The BCA Part 2 that was provided to you is a draft so you don''t have to mention page number the next time you are quoting from BCA. In comments, please mention the following and then provide justification for answer selection:As per BCA Part 2, entity is a 90:10 joint venture between OIA and Westmont Hospitality Group (“Westmont” or “Minority Shareholder”). OIA is the sovereign wealth fund of Oman. Westmont is a privately held owner and operator of hotels globally. Their responsibilities include overseeing the asset management of the hotel (DoubleTree by Hilton Hyde Park Hotel) including financial accounting, sales and marketing, IT and human resources. A Franchise Agreement is in place between entity and DoubleTree International Franchise LLC (the “Franchisor”). This contract allows the entity to run the hotel as a DoubleTree by Hilton branded asset. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
