INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20553, 401, '1575987', '2023-09-28 08:48:29', 'Ptasinska, Dorota', NULL, 'The entity is setting up lithium battery manufacturing plant. These batteries are expected to be primarily utilized in Auto sector. Given the product will help Auto/ power sector transition , we may consider rating as Medium ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
