INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20607, 453, '1551380', '2023-10-09 03:18:31', 'Leva, Aljaz', NULL, 'Try to remove information that is not useful and make your comment concise and sharp. You can change it to "Al-Haj Karim Textiles Limited (AKTL) is a manufacturer of cotton yarn. The company is incorporated on 27 April 2005 and subsequently started its operation from 2007 at Kalampur, Dhamrai, Dhaka Bangladesh. AKTL is 100% export-oriented company and also a member of Bangladesh Textiles Mills Association (BTMA). The company mostly imports raw cotton from Switzerland, Singapore, India and USA. The company has their own supply of electricity (6000 KW generator: 6 Generator, 500KV capacity) which is powered by gas.Based on the company’s business activities described above, AKTL’s reliance on fossil fuels/high carbon products is assessed as high."Please also update Outcome tab. Following comments are for outcome tab. Climate Risk Grading (BRAG) Analysis - some wordings added to sentence "Level of applicability: Due to the lack of publicly ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2081, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20607, 457, '1575987', '2023-10-10 12:36:12', 'Leva, Aljaz', NULL, 'Selling waste cotton is a commercial decision and cannot be considered as a measure to reduce GHG emissions. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2009, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20612, 473, '1575987', '2023-10-16 05:28:51', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', '.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20630, 662, '1493405', '2023-11-28 03:05:55', 'Ptasinska, Dorota', NULL, 'Accuracy of CRQ - The answer here does not link to Scenario modelling. The evidence is just description of various "climate scenarios"', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2035, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20630, 663, '1493405', '2023-11-28 03:06:43', 'Ptasinska, Dorota', NULL, 'Analytical aspects - In terms of evidence, can we include anything that refers to how much financial impact will this carbon price have on the business from the CDP Questionnaire?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2037, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20630, 664, '1493405', '2023-11-28 03:12:37', 'Ptasinska, Dorota', NULL, 'Accuracy of CRQ - please use the below from the sustainability report with regards to that mentioned in the Shipping Industry and we should refer the IMO Guidelines in the CRQ Analysis too.We are also seeking to bring greater transparency andcomparability of GHG emissions in the shipping sector, also please refer CDP question 11.1 (d) for better references.as founding members of the Sea Cargo Charter and theGetting to Zero coalition. In 2022, initial disclosures by25 signatories under the Sea Cargo Charter resulted inunprecedented levels of transparency and data sharingand I am pleased to note that Trafigura’s performance isahead of the industry decarbonisation trajectory set by theInternational Maritime Organisation (IMO).Through our investments in vessel technology andoperational efficiency, we made strong progress this yeartowards our target to reduce the carbon intensity of allshipping voyages by 25 percent by 2030, compared toour I', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2002, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20630, 665, '1493405', '2023-11-28 03:18:32', 'Ptasinska, Dorota', NULL, 'Accuracy of CRQ Please refer to Page 42 of the Sustainability Report, there is a mention of overall investment into Low Carbon Technologies;Also should we change the answer option if we know the denominator of the overall investments from the BCA?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2031, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20630, 666, '1493405', '2023-11-28 03:22:50', 'Ptasinska, Dorota', NULL, 'Accuracy of CRQ - please provide adequate evidence as this question must be answered keeping in mind Shipping and plans with regards to that and the plan to meet IMO 2030 targets. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2032, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20665, 810, '1493184', '2023-12-31 11:39:02', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Accuracy:  If Scope 3 emissions are not accurate, and only now they aim to disclose the right results, change the option to say only Scope1,2 are reported', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2003, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20665, 811, '1493184', '2023-12-31 11:42:45', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Minor issue: Do we know if the sustainability linked lonas are related to climate/emission targets ? can we check ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2031, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20794, 739, '1191828', '2023-12-18 18:24:31', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'pls refer BCA', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2080, 'PRA', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20799, 799, '1551380', '2023-12-28 07:16:32', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Accuracy of CRQ - This client is an offshore contract drilling company operating jack-up rigs. So the focus should be on how they are addressing the change in O&G industry (increasing focus on reducing carbon emissions and transitioning to renewable energy sources resulting in the decline in the demand for oil and gas to support the world''s energy needs) and how they are reducing emissions from operations (implementation of various regulations and initiatives for the shipping industry to reduce emissions).', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2002, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20799, 800, '1551380', '2023-12-28 07:30:59', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Other minor issues - This comment is for LoA reason for override. As per BCA, Shelf Drilling, Ltd. (SDL) is a holding company with no significant operations or assets other than interests in its direct and indirect subsidiaries. All operations are conducted through Shelf Drilling Holdings, Ltd. (SDHL), an indirect wholly owned subsidiary of SDL. Hence, I suggest changing the reason for override to below:LE is an indirect wholly owned subsidiary of Shelf Drilling, Ltd. (SDL). SDL is a holding company with no significant operations or assets and all operations are conducted through LE. As report is not available at LE level and LE is deemed to be in the same sector as group, group report is used. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2039, 'GND', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20799, 801, '1551380', '2023-12-28 10:04:42', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Accuracy of CRQ - Entity is an offshore contract drilling company operating jack-up rigs. Hence, the focus should be on both the O&G industry and shipping industry. Similarly for Q5.2, the focus should be on policy measures impacting both the O&G and Shipping industry. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2084, 'GTR', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20799, 802, '1551380', '2023-12-28 10:56:17', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Other minor issues - Please quote AR2022 Pg79"Current and future regulations relating to greenhouse gases and climate change also may result in increased compliance costs or additional operating restrictions on our business. The negative impacts of greenhouse gases and climate change have resulted in adverse publicity for the oil and natural gas industry and could cause damage to our reputation. In addition, because our business depends on the level of activity in the offshore oil and natural gas industry, existing or future regulations or other agreements related to greenhouse gases and climate change, including carbon taxes or greenhouse gas fees or incentives to conserve energy or use renewable energy alternatives, could decrease the demand for oil and natural gas or decrease exploration activity."', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2001, 'TRM', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20799, 803, '1551380', '2023-12-28 11:01:11', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Other minor issues - Please quote AR2022 Pg79."The scientific community has concluded that increasing concentrations of greenhouse gases in the Earth’s atmosphere are producing climate changes that have significant physical effects, such as increased frequency and severity of storms, floods and other climatic events. Such events could have a materially adverse effect on our operations, especially given that our rigs may need to curtail operations or suffer damage during significant weather events."', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2076, 'PRA', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 20872, 796, '1575987', '2023-12-28 04:52:34', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', '.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 2043, 'GND', 'esg_navigiator', '01');
