INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21168, 698, '1599218', '2023-12-07 16:04:58', 'Davies, Krista', NULL, '  Accuracy of CRQ- Why do you state the Entity is not susceptible to Physical Risk? This does not depend on the level of risk itself, but whether the Client owns physical assets - it does in this case. Please change, and in Q2.13 use count of asset locations by region as per following global diversification: https://demo.baomarc.it/contatti/', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21179, 703, '1551380', '2023-12-11 14:34:07', 'Ptasinska, Dorota', NULL, 'Other minor issues - Try not to just copy and paste all information. Instead, extract only the relevant information. In this case, only include the part relating to physical risk and summarizes the findings. You can update your comments to the following:As per Page 10 of SR, company has identified climate related physical risks including Hurricane, Wildfires, Droughts, Floods, Extreme heat and Changes to precipitation pattern. In terms of likelihood of risk, company sees its operations in ANZ, UK and USA being likely to face physical risk in the short-term. Impact of climate related risk include reduced revenue due to potential risks of supplier, logistics and network disruption. The company also identified opportunities in the areas of conducting flood and heat risk assessments on existing properties. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21179, 704, '1551380', '2023-12-11 14:51:14', 'Ptasinska, Dorota', NULL, 'Other minor issues - The answer selection and commentary provided seems to contradict the analysis you have provided in outcome tab.Here we have selected that the company has made current / future plans to manage or adapt to physical risks in the context of their direct business operations. However in physical risk analysis, it was mentioned that "CSE does not assess the vulnerabilities of its facilities to climate hazards through in-depth physical risk analysis comprising the risk of climate hazards happening, the lifespan of the projects and the capacity of each facility to adapt to the changing climate."', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21179, 705, '1551380', '2023-12-11 14:57:18', 'Ptasinska, Dorota', NULL, 'CRA summary analysis - Below feedback is for Transition Risk Analysis in outcome tab as well as the overall climate risk assessment. If you read the company''s SR closely, you will realize that the company is at its very early stage of recognizing and disclosing climate risk. What the company has done is merely identifying the risks and pointing out some possible impacts and opportunities. There is no in-depth impact analysis and mitigation plan. Some of the phrases that support what I have mentioned includes:- "We are cognisant of the impact climate change can have on our operations and is taking steps to identify and integrate these climate-related risks into our business strategy. To that end, we started adopting the recommendations of the TCFD framework in FY2022, which enabled us to better position ourselves to manage identified climate-related risks and seize climate-related opportunities arising from these risks."- "Achieving a cl', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21194, 812, '1493184', '2023-12-31 11:52:37', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Analytical Issues:  If the CRA is for a proejct, we are concerned about the specific asset being financed, we don''t need all Group assets', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21194, 813, '1493184', '2023-12-31 11:54:29', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Minor issues:  Surprising if the asset has no insurance and we are funding it - please check in the BCA/check with the RM. Section 2 also indicates high risk of cyclones/typhoons, hence damage to asset needs to be covered at a minimum', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21194, 814, '1493184', '2023-12-31 11:55:55', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Minor :  Please check BCA as well as its an ETB - explicitly whether this building is LEED certified or not', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3419, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21194, 815, '1493184', '2024-01-01 23:16:53', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Analytical: Pls confirm if these emissions represent the project or overall company - even if we can conclude that project is material to overall emissions, then we can use company emissions, otherwise what is the rationale --kindly refer to the project finance user guide.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
