INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21221, 735, '1493184', '2023-12-18 16:30:12', 'Pal, Aditya', 'Delaney, Peter Jared', 'Analytical aspects: I don''t fully follow the response, are you saying the company does acknowledge policy, legal, market and technology risk ? if yes, then it does acknowledge climate risks. But ifn not, simply mark as no with one line comment. Some of the responses are not particular to the client and are more about what should happen in the industry.. This is irrelevant here.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21221, 749, '1493184', '2023-12-20 09:30:24', 'Pal, Aditya', 'Delaney, Peter Jared', 'Analytical aspect: For projects, we will have definitely have asset location available which should be entered here.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21222, 741, '1493184', '2023-12-18 19:27:34', 'Mutepfa, Tashinga', 'Brodzicka, Elzbieta', 'Minor issues:  pPLease change underlying building to yes  --> this is meant to capture only where the transaction pertains to an underlying asset and not whether the building is already there or not', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3419, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21233, 771, '1551380', '2023-12-22 03:47:09', 'Waclawska, Kamila', 'Baran, Ewa', 'Other minor issues - When you are quoting from BCA Part 2, be mindful that the question is about whether company "acknowledge" or "identify". So we can only take it as evidence if it is mentioned that the statement is from client. If not, place it after the evidence from other sources and treat it as a supporting statement. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21233, 772, '1551380', '2023-12-22 03:48:10', 'Waclawska, Kamila', 'Baran, Ewa', 'Other minor issues - For this particular question, I don''t think the ISIC code Manufacture of fertilizers and nitrogen compounds (3512) should be translated to Agri Producers. However, I understand this is a industrial classification issue. So I would suggest rewording comments to below so it helps to explain other questions using industry averages as well.No, the Client''s sector is not covered by NZ commitments. ISIC code 3512 Manufacture of fertilizers and nitrogen compounds translate to Agri Producers as per system industrial classification.	', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21233, 773, '1551380', '2023-12-22 03:57:18', 'Waclawska, Kamila', 'Baran, Ewa', 'Other minor issues - I would suggest quoting from website (https://nghc.com/about/why-green-hydrogen/) as well.HOW IS NGHC HELPING SAUDI ARABIA REACH ITS CLIMATE GOALS?Saudi Arabia aims to diversify its energy mix away from fossil fuels, reduce its dependence on oil and increase the share of renewable energy in power generation under Vision 2030. By harnessing the power of both nature and technology, NGHC will support the Kingdom’s climate mandate by enabling the large-scale adoption of green hydrogen and ushering in a new sustainable clean energy era.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21234, 818, '2009422', '2024-01-04 15:47:59', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Accuracy of CRQ: please use this link to add the sustainability report of EDP https://www.edp.com/en/2022-annual-integrated-report', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
