INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21234, 820, '2009422', '2024-01-04 15:59:09', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Accuracy of CRQ:  please refer to page 272 of the report (https://www.edp.com/en/2022-annual-integrated-report) and compute the weighted average sovereign score using the revenue breakdown by country.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21234, 821, '2009422', '2024-01-04 16:18:26', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Analytical aspect: Please amend the commentary and referring to page 16 ( 74% of company''s generation is coming from renewable sources) of the report (https://www.edp.com/sites/default/files/2023-08/Integrated%20Report%202022%20-%20website%20version.pdf); therefore the company won''t be significantly impacted by the policies. Please change your answer to no additional policies.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
