INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21266, 999, '1599218', '2024-02-12 17:00:05', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Analytical aspects - no need to change the answer, but can you please mention that, according to their CDP Report, they expect a carbon pricing impacting them in the next years?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21266, 1028, '1599218', '2024-02-13 14:20:21', 'Gurunathan, Akshay Ram', 'Kumar, Ajith', 'Analytical Aspects: please ensure the target 4 is monitored, fill the data in the table for target 4 (the data are available).Analytical aspects - I do not understand where these data come from. Target 1 is to reduce emissions by 50% by 2025 vs 2019. Page 50 provides you all these data. 2019 S1+2 (293,508), 2022 S1+2 (234,476) and 2030 target (293,508 * 50% = 146,754‬). Exact same thing for Target 2. Please also note the additional intermediate 2025 target of -25%. Please ensure this is added to the previous table.For target 3 things are more complicated. You have the baseline figure (14,361,452) and you can compute the target level (14,361,452*(1-0.28) = 10,340,245). For the current level, page 17 tells Scope 3 account of 98% of total emissions (hence S1+2 (=293,508) represent 2%). This means, you can compute S3 emissions current level as (293,508/0.02)= 14,675,400‬. These have increased!', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
