INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21269, 938, '1599218', '2024-01-31 15:05:07', 'Radhakrishnan, Gowtham ', 'Kumar, Ajith', 'Accuracy of CRQ - last year it was set at policy in the next  2y because of the expected carbon tax on the energy sector. Policy tracker still says the same rating for carbon pricing. Additionally, the Client also maintains operations in Indonesia and Australia - for both regions we know the client is impacted by carbon pricing. These things should be considered and added both in the commentary section and the CRA Analysis. Please tailor your analysis to the scope of the carbon pricing initiatives and their coverage', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
