INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21325, 1025, '1599218', '2024-02-13 13:58:17', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Analytical aspects - as mentioned several times, it is not important what is this financial ratio and this is just a guide. The question is "Does the Client have operating assets that can be impacted by physical hazards?" the answer (and your justification for the commentary box) should be "Yes, the Client is exposed to physical hazards when taking into account the fact its solar plants can be impacted by several extreme whether events which could ultimately impact its ability to generate and sell electricity" All the rest is not relevant', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21325, 1026, '1599218', '2024-02-13 14:00:08', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'LoA - if you want to use EDF, please only focus on biodiversity matters related to EDF''s solar business. You mention a few things about hydro and other kind of plants which are not applicable to the client LEID. If you do not have this info, then just say no.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3104, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21325, 1027, '1599218', '2024-02-13 14:00:11', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'LoA - if you want to use EDF, please only focus on biodiversity matters related to EDF''s solar business. You mention a few things about hydro and other kind of plants which are not applicable to the client LEID. If you do not have this info, then just say no.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3105, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21329, 891, '1599218', '2024-01-23 14:59:53', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Accuracy of CRQ - what do you mean by "Business of Bunge is all over the world in Different Countries as seen above" I do not see any country listed. Please, can you take all these countries and list them in the commentary - please do not use the global average but try to weight their heatmap by revenues/costs/or other financial metrics. UPDATED: just to be more specific, I do not want to use the global average for granted. I want to see where the Client''s assets are and based on this determine the HM. If you look into the annual report (https://investors.bunge.com/~/media/Files/B/Bunge-IR/documents/financial-information/annual-reports/bunge-2022-annual-report.pdf) at page 146 of the PDF, you have the breakdown of PPE by country. Use those that are listed at least and average the European countries and APAC HM rank', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21329, 892, '1599218', '2024-01-23 15:05:50', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'Accuracy of CRQ - the commentary is not relevant to the question - here they describe a risk and estimate the financial cost of it through the increase in insurance premia.rather use this: "There were no substantive acute physical events experienced in 2022. A cold snap in the Southern states of the United States resulted in roughly $10m business disruption, however, this is considered a relatively small impact. Nevertheless, in previous years Bunge experienced more significant events such as hurricanes that caused more structural damage and business disruption – all of which were beneath our substantive risk threshold and recuperated through insurance." However, DO NOT COPY PASTE IT - just say that in the past the Client had climate risk events which were recuperated through insurance programmes, which demonstrates the Client actually has insurance policies in place', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21329, 893, '1599218', '2024-01-23 15:12:51', 'Radhakrishnan, Gowtham ', 'Harsh, Shubham', 'this is not a comment, but just wanted to say well done on how the targets have been captured', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
