INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21345, 1056, '1489063', '2024-02-19 16:50:57', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'I would argue that airlines are very susceptible to physical risk events, as you mention the changing conditions have a heightened impact on flight paths, operations and hence revenue and operating ability.  I would hence change this answer to a yes for direct assets as well.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21345, 1057, '1489063', '2024-02-19 16:53:10', 'Gurunathan, Akshay Ram', 'Harsh, Shubham', 'This entity is an airline and hence has global or at least European operations, which are not solely situated in Ireland. I would argue that this should be changed to a Global average, or some investigation done into the Ryanair countries of operation and a weighted average  taken.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
