INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21361, 887, '1599218', '2024-01-23 11:07:29', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Accuracy of CRQ - Please use the sustainability for this question. for example, they have a target on the type of assessment "100% of AESL''s operational locations and subsidiaries to be covered under biodiversity impact assessments by FY 2024-25"please also refer to page 78 of the sustainability report', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3104, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21361, 888, '1599218', '2024-01-23 11:57:59', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Accuracy of CRQ - all targets you have added are long term only. Please change the time horizon to LT onlyAccuracy of CRQ - baseline year for target #1 is 2022Accuracy of CRQ - baseline year for target #2 is 2021Accuracy of CRQ - please also add the target where they aim to phase out their 500MW coal plant by 2030 (page 68 of Sustainability report)', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21361, 889, '1599218', '2024-01-23 11:58:55', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Accuracy of CRQ - please rectify the data you use for baseline level as per previous commentAnalytical aspects - additionally, please in the commentary box and the CRA analysis, mention the evolution of emission intensity per MWh sold. You can find this info in page 64 of sustainability report. State this is high (i.e., above 1,000 tCO2/MWh) due to dependency', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21362, 1155, '1599218', '2024-02-28 10:58:10', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Accuracy of CRQ - Capacity: 481.9 all for on shore wind - Generation is not available, please remove the figure you have addedProject 1=29.9MWProject 2=252MWProject 3=200MW', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3415, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21362, 1156, '1599218', '2024-02-28 10:59:27', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Analytical aspects - the following comment is not true at all "Renewable energy generation assets should not be considered as part of NZ commitment." Please remove it, and remove such reference from the CRA Analysis as well', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21365, 1089, '1551380', '2024-02-22 05:44:55', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Other minor issues - What caused the change in answer as compared to CRA done last year where answer selection was "High <=70%"? Please spend some time understanding the business activities of the company. From what I read, the company is a Apple Premium Reseller (APR) and has ~70 retail stores. Sales are to individuals and corporate buyers.Also, analysis (i.e. high gross transition risk which is driven by its business model i.e reliant on high carbon products as it has dependency on logistics being a sourcing and sales arm of Apple in Shanghai, the company may have lower Scope 1 and Scope 2 emission, and higher Scope 3 emissions) does not make sense. If you are looking at logistic side, then the focus should be scope 1 emission which is typically from owned or leased vehicles to distribute products. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21365, 1090, '1551380', '2024-02-22 05:46:27', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Other minor issues - What policy measures are currently in place? Is the company impacted by the policy measures? In last year CRA, answer selection was "Additional policy measures expected in next 2 - 5 years". ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21365, 1092, '1551380', '2024-02-22 06:24:53', 'Gurunathan, Akshay Ram', 'Jen, Yvonne ', 'Company has ~70 retail stores located in Shanghai, Jiangsu and Anhui. Please include information. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
