INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21434, 817, '1551380', '2024-01-04 02:27:05', NULL, 'Scariah, Renjith ', 'LOA -1) Please check what''s the CAT 1 limit and determine if client should be in scope.2) I believe you have take a look at the ESRA. In ESRA, the CA made reference to Network International Holdings. Please check with CA on the relationship of entity and Network International Holdings and determine the appropriate LoA. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21449, 993, '1575987', '2024-02-11 12:56:45', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Please say that the company business does not fall under aluminum value chain . Due to automated selection of ISIC , the company is being classified under aluminum value chain ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3413, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21449, 994, '1575987', '2024-02-11 13:00:37', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Consider additional policy measures in 2-5 years due to expected implementation of carbon pricing. Add info. on developments wrt ETS scheme. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21450, 979, '1493184', '2024-02-08 20:31:01', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical issues:  1. Has LOA been confirmed BY RM ? Please check -- if there is no response, use ENI Ghana Exploration and Production Ltd which is the operator of the asset as  LOA -- please redo the CRA.2. Any project/asset level climate/due diligence report received from the RM ? Was it asked', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21450, 980, '1493184', '2024-02-08 20:32:25', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical issues:  The project refers to an underlying asset -- location details for the project can be obtained and is mandatory in line with the project finance user guide.If not available in BCA, please check with the RM', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21450, 981, '1493184', '2024-02-08 20:33:11', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Incorrect LOA -  Check with RMTo be redone', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21450, 982, '1493184', '2024-02-08 20:34:19', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical issues:  Please check with the RM for split between oil and gas from the underlying asset -- The BCA mentions that there is crude oil condensate as well as non -associated gas coming from the asset.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3414, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21450, 983, '1493184', '2024-02-08 20:35:33', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Analytical issues:  Project finance user guide clearly states that for a project, the emissions are to be for the asset - please check with the RM for details, or leave it as empty if no details are available.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
