INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21458, 1123, '1493184', '2024-02-25 21:46:18', 'Gurunathan, Akshay Ram', 'Scariah, Renjith ', 'Bel- Air is not relevant to the project directly -- its another oroejct by the same developer -- can we please mention thi that we are using Bel-Air as representative evidence. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21483, 873, '1493184', '2024-01-20 08:50:38', 'Mutepfa, Tashinga', 'Tarakji, Ranim', 'Minor comments:  PLease mention in comments again that locations are actually representative, so we know the domicile is only used due to the technical time lag with Munich Re', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
