INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21513, 882, '1551380', '2024-01-22 16:45:56', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Other minor issues - While I don''t necessarily agree with the answer selection given that it was mentioned in various reports that company is subjected to several carbon pricing regulations, I am ok if valid justification can be provided (e.g. Americas being key revenue contributor contributing 42.6% of 2023 revenue) but I would still want the applicable carbon pricing regulations to be captured in the Comments and/or Analysis in Outcome tab.  As per CDP (C11.1a), several carbon pricing regulation(s) have been mentioned. Alberta TIER - ETSCalifornia CaT - ETSEU ETSGuangdong pilot ETSKorea ETSOntario EPS - ETSTianjin pilot ETSAs per Annual Report (Page 22/140):Some of our operations are within jurisdictions that have or are developing regulatory regimes governing emissions of greenhouse gases (“GHG”), including CO2. These include existing coverage under the European Union Emission Trading System, the California Cap-and-Trade Program, Chi', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21513, 884, '1551380', '2024-01-23 07:25:05', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Other minor issues - please amend sentence "However, as the assets are spread only between USA and International, without specific countries, Global Average is selected." Company has provided the information in Annual Report actually. Refer to page 32/140 where they provide descriptions of the properties used by the company''s five business segments. "Our Americas segment operates from approximately 450 production and distribution facilities in North and SouthAmerica"; "Our Asia segment operates from approximately 300 production and distribution facilities within the region"; "Our Europe segment operates from approximately 210 production and distribution facilities in Europe"; and "Our Middle East and India segment operates from approximately 15 production and distribution facilities throughout the region".You can say "as assets are spread across the globe, Global Average is selected." ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21513, 885, '1551380', '2024-01-23 07:29:33', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Other minor issues - What is the rationale of selecting "High <=70%"? I don''t see any reason provided. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21586, 905, '1489063', '2024-01-25 11:05:05', 'Masarin, Lisa', NULL, 'If these are considered representative, please provide the MunichRe report as ad-hoc commentary.  It is hard to tell where those three locations are, and I would expect more known locations.Any chance we can review their routes and see which airports they maintain aircraft at, and perform a MunichRe assessment like that?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
