INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21595, 829, '1599218', '2024-01-15 13:44:31', 'Masarin, Lisa', 'Baran, Ewa', 'Analytical aspects - please rather use "3. Yes - Planned change in production operations: Improved efficiency of equipment(e.g. Electrifcation of operating assets / New Technology)" and state the answer is to provide benefit of the CCGT technology, which is more efficient than traditional gas plants. Reflect this into the CRA analysis as well', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
