INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21665, 831, '1599218', '2024-01-16 17:20:09', 'Davies, Krista', NULL, 'Accuracy of CRQ - last year this question was set as "Very high". Why has the answer changed? Unless you have a breakdown of revenues by types of product sales that helps you justify the change, do not change further. The 2023 annual report states that EU taxonomy-aligned revenues are 16.5% - page 41 of consolidated statement https://www.siemens.com/global/en/company/investor-relations/events-publications-ad-hoc/annualreports.html', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21665, 832, '1599218', '2024-01-16 17:22:04', 'Davies, Krista', NULL, 'Accuracy of CRQ - why have you set no additional policies in the next 10y? There is a carbon price in China covering power generation, hence the Client will be impacted too. Please also note the sovereign policy rating is "Policy measures in place"', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
