INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21665, 929, '1599218', '2024-01-29 14:21:18', 'Davies, Krista', NULL, 'Accuracy of CRQ - how did you determine the current level of target 1? It does not match the sum of emissions as per Q5.4', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21673, 1061, '1575987', '2024-02-20 04:52:45', 'Pal, Aditya', 'Roy, Devika Rose', 'Please say that Fertilizer company are not part of NZ sector. Due to issue with ISIC it is showing as Mining ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3412, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21673, 1062, '1575987', '2024-02-20 04:54:08', 'Pal, Aditya', 'Roy, Devika Rose', 'Urea production facilities are covered under the Australian Safe guard mechanism (Standard baseline).  Please find the prescribed production variable and default emission intensities published by the Australian government under the Safe guard Mechanism attached.  (Baselines for financial years commencing on or after 1 July 2023 (cleanenergyregulator.gov.au). https://www.dcceew.gov.au/climate-change/publications/safeguard-mechanism-document#:~:text=The%20Safeguard%20Mechanism%20and%20National%2creport%20and%20manage%20their%20emissions.There are existing carbon policies which are expected to continue', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21679, 1085, '1551380', '2024-02-22 04:06:50', 'Waclawska, Kamila', NULL, 'Other minor issues - Answer selection is "Policy measures are currently in place and expected to continue" but not very clear on what policy measures are in place and impacting client. Same for analysis in outcome tab. Analysis mentioned "Policies are currently in place in China and are expected to continue to impact the entity" but no details provided. We need to be more specific so that CA/RM is able to address those policies measures in BCA. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21679, 1086, '1551380', '2024-02-22 04:11:02', 'Waclawska, Kamila', NULL, 'Other minor issues - I would also add the Group''s 2022 Annual Report.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21679, 1087, '1551380', '2024-02-22 04:21:15', 'Waclawska, Kamila', NULL, 'Other minor issues - I would add information found in Group 2022 Annual Report here. This is also to justify that we have already looked at the AR.Information can be added here:2022 AR Page 81 - mention that although company does not provide emission data in report, it mentioned that the company has taken measures to reduce carbon emissions and the amount of emissions reduced for the year was 518,393 tons CO2e.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21686, 1173, '1493184', '2024-02-29 19:14:11', 'Pal, Aditya', 'Roy, Devika Rose', 'Accuracy of CRQ:  PLease enter the right business - this isnot a commodty trader -- refer to BCA Part 2 or CDP', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21686, 1174, '1493184', '2024-02-29 19:16:32', 'Pal, Aditya', 'Roy, Devika Rose', 'Analytical issue:  As epr comments,  carbon tax in Singapore covers only power and manufacturing, then how is this company affected by it ? Please edit to expected in 2 years', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
