INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21687, 1128, '1489063', '2024-02-26 16:07:53', 'Pal, Aditya', 'Roy, Devika Rose', 'Can we add some details around the project (From BCA p2) to help understand the nuace of this CRA.	ExxonMobil is selling its 100% equity interest in MPN (the “Acquisition”), through a competitive bidding process where SCB is also acting as M&A sell-side advisor. Seplat (Standalone CG – 6A, Post country cap – 9B) – a long-established and successful indigenous O&G producer in Nigeria has been selected as the preferred bidder for this Acquisition.	This opportunity is being pursued by Seplat (“Sponsor” or “Shareholder”) and a newly Nigeria incorporated 100% owned SPV Seplat Energy Offshore Limited shall acquire a 100% ownership interest in MPN. Seplat being an indigenous O&G player, complies with Nigerian local content requirements.	Seplat intends to fund the Acquisition through a combination of senior debt, junior debt and sponsors’ equity. The senior debt will consist in an up to US$550m term loan with a 6-year tenor from the signing d', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21687, 1129, '1489063', '2024-02-26 16:12:06', 'Pal, Aditya', 'Roy, Devika Rose', 'Why have we not taken Seplat as the LoA for this transaction, who have sustainability and TCFD reports? As per PEF user guide1.LOA is to be confirmed by the Project team/GCM/RM as first preference for choosing LOA. 2 follow-ups to be done2. If no confirmation is received, LOA is determined on the basis of the entity which has operational control over the E&S/climate risk policies of the project 3. When unsure with the operational control, consider the sponsor which has financial control of the oil/gas reserves as the LOA					', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21687, 1146, '1489063', '2024-02-28 08:16:50', 'Pal, Aditya', 'Roy, Devika Rose', 'This isn''t really a physical impact - we are quoting about potential militant action as a result of physical impacts (so 2nd order) and these comments seems vague and assumption based. This is not really a company assessment of the risk, but more a horizon scanning exercise.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21687, 1147, '1489063', '2024-02-28 08:18:40', 'Pal, Aditya', 'Roy, Devika Rose', 'could classify this as a non-quantifiable short term target.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21687, 1148, '1489063', '2024-02-28 08:21:51', 'Pal, Aditya', 'Roy, Devika Rose', 'Can you provide some evidence / analysis as to why there is not going to be impact? I would tend to agree with you, but we need to back it up.e.g. Can we estimate the saving in Co2e and compute a shadow carbon tax pricing and see that as a % of their revenue / profits? ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
