INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21692, 840, '1489063', '2024-01-17 10:13:10', 'Komjati, Dalma Beatrix ', 'Adebajo, Taigh Olatomiwa', 'Can we understand why the company is defaulting? Given it is a trading arm, the impact should be lower than others in the sector and default is drastic', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3428, 'GTR3', 'esg_navigiator', '01');
