INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 959, '1660361', '2024-02-07 08:31:08', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'LOA - Legal Entity should not be selected here. All CDP disclosures and Sustainability reports are pertaining to the Group.Please also include the following sources - Sustainability Report 2023, Climate Action Report 2021, Sustainability Data Supplement.On alignment to TCFD, Refer to Sustainability Data Supplement pg 24 which gives a detailed breakdown of Bluescope''s adherence to TCFD recommendations and the location of relevant disclosures in its Sustainability Report 2023 and Climate Action Report – released in September 2021.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 961, '1660361', '2024-02-07 08:50:31', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'Operating locations are not representative of the entity. The locations listed are for the Parent Group.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 963, '1660361', '2024-02-07 09:15:20', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'Option selected does not correspond to comments.Refer to SR pg 70Our proposed actions to address identified risks- Climate physical risk assessment performed by climate risk experts to assess the exposure of our sites to projected climate-related hazards.- Results from climate physical risk assessment and scenario analysis in risk management processes and Capital Allocation Framework.- Plant design specifications, asset and site maintenance plans, and sustaining capital and repair and maintenance budgets consider acute or chronic impacts of climate change and additional adaptation measures.- Engage with key suppliers to support better insight into specific supplier physical risk exposures and vulnerabilities that may impact BlueScope operations.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 965, '1660361', '2024-02-07 09:50:45', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'Agreed with the option selected, as the manufacturing and marketing operations in Malaysia (85% of revenue) will not be impacted since Malaysia does not have an existing carbon price, nor has it set a future date for implementation. However, 15% of revenue comprises of exports to South Africa, Thailand, Singapore, United States and New Zealand. As such, please insert a comment accordingly as additional costs may be incurred in these markets on steel imports. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 967, '1660361', '2024-02-07 10:11:31', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'Noted that the company''s financial year end is June. Also, the latest year''s figures (FY22/23) has not been captured here. Please move the figures down by a year (2022 to 2021, 2021, to 2020, etc) so that the latest year numbers can be reflected as well and insert comment accordingly.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21708, 968, '1660361', '2024-02-07 10:24:05', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'The numbers here look wrong. Please refer to SR 2023 pg 44 for the targets and progress.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21709, 1080, '1489063', '2024-02-21 14:21:06', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'the 2015 waster recovery system is too old to be described here as a roadmap or transition plan. I has been implemented and is nearly 10yr old - we should have more focus on the forward looking plans.Additionally - upgrading the plant to burn alternatives, doesn''t mean that more alternative fuels have been employed necessarily. Do we have info on what alternatives it is going to use in the 30% shift?can you explain more the FBT and VFD methods if this is the evidence for production operation changes? I don''t see how these will drastically change the emissions amount.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21709, 1081, '1489063', '2024-02-21 14:25:01', 'Radhakrishnan, Gowtham ', 'Adebajo, Taigh Olatomiwa', 'I think this is hard ot say - without knowledge of the alternative fuels to be used, or a deepened understanding of the supposed technology improvements and how much CO2 they can actually save, then we cannot say this is a meaningful impact.Would change this to no until more evidence is sourced.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1109, '2009422', '2024-02-23 13:28:32', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ: please be consistent, change the answer, there is no project.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1111, '2009422', '2024-02-23 14:09:01', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of the CRQ: please update your answer based on page 196 of the sustainability report.Please make sure you use all the countries from the table.For "other countries" mentioned in the Table (sustainability report pg. 196) please use the global average from the heat map table.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1112, '2009422', '2024-02-23 14:44:26', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ: Your commentary is rather a theoretical statement implying the impact of natural hazards in supply chain. How does the HMA assess the physical risk throughout value chain i.e: in material sourcing, production, consumption and disposal/recycling processes. Please provide evidences on this one if there are any and add it in your commentary, otherwise amend your answer.Accuracy of CRQ: What are the factors that can impact the supply chain?Please either provide evidences on the physical risk impact in the supply chain or consider in your answer only direct emission and remove the supply chain.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1115, '2009422', '2024-02-23 15:06:38', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ: These are the mechanism impacting the client as mentioned in the CDP: BC carbon taxEU ETSSweden carbon taxPlease consider them in your commentary.Furthermore the ETS has a financial impact of 190 million EUR up to 2026 (refer to CDP 2.3a). Please do consider it in your commentary and in the CRA analysis.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1116, '2009422', '2024-02-23 15:10:10', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', '.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1125, '2009422', '2024-02-26 13:53:59', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Analytical aspects: this information is available at page 42 of sustainability report. There is pie chart there were the sum of "Ordinary Portland cement", "Limestone cement" and "Multi-component cement" correspond to clinker in our data gathering tables/ Fly Ashes and slag cement are available in the chart as well. Please sum it up and update the answer and comment.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3418, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1126, '2009422', '2024-02-26 14:06:50', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ: Please amend the description to target 3 i.e Scope 3, "25% reduction in absolute emissions from purchased cement and clinker".Accuracy of CRQ:  Scope 1 and 2 "emission targets" are on intensity basis, while Scope 3 "emission targets" are at absolute emission. Please refer to page 37 of the sustainability report to update the table.CO2 reduction compared to base year 2020: Scope 1: –24% per tonne of cementitious material Scope 2: –65% per tonne of cementitious material Scope 3: –25% in absolute emissions from purchased cement and clinker.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21710, 1127, '2009422', '2024-02-26 14:19:11', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ: Please compute target 3, you have the absolute emission figures and the 2030 target (please refer to page 37 and 334 of the sustainability report).Accuracy of CRQ: please refer to page 334 to project the future emissions i.e Scope 1:  Specific net CO2 emissions per tonne of cementitious material Scope 2:  Specific CO2 emissions from external electrical power and thermal energy production per tonne of cementitious materialand Scope 3: CO2 emissions from purchased materials', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1033, '1660361', '2024-02-14 07:20:04', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Recommend to add in a note that the company has endorsed initiatives however these are mainly driven by destruction and disruption to nature and biodiversity due to its business operations. Annual review (AR) pg. 39 Rehabilitating legacy areas in ArcelorMittal South Africa. In South Africa, in 2021, 13.4 hectares of land and 52 hectares of contaminated soil in legacy dams were remediated. To date, 211 hectares on land have been rehabilitated and 108 hectares under water. In addition, 290 hectares of the Thabazimbi iron ore mine have undergone rehabilitation. Work at this legacy site has translated into a rebound in biodiversity, including populations of antelope.AR pg 40 Biodiversity programme in ArcelorMittal LiberiaArcelorMittal Liberia and the Co-Management Committee of the East Nimba Nature Reserve (ENNR) signed a Memorandum of Understanding in 2022 to extend its existing support for biodiversity programmes and the conservation and ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3104, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1034, '1660361', '2024-02-14 07:48:35', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Combination of both Group and LE locations; if locations are not representative of entity''s risk profile, why is LE selected here?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1035, '1660361', '2024-02-14 08:02:48', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Minor point - on the source, please specify that it is the CAR 2 as the company has published multiple CAR in the past few years.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1036, '1660361', '2024-02-14 08:08:19', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Recommend to add in comment - with reference to BCA Part 2, the company utilises mainly coal and natural gas, in that order, as key sources of energy in its manufacturing operations.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3420, 'GTR3', 'esg_navigiator', '01');
