INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1042, '1660361', '2024-02-14 09:33:05', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Carbon credits - AR pg 24 For these residual emissions, which today we estimate will be 5%-10% of today’s emissions, we plan to buy high-quality offsets or launch projects to generate high-quality carbon credits that would not have happened without the company’s intervention.Carbon capture - AR pg 30 ArcelorMittal South Africa and Sasol have announced a partnership to develop carbon capture and utilisation (CCU) technology using process carbon produced at ArcelorMittal’s Vanderbijlpark Works plant and to advance the production of low carbon intensity steel using green hydrogen. pg 22 In Europe, we inaugurated Europe’s first carbon capture and utilisation facility at ArcelorMittal Ghent.Greening of energy mix - AR pg 30 In 2022, we agreed a strategic partnership with Greenko Group, India’s leading energy transition company, to develop a round-the-clock renewable energy project in India with 975MW of nominal capacity. The $0.6bn project w', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21711, 1043, '1660361', '2024-02-14 09:51:33', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'Overall, do not agree the impact will be meaningful. While Xcarb steel looks promising in terms of significantly lowering GHG produced during manufacturing, the price as compared to normal steel is very high and adoption rate is as such very low currently. Noted heavy investment ~USD150m into furthering this technology. In addition, much more significant work needs to be undertaken to replace energy source for manufacturing with renewable/less carbon intensive fuel and move away from mainly coal. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21717, 1095, '1551380', '2024-02-22 07:14:43', 'Leva, Aljaz', 'Adebajo, Taigh Olatomiwa', 'Other minor issues - please mention bulk (>90%) of the company''s products are exported and key export markets include Spain, Sweden, Netherlands, United States and Australia. Hence, any policy measures like carbon border tax implemented in these markets will have an impact on the company as well. Put this in analysis in Outcome tab as well. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21717, 1096, '1551380', '2024-02-22 07:18:24', 'Leva, Aljaz', 'Adebajo, Taigh Olatomiwa', 'Other minor issues - Frontline team has obtained further information from client. Please refer to information provided when previous RT is being closed. I have forward email to Aljaz.  Please update all relevant questions with information provided. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21719, 895, '1489063', '2024-01-24 16:13:57', 'Ptasinska, Dorota', 'Adebajo, Taigh Olatomiwa', 'This should render the client as Amber at minimum, due to standards.Referring to Michal''s email PROCESS NOTE: Defaulting PD in Q4.5 (issue related to BRAG generation logic) - WorkaroundWorkaround:Specific wordings to be added to outcome section (Climate Risk Grading (BRAG) Analysis)‘Climate Risk Grading should be AMBER instead of Green – According to Climate Risk Grading Framework, a minimum Grading of AMBER should be assigned to client that experiences a default over the first 5 years in the 2-degree orderly scenario as per transition risk model output. Due to system constraints, Green rating is shown which is incorrect.’', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3428, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21727, 913, '1551380', '2024-01-26 12:28:49', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Other minor issues - Emissions intensity is missing. I can see numbers included in other CRAs using same report.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3507, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21727, 914, '1551380', '2024-01-26 13:01:07', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Other minor issues - For Target 2, why is it blank? It should be [(51+7) - (72+11)] / (72+11) = -30% (or 30% reduction). Refer https://reports.shell.com/energy-transition-progress-report/2022/our-performance/absolute-emissions-progress.html or pg 97 of annual report.Refer to email sent separately.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21735, 970, '1493184', '2024-02-07 16:36:53', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Accuracy of CRQ:  CDP report is avail for Group and scored D	https://www.cdp.net/en/responses?queries%5Bname%5D=petronas', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3102, 'DND3', 'esg_navigiator', '01');
