INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21735, 1008, '1493184', '2024-02-12 18:45:10', 'Waclawska, Kamila', 'Popielarczyk, Dagmara', 'Apologies I had one more question here:As it is a global integrated O&G company, assets could be located all over the world, -- even if there are no carbon policies in Malaysia, specific upstream assets in countries with carbon policies can lead to policy measures which impact the Group. https://www.petronas.com/integrated-report-2022/assets/pdf/by-section/4.%20PETRONAS%20Integrated%20Report%20(PIR)%202022%20-%20PETRONAS%20An%20Overview.pdfCan you please check adn confirm if there are assets in developed countries as well which could lead to polciy measures in near term/or already existing ?', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
