INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21849, 1192, '1660361', '2024-03-04 05:44:02', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Since this is an asset financing case and given the location of the asset (in Hong Kong), insurance is likely to be available. Noted that we have a confirmation from Credit analyst on insurance coverage against both damage and business disruption (comment on verified by SGS Hong Kong is irrelevant).', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21849, 1193, '1660361', '2024-03-04 05:58:18', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'PCAF score should be 4 instead of 5', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3504, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21854, 1059, '1489063', '2024-02-19 17:02:30', 'Komjati, Dalma Beatrix ', 'Delaney, Peter Jared', 'Basis the above, I am not sure how the changes can be largely meaningful to reduction of emissions. The evidence quoted seems to indicate a new profit line, but that does not change emissions drastically.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
