INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21857, 868, '1599218', '2024-01-18 16:33:42', 'Mutepfa, Tashinga', NULL, 'Accuracy of CRQ - this not a project actually - the scorecard that is being used is Mid Corp and when you look at the details of the term loan granted it states "For working capital and other general corporate purposes, including, without limitation, for Capital Expenditures, acquisitions, letter of credit issuances, Restricted Payments, refinancing of Indebtedness and any other transaction." - please change', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3103, 'DND3', 'esg_navigiator', '01');
