INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21862, 1053, '1575987', '2024-02-17 16:57:15', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'If most sales is to companies in China - Why are we not using China''s heat map', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3216, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21862, 1088, '1575987', '2024-02-22 05:01:38', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'The company is the procurement arm of the group engaged in manufacturing of Iron and Steel. Manufacturing facilities are located in China. Application of ETS by China on Iron and Steel can have negative impact on PAT margins available for the company. - Consider China ETS related policy measures. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21862, 1091, '1575987', '2024-02-22 06:05:19', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'I understand that the company has not elaborated on how it will reduce emissions from it metal division. No quantitative details have been provided , hence we cannot consider it as meaningful impact . - Green Building and Green construction has nothing to do with the business of legal entity or Metal division of the group  ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3512, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21862, 1093, '1575987', '2024-02-22 06:39:36', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'Green building and construction does not have relevance with respect to the business of legal entity.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21862, 1094, '1575987', '2024-02-22 06:40:27', 'Waclawska, Kamila', 'Delaney, Peter Jared', 'Please make changes appropriately ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3513, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21868, 1138, '1551380', '2024-02-27 06:14:42', 'Waclawska, Kamila', NULL, 'Other minor issues - Answer selection and comments seem contradictory. ETS only applies to CO2 emissions from the power sector currently and it is also mentioned that additional costs for firms in 2-5 years.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
