INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21877, 834, '1575987', '2024-01-17 05:08:05', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', 'Please confirm with Credit analyst regarding insurance coverage for the project.  We need specific confirmation in case of project finance. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21877, 835, '1575987', '2024-01-17 05:09:05', 'Gurunathan, Akshay Ram', 'Gowri, V Kavya', 'Policy measures will not apply for a Wind power project. UPDATED: please set no additional policies in the next 10y. This is a wind project, and there is no regulatory pressure to stop wind-power', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
