INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21898, 843, '1599218', '2024-01-17 13:43:08', NULL, 'Kumar, Ajith', 'Accuracy of CRQ - please use "Others". Transmission refers to transmission of electricity generated upstream by power plants. This project is for construction of a gas-pipeline, which connects the gas infrastructures to the power plants', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3404, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21898, 844, '1599218', '2024-01-17 13:45:51', NULL, 'Kumar, Ajith', 'Accuracy of CRQ - can you please reflect the sovereign rating under the carbon pricing? The carbon pricing in Mexico will not cover directly the project''s operations, but will be taxing power generation as well, i.e., the plants this pipeline serves - hence we need to reflect the second order risk. Please make this clear, build a narrative around it both in the commentary and the CRA AnalysisUPDATE: please also reflect the carbon pricing in the rating', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
