INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21901, 927, '1599218', '2024-01-29 10:58:04', NULL, 'Tarakji, Ranim', 'Accuracy of CRQ - I do not understand why you have selected no assets impacted by Physical risk. I understand the properties on the site will be destroyed but the land will be reused to construct new properties, which will then be sold and be exposed to physical risk. Please amend answer option to A.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 21902, 1011, '1599218', '2024-02-13 09:44:56', 'Mutepfa, Tashinga', 'Adebajo, Taigh Olatomiwa', 'Accuracy of CRQ - ref to Risk 1 under C2.3a in CDP. They clearly mention they face carbon pricing in South Africa, through South Africa''s carbon tax. They also provide the financial impact of it and the cost to respond. Please change answer choice to E and add the reference to South Africa. Please also add that Risk #8 under C2.3a in CDP mentions the possibility of a carbon pricing in Senegal by 2025 and potentially also in Nigeria. All these data points are missing from your analysis - please ensure these are added both in Q4.2 questionnaire and in the CRA Analysis. Additionally, at page 47 of the annual report, you have also the breakdown of emissions S1 by location. Also cite these ones to show the materiality of the carbon pricing initiatives on the client', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
