INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22177, 1229, '1551380', '2024-03-18 04:26:42', NULL, 'Banerjee, Monalisa', 'Other minor issues - please add the additional description provided in BCA Part 2. From BCA Part 2:Eternal International (HK) Limited (“EIHK”), is the wholly owned sourcing arm of Eternal Asia Group, which is mainly engaged in shipping, warehouse and payments routed through HK, including HK/overseas purchases. It is a key service centre for Eternal Asia’s operation. EIHK handles around 60% of the import volume of the EA, which is the major import entity.  ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3405, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22177, 1230, '1551380', '2024-03-18 05:54:36', NULL, 'Banerjee, Monalisa', 'Other minor issues - given that ETERNAL INTERNATIONAL (HK) LIMITED is 100% owned by Eternal Asia Supply Chain Management Ltd, the details provided in BCA Part 2 of Eternal Asia Supply Chain Management Ltd should also applicable.Please mention additional information has been provided in BCA Part 2 of Eternal Asia Supply Chain Management Ltd and use the information for this CRA.Extract from BCA Part 2 of Eternal Asia Supply Chain Management Ltd:For Gross Physical Risk, we communicated with client for below aspects. Client has acknowledgement of physical risk hazards on their business operations. Eternal Asia has six logistics bases located in Shanghai, Dalian, Changsha, Shenzhen (two), Yangshan. All of them are located in well-developed area, such as economic development zones, Logistics park or bonded port area, with minimal physical risk hazards (such as floods, storms, wildfires, heat stress, sea level rise, etc.) and good climate. The', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3301, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22177, 1231, '1551380', '2024-03-18 05:54:48', NULL, 'Banerjee, Monalisa', 'Other minor issues - given that ETERNAL INTERNATIONAL (HK) LIMITED is 100% owned by Eternal Asia Supply Chain Management Ltd, the details provided in BCA Part 2 of Eternal Asia Supply Chain Management Ltd should also applicable.Please mention additional information has been provided in BCA Part 2 of Eternal Asia Supply Chain Management Ltd and use the information for this CRA.Extract from BCA Part 2 of Eternal Asia Supply Chain Management Ltd:For Gross Physical Risk, we communicated with client for below aspects. Client has acknowledgement of physical risk hazards on their business operations. Eternal Asia has six logistics bases located in Shanghai, Dalian, Changsha, Shenzhen (two), Yangshan. All of them are located in well-developed area, such as economic development zones, Logistics park or bonded port area, with minimal physical risk hazards (such as floods, storms, wildfires, heat stress, sea level rise, etc.) and good climate. The', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3304, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22180, 1160, '1489063', '2024-02-28 13:22:27', NULL, 'Banerjee, Monalisa', 'Cand we analyse the make-up of the product sales from CEMCOA. Whilst they trade cement, they also trade less carbon intensive products, such as gypsum, limestone etc.. and so would be interesting to understand what their make-up of high emitting products is.Additionally, they have a more 2nd order impact from emissions than direct risk from trading the goods, so I would maybe argue to bring down to a "High" rating, given they won''t have the same risk of carbon taxes and policy,', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
