INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22375, 1273, '1551380', '2024-03-21 17:13:04', 'Radhakrishnan, Gowtham ', 'Scariah, Renjith ', 'Other minor issues - Please update future outlook based on latest policy tracker. Future Outlook:The climate bill, titled the "Climate Change Response Act," has been passed in January 2023 and is used to establish a carbon fee system for large emitters and set a goal of reaching net-zero emissions by 2050. The approved version of the act establishes a goal of reaching net-zero carbon emissions in Taiwan by 2050, meaning that the amount of greenhouse gases emitted would be no more than the amount removed from the atmosphere. To reach the net-zero goal, the act will introduce in phases a mechanism to collect carbon fees on "direct", and later "indirect" emissions from entities whose emissions reach a certain threshold. The system will likely take effect from the beginning of 2024, and in its initial stage impose fees on companies and other entities in Taiwan with annual carbon dioxide emissions of at least 25,000 tonnes.Meanwhile, all rev', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
