INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22454, 1527, '1551380', '2024-04-30 05:47:42', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'LOA - I am assuming CSCD refers to China State Construction Development Holdings Limited? What is the relationship between CSCD and Company (PT China Construction Yangtze River Indonesia)? To use the report of CSCD, we will need to ensure that the report used covers the company we are assessing? Did we confirm that and has this been agreed with business team? Looking at the Group Org Chart, I am of the view that report for CHINA STATE CONSTRUCTION ENGINEERING CORPORATION LIMITED (listed in Shanghai) should be used.  Also, CSEC 2023 Interim report is not listed as source. Lastly, please ensure that all the long names have been mentioned before abbreviations are used (i.e. CSCECL, CSEC and CSCD) as it can get confusing. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22454, 1528, '1551380', '2024-04-30 07:53:50', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'Other minor issues - Shouldn''t comment relating to CRE be used?Present Situation:The Indonesian government is focused on reducing cement industry emissions by lowering clinker-to-cement ratio. Voluntary guidelines have been developed to encourage the use of blended cement by using clinker substitutes such as fly ash, and by using biomass and other alternative fuel and raw materials (AFR) in the cement production process.Regulation 36/2005 under Law No. 28/2002 sets energy standards for buildings (SNI) concerning energy audit procedure. Energy Performance Certificates are mandated for building users whose energy consumption is beyond 6,000 toe/a. These users are required to conduct an energy audit and implement its recommendation, and report result of the implementation energy measures to the Government. Compliance with energy conservation and efficiency regulations for large buildings is reinforced through the issuance of building permi', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22454, 1529, '1551380', '2024-04-30 08:41:38', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'Other minor issues - projects are all located in Indonesia as per BCA part 2. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
