INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22454, 1531, '1551380', '2024-04-30 09:19:31', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'Other minor issues - Comment is not exactly appropriate. Please change to below.Source: BCA Part 2 and ESRAPT CHINA CONSTRUCTION YANGTZE RIVER INDONESIA (“CCYRI”) is a joint venture company between China Construction Third Engineering Bureau Company Ltd (”CSCEC B3”) and PT Boxin Konstruksi Indonesia (a local construction company established in May 2017). CCYRI officially began its commercial operation in June 2019 and specializes on basic infrastructure construction such as marine engineering, dredging & reclamation, road & bridge, railways, airports, complete plant, and other works.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
