INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22454, 1544, '1551380', '2024-05-02 01:51:03', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'CRA summary analysis - I am putting comment here instead of in Q2.12/Q2.13 so that this will not be missed. The amendments to Q2.12/Q2.13 need to be reflected in outcome tab as well. Physical Risk Analysis is still saying "PCCYI''s EPC expansion network also spans overseas in Central Asia, Africa, Southeast Asia, Latin America etc, through nine regional marketing centres with over 40 country specific project teams. CSCECL has also built 3/4 of key airports and 1/3 of urban utility tunnels in China, it was also reported 1 out of every 25 Chinese lives in the house built by the group. As such, global average is leveraged here based on SCB''s in house heatmap ranking of sovereign nations."', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
