INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22461, 1655, '1489063', '2024-05-28 13:57:09', 'Pal, Aditya', 'Davies, Krista', 'From reading their website - they appear to be a downsteam entity of the steel making process and instead manufacture steek roofing and corrugated sheets / building solutions. Instead of using blast furnaces to actually make steel.Hence, would reattribute this to be a Downstream answer option.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3410, 'GTR3', 'esg_navigiator', '01');
