INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22465, 1696, '1489063', '2024-06-03 15:43:17', 'Pal, Aditya', 'Adebajo, Taigh Olatomiwa', 'I don''t understand how this can be a high-reliance entity on emissions / carbon products. They are a trader of tractors and heavy equipment, so not reliant on any manufacturing process themselves and not trading a fossil commodity.I would argue this is low reliance and don''t think placement as a trading company makes it high - this is a broad category and contains many types of traders, so needs to be considered individually.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
