INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22837, 944, '1551380', '2024-02-02 08:13:42', 'Leva, Aljaz', NULL, 'Other minor issues - please include additional information on group given that company is a procurement arm of the Group. Renewable Feed Singapore PTE. LTD. engages into trading of palm oil mill effluent and used cooking oil. They mainly act as the procurement hub for Group''s plants in China and future plant (in construction) in Malaysia where waste vegetable oils and animal fats are used as raw materials to produce biofuels including Hydrotreated Vegetable Oils (HVO) and Sustainable Aviation Fuel (SAF). ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3401, 'GTR3', 'esg_navigiator', '01');
