INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22881, 969, '1599218', '2024-02-07 16:13:10', 'Gurunathan, Akshay Ram', 'Banerjee, Monalisa', 'Analytical aspects: I understand what you mean with this - the project will help the Government reach its own NZ targets given the renewable energy sourced and you align the project''s targets to the Government. But think about the implications of this approach - what kind of emission progress will we be monitoring? Are we monitoring Turkey''s emissions??? Q5.5.1 is now blank, but how will you be filling it up going forward when it is no longer NTB? Please, remove these targets', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
