INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22903, 1684, '1551380', '2024-05-31 15:50:37', 'Pal, Aditya', 'Roy, Devika Rose', 'Target progress is incorrectly matched. It should be:Target 1 - 128.26% (it is mentioned in report that "In 2023, we have achieved a reduction of emissions of CO2 equivalents (CO2e) of about 59% in Scopes 1 and 2 against 2019. This means we reached our milestone for 2025 two years earlier than anticipated".)Target 2 - 63.33%Target 3 - 95%Target 4 - 96.43%', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
