INSERT INTO mstr.advisor_memo_report VALUES (NULL, 22911, 1686, '1599218', '2024-05-31 16:35:25', 'Pal, Aditya', 'Roy, Devika Rose', 'COMMENT1: Accuracy of CRQ - this is not correct. Please let''s do a bit of research as to whether a Client is impacted by carbon pricing. It took me less than 10mins to find - go to the annual report and you will find the following. I appreciate if you can be always careful when looking at carbon pricing, especially for clients where we know a carbon pricing system is in place "The Group received emission rights free of charge from the government under a domestic Greenhouse Gas Emission trading scheme. The Group must submit an equal quantity of emission rights in response to actual emissions. The emissions allocated free of charge are accounted for using the net debt approach. Accordingly, when actual emissions exceed the amount of emission rights received and held, a provision is recorded. The rights purchased additionally from third parties are measured at acquisition cost"COMMENT2: please also ensure the following is reported also in ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
