INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23073, 1187, '1551380', '2024-03-01 13:44:49', 'Pal, Aditya', 'Brodzicka, Elzbieta', 'Please also add the targets in words in Comments. It would be easier for the CA to understand. You can make reference to page 3-4 of China Gas Carbon Neutrality Action Plan 2022 below.Three Unswerving Commitments: To reduce the GHG emission intensity by 50% from the level of 2021 by 2030 To peak carbon dioxide emissions by 2030To achieve carbon neutrality in 2050Please also add in analysis in Outcome tab that proposed Additional Analysis to "discuss with client on setting long term targets" is not required given that there is a long time target to achieve carbon neutrality in 2050 at group level. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
