INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23097, 1221, '1575987', '2024-03-17 17:31:43', 'Radhakrishnan, Gowtham ', 'Joardar, Abhisek ', 'Pls use vessel level data only . As per bca, 	The newbuild Suezmax tanker will be dual fuel and shall be capable of running on LNG (i.e. dual-fuel LNG). According to Clarksons, the vessel will be fitted with Eco-Electronic Engine Modern, and Energy Saving Technologies (EST', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23110, 1222, '1551380', '2024-03-18 01:27:26', 'Komjati, Dalma Beatrix ', NULL, 'Other minor issues - Agree that there is no policy measures for trading companies but worth mentioning that China''s ETS is expected to gradually expand its sectoral coverage to other high-emission industries including pulp and paper. This would potentially impact the paper industry. You can add this in the first sentence.Example:The entity is merely a paper trading company, and is therefore not currently covered by any sector specific policies in . Nevertheless, given that China''s ETS is expected to gradually expand its sectoral coverage to other high-emission industries including pulp and paper, the industry can potentially be impacted if any change in policy is announced. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
