INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23113, 1218, '1493184', '2024-03-15 17:12:43', 'Radhakrishnan, Gowtham ', 'Jen, Yvonne ', 'Minor issues:  Self-insurance is not a form of insuracne -- what does it cover ? Mark as No. Text clearly says:Accordingly, in the event of a material incident, we would have to meet our obligations without access to material proceeds from third-party insurers. We have in the past incurred adverse impacts from events, such as Hurricane Ida in 2021. We may, in the future, incur significant losses from different types of hazard risks that are not insured with third-party insurers, potentially resulting in a material adverse effect on our earnings, cash flows and financial condition', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3305, 'PRA3', 'esg_navigiator', '01');
