INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23701, 1871, '1551380', '2024-07-11 15:28:38', 'Ciszewski, Michal', 'Waclawska, Kamila', 'CRA summary analysis - Please replace Climate Risk Grading (BRAG) Analysis with wordings below. MULLER & PHIPPS (PAKISTAN) (PVT) LTD (“MPP”) is the largest and oldest distribution company in Pakistan. The company distributes and sells healthcare, consumer, pharmaceutical, and telecommunication products. MPP does not publish any report on Climate Risk on public source and there is no report available at Group level (Getz Corporation) as well based on online search which can be used for assessment. Despite limited disclosure on climate related risk, MPP obtained a Green grading (no change from previous CRA) as gross transition risk is assesed as low with no additional policy measures expected in the next 10 years which would have material impact on company’s financials or business model. Based on limited information found on website on Corporate Social Responsibility, the company uses low emission vehicles as much as possible to reduce it', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3501, 'CTP3', 'esg_navigiator', '01');
