INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23852, 2131, '1599218', '2024-09-24 16:18:26', 'Pal, Aditya', 'Muszynska, Klaudia', 'as per email - you have used Group data for baseline and target, meanwhile you have used entity-level for current emission levels. this just skews the results and is not correct. I prefer we rather say are not able to monitor than mixing group and parent data ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 23894, 1965, '1660361', '2024-07-30 08:28:13', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'Improper selection of answer choice - comments do not correspond to "planned change in product mix" answer selected. Also noted no such initiative in the ESG report or website. Since this is still a building under construction, we can revisit this section again once the project is completed and we have a better sense of the enhancements in line for this building. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
