INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24171, 2020, '1599218', '2024-08-16 17:48:43', 'Pal, Aditya', 'Harsh, Shubham', 'Accuracy of CRQ - please use the 2023 TCFD report - it was published in Feb 2024 and should have used in this CRA. You will have plenty info on physical risk, scenario analysis, latest emissions, etc https://www.prismjohnson.in/wp-content/uploads/2024/02/Prism-Johnson-Limited-TCFD-Report-February-2024.pdf', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3101, 'DND3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24171, 2021, '1599218', '2024-08-16 17:49:21', 'Pal, Aditya', 'Harsh, Shubham', 'Accuracy - please check if this can be answered with the TCFD report', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3302, 'PRA3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24171, 2022, '1599218', '2024-08-16 17:52:40', 'Pal, Aditya', 'Harsh, Shubham', 'Analytical - target 1 is an emission intensity target Kg of CO2 per ton of cementitious product. This is a quantifiable target as well - please change the answer as wellAnalytical - both target 1 and 2 have target year 2024-25. Why for target 1 you have added 2024 as target year meanwhile 2025 in target 2? Please align to 2025', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3509, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24171, 2023, '1599218', '2024-08-16 17:57:22', 'Pal, Aditya', 'Harsh, Shubham', 'Analytical - the 2021 baseline is available in the 2021-2022 Sustainability Report. Please, as a reminder, for the targets, if the baseline is not available in the current report, go back and check previous reports (https://www.prismjohnson.in/wp-content/uploads/2023/01/PJL-Sustainability-Report-2021-22.pdf). The figure for target 1 will be - baseline: 650 and target: 615. For the current figure, please note that has been recently disclosed the 2023-2024 Sustainability Report (https://www.prismjohnson.in/wp-content/uploads/2024/08/Prism-Johnson-SR-2023-24.pdf) - I would not have asked you to check that, but since you are doing the changes, please use the latest available data (616)', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3510, 'CTP3', 'esg_navigiator', '01');
