INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24194, 2135, '1660361', '2024-09-25 10:29:40', 'Joardar, Abhisek ', 'Harsh, Shubham', 'As mentioned on Teams, the concerned properties can be found in the ESRA. Please reach out to the RM and see if you can get their locations for risk assessment. Same for the question on physical risk mitigation (insurance) please.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
