INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24293, 2100, '1493184', '2024-09-12 19:34:47', 'Radhakrishnan, Gowtham ', 'Komjati, Dalma Beatrix ', 'Analytical issues: PLease detail what exactly is the product mix improvement for which the option is chosen --- the company operates and builds pipelines and storage terminals and some renewable infra. ', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3511, 'CTP3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24344, 2051, '1660361', '2024-08-29 03:27:53', 'Leva, Aljaz', 'Muszynska, Klaudia', 'Do not understand explanation provided, the client operates only in Bahrain as a importer and retailer of Hyundai vehicles. Why are its key operating locations (showroom and service center/garage in Bahrain) not deemed representative?Also, it has a high level of inventory, hence assets would also be affected by physical risk events.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3202, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24344, 2052, '1660361', '2024-08-29 03:49:43', 'Leva, Aljaz', 'Muszynska, Klaudia', 'Do not agree with this - the client is an exclusive distributor of Hyundai vehicles in Bahrain. While the ETS in Korea may lead to increased costs of production in Korea, leading to increased cost of vehicles manufactured in Korea (by the way Hyundai has manufacturing locations in Singapore, Turkey, etc as well), the main driver of transition risk from policy measures should be Bahrain focused. Think of it this way - what do you expect the client to do on the transition risk trigger? (if we select this option (policy measures in place), auto transition risk trigger will come up) It operates solely in Bahrain and there is no regulatory policy on auto. Should regulatory policy kick in, the client can either distribute other brands (if Hyundai does not produce good electric vehicles) or it can simply start selling Hyundai electric vehicles. The client also needs to maintain its competitiveness currently with other distributors still sellin', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3425, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24345, 1799, '1489063', '2024-06-27 12:45:16', 'Pal, Aditya', 'Masarin, Lisa', 'I disagree that this should be a high rated reliance on emissions. The entity is not invovlded in the direct production of emissions and neither is the pharmaceutical industry to a great extent. Whilst there might be some reliance on shipping of air freighting, there are other easy alternative transportation means to change to Green / renewable usages and so believe the reliance is Low for this client. Please change.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3402, 'GTR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24351, 1770, '1489063', '2024-06-18 14:31:11', 'Mutepfa, Tashinga', 'Muszynska, Klaudia', 'To adjust physcial risk analysis section and include where needed', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3201, 'GPR3', 'esg_navigiator', '01');
INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24486, 2058, '1551380', '2024-09-01 12:52:52', 'Ptasinska, Dorota', 'Popielarczyk, Dagmara', 'Where does the information "The Client is a trading arm for the Group" come from?BCA part 2 says "Sinopec Century Bright Capital Investment (Middle East) Limited (Sinopec ME) is a treasury/borrowing arm of SINOPEC Group", "Sinopec ME is a company limited by shares, registered, and incorporated in Dubai International Financial Centre in 2008. The company’s registered office is at 1002, Level 10, Liberty House, Dubai International Financial Centre (DIFC), Dubai, United Arab Emirates. The principal activities of the company is providing consulting and financial related services to the companies of Sinopec Group (its related services). " and "The key business of Sinopec ME is to provide loans to Sinopec’s subsidiaries which have projects in MENA to earn interest income. The interest income earned from inter-group lending is the main revenue stream for the company. "', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3215, 'GPR3', 'esg_navigiator', '01');
