INSERT INTO mstr.advisor_memo_report VALUES (NULL, 24576, 1582, '1599218', '2024-05-15 14:47:07', 'Masarin, Lisa', 'Tarakji, Ranim', 'Analytical aspects - these emissions are not applicable for the LE because as per Sustainability report (page 26) "Hyundai Rotem has calculated carbon emissions for its domestic production plants, which include the Changwon plant, Dangjin plant, and Uiwang R&D center." Hence the international business is not accounted for.In the CDP Report (C7.2 and C7.5), you will find the emissions for each region, including Egypt. Please use those.', NULL, NULL, NULL, '1900-01-01 00:00:00', '1900-01-01 00:00:00', '1900-01-01 00:00:00', '2025-05-25 00:00:00', 3505, 'CTP3', 'esg_navigiator', '01');
