-- ============================================================
-- Advisor Memo Report - Create table + insert all records
-- Schema: mstr
-- ============================================================

DROP TABLE IF EXISTS mstr.advisor_memo_report CASCADE;

CREATE TABLE mstr.advisor_memo_report (
    memo_reply_id                               INTEGER,
    case_id                                     INTEGER,
    memo_id                                     INTEGER,
    memo_created_by                             VARCHAR(50),
    memo_created_date                           TIMESTAMP,
    checker                                     VARCHAR(100),
    maker                                       VARCHAR(100),
    memo_feedback                               TEXT,
    memo_reply                                  TEXT,
    memo_reply_created_by                       VARCHAR(50),
    memo_reply_created_date                     TIMESTAMP,
    date_of_submission_to_rm                    TIMESTAMP,
    date_of_submission_to_climate_risk_advisor  TIMESTAMP,
    date_of_rejection_by_climate_risk_advisor   TIMESTAMP,
    ods                                         TIMESTAMP,
    question_id                                 INTEGER,
    section_code                                VARCHAR(20),
    source_system_name                          VARCHAR(50),
    version                                     VARCHAR(10)
);

-- ============================================================
-- INSERT all records
-- ============================================================


-- ============================================================
-- Indexes
-- ============================================================
CREATE INDEX idx_memo_case_id ON mstr.advisor_memo_report (case_id);
CREATE INDEX idx_memo_section_code ON mstr.advisor_memo_report (section_code);
CREATE INDEX idx_memo_checker ON mstr.advisor_memo_report (checker);
CREATE INDEX idx_memo_maker ON mstr.advisor_memo_report (maker);
CREATE INDEX idx_memo_created_date ON mstr.advisor_memo_report (memo_created_date);
